-- Poems batch 64
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f50e1641-b908-4a6c-9138-f9b80c3ac52b','富春二首（之二）','吳融','唐','唐诗','tang','','[]','兩岸山花中有溪，山花紅白偏高低。',87,'全唐诗/poet.tang.54000.json','["兩岸山花中有溪，山花紅白偏高低。", "靈源忽若乘槎到，仙洞還同採藥迷。", "二月辛夷猶未落，五更鴉舅最先啼。", "茶煙漁火遙看處，一片人家在水西。", "（見《唐音戊籤》八十一〖《統籤》卷七三四〗）。"]'),
('9856c758-9bae-4731-801a-eed15e3b16c8','自遣','吳融','唐','唐诗','tang','','[]','幾年曾見舊江村，樹有交柯犢有孫。',67,'全唐诗/poet.tang.54000.json','["幾年曾見舊江村，樹有交柯犢有孫。", "深感下峰顏色好，晚雲纔散又當門。", "（見《竹莊詩話》卷十五引郭思《瑤谿集》、《能改齋漫錄》卷八錄後二句）。"]'),
('f17c930d-3517-4db9-8d7d-63e5b3c15c32','杏花','吳融','唐','唐诗','tang','','[]','春意竟相妬，杏花應最嬌。',53,'全唐诗/poet.tang.54000.json','["春意竟相妬，杏花應最嬌。", "紅輕欲愁殺，粉薄似啼消。", "願作年華夢，翩翩遶此條。", "（《全芳備祖前集》卷十《杏花》）。"]'),
('027308ea-aea0-447c-b1e5-30d971472026','悼孟昭圖（題擬）','狄常侍','唐','唐诗','tang','','[]','一何罪死一何名，獨向湘江弔屈平。',203,'全唐诗/poet.tang.54000.json','["一何罪死一何名，獨向湘江弔屈平。", "從此蜀川春夜月，杜鵑啼作兩般聲。", "（周校本《詩話總龜》卷四五引盧瓌《抒情》）（按：盧瓌《抒情》云：「僖宗幸蜀，拾遺孟昭門上疏切直，蹈于非罪。", "時狄常侍歸蜀，以詩悼之曰〖詩略〗。", "」《全唐詩》卷六○○據《南部新書》卷己、《唐詩紀事》卷六八等書所引，收歸裴澈名下。", "《抒情詩》成書較早，詩句差異較大，故兩存之。", "狄常侍，疑即狄歸昌。", "昭門，顯爲昭圖之誤。", "《全唐詩》作「孟昌圖」，亦未諦。", "）。"]'),
('a0431e34-d65c-4f04-a194-0b8e6d3b2ccb','雪','唐彥謙','唐','唐诗','tang','','[]','客來迷舊徑，虎過識新蹤。',44,'全唐诗/poet.tang.54000.json','["客來迷舊徑，虎過識新蹤。", "浦近渾無鶴，林疏只有松。", "（《分門纂類唐宋時賢千家詩選》卷十三）。"]'),
('6a890f87-2368-4923-bac2-c4198966f516','贈齊己（題擬）','鄭谷','唐','唐诗','tang','','[]','敲門誰訪□，□客即□師。',134,'全唐诗/poet.tang.54000.json','["敲門誰訪□，□客即□師。", "應是逢新雪，高吟得好詩。", "格清無俗字，思苦有蒼髭。", "諷味但忘倦，拋琴復捨碁。", "（見《四部叢刊》本《白蓮集》卷首孫光憲《白蓮集序》引。", "此首承趙昌平同志錄志。", "）（〖1〗《白蓮集序》：「鄭谷郎中與師□□□□□□〖下引詩，略〗其爲詩家流之之稱許也如此。", "」）。"]'),
('5c0dcdc8-16d9-4aa3-a6a6-333961fa42b1','荷花（題擬）','鄭谷','唐','唐诗','tang','','[]','佛愛我亦愛，清香蝶不偷。',39,'全唐诗/poet.tang.54000.json','["佛愛我亦愛，清香蝶不偷。", "一般奇特處，不上婦人頭。", "（見《全芳備祖前集》卷十一）。"]'),
('30e60921-41c7-4802-8230-cc189e216ead','筆峰','鄭谷','唐','唐诗','tang','','[]','似筆挺然秀，山川亦好文。',71,'全唐诗/poet.tang.54000.json','["似筆挺然秀，山川亦好文。", "宕渠花裏發，秦壠竹間分。", "石臼生春水，香龕積暮雲。", "道經難久住，日後憶離羣。", "（見民國十七年刊曾瀛藻纂《大竹縣志》卷十四）。"]'),
('c33608b7-3ca2-4093-8a72-bd51c3f5a4ab','春日即事','鄭谷','唐','唐诗','tang','','[]','典衣估酒得，伴客看閒花。',35,'全唐诗/poet.tang.54000.json','["典衣估酒得，伴客看閒花。", "（見《吟窗雜錄》卷十四正字王玄《詩中旨格》）。"]'),
('22d84dca-e3b3-4cb9-b53e-8f5e9eda551f','秋扇','鄭谷','唐','唐诗','tang','','[]','汗流浹背曾施力，氣爽中宵便負心。',21,'全唐诗/poet.tang.54000.json','["汗流浹背曾施力，氣爽中宵便負心。", "（同前）。"]'),
('62152f05-6664-4b67-8868-6e5bcaf6504f','贈王貞白','鄭谷','唐','唐诗','tang','','[]','殿前新進士，闕下校書郎。',32,'全唐诗/poet.tang.54000.json','["殿前新進士，闕下校書郎。", "（《唐才子傳》卷九。", "此則承陶先生見告）。"]'),
('b67b49e4-f27d-4a20-8f51-d814424eaa2d','秋夜雨中','崔致遠','唐','唐诗','tang','','[]','秋風唯苦吟，舉世少知音。',40,'全唐诗/poet.tang.54000.json','["秋風唯苦吟，舉世少知音。", "窗前三更雨，燈前萬里心。", "（金東勳云見《東文選》卷十九）。"]'),
('54d15c52-03c6-4fd6-9d9e-92a818944286','登潤州慈和寺上房','崔致遠','唐','唐诗','tang','','[]','登臨蹔隔路歧塵，吟想興亡恨益新。',64,'全唐诗/poet.tang.54000.json','["登臨蹔隔路歧塵，吟想興亡恨益新。", "畫角聲中朝暮浪，青山影裏古今人。", "霜摧玉樹花無主，風暖金陵草自春。", "賴有謝家餘景在，常叫詞客爽精神。"]'),
('ad35ed7f-050f-462a-8f44-e885604c21da','送吳進士巒歸江南','崔致遠','唐','唐诗','tang','','[]','自識君來幾度別，此回相別恨重重。',64,'全唐诗/poet.tang.54000.json','["自識君來幾度別，此回相別恨重重。", "干戈到處方多事，詩酒何時得再逢。", "遠樹參差江畔路，寒雲零落馬前峰。", "行行遇景傳新作，莫學嵇康盡放慵。"]'),
('9735c8df-8694-420a-aaa8-15aa383799cd','秋日再經盱眙縣寄李長官','崔致遠','唐','唐诗','tang','','[]','孤蓬再此接恩輝，吟對秋風悵有違。',64,'全唐诗/poet.tang.54000.json','["孤蓬再此接恩輝，吟對秋風悵有違。", "門柳己凋新歲葉，旅人猶着去年衣。", "路迷霄漢愁中老，家隔煙波夢裏歸。", "自歎身如春社燕，畫樑高處又來飛。"]'),
('ae7610dd-8d76-465a-8910-8829541ed760','暮春即事和顧雲友使','崔致遠','唐','唐诗','tang','','[]','東風遍閱百般香，意緒偏饒柳帶長。',104,'全唐诗/poet.tang.54000.json','["東風遍閱百般香，意緒偏饒柳帶長。", "蘇武書回深塞盡，莊周夢逐落花忙。", "好憑殘景朝朝醉，難把離心寸寸量。", "正是浴沂時節日，舊遊魂斷白雲鄉。", "（以上五首錄自《社會科學戰線》一九八四年第四期刊何鳴雁《新羅詩人崔致遠》一文）。"]'),
('5962b101-ae0e-4d47-aab2-a39c6403c264','山陽與鄉友話別','崔致遠','唐','唐诗','tang','','[]','相逢暫樂楚山春，又欲分離淚滿巾。',43,'全唐诗/poet.tang.54000.json','["相逢暫樂楚山春，又欲分離淚滿巾。", "莫怪臨風偏悵望，異鄉難遇故鄉人。", "（《東文選》卷十九）。"]'),
('42429ee9-5f37-4f34-a673-982678dfcad7','古意','崔致遠','唐','唐诗','tang','','[]','狐能化美女，狸亦作書生。',55,'全唐诗/poet.tang.54000.json','["狐能化美女，狸亦作書生。", "誰知異物類，幻惑同人形。", "變化尚非艱，操心良獨難。", "欲辨真與僞，願磨心鏡看。", "（同前卷四）。"]'),
('38155bc4-868f-44ff-b9f0-ab116d861f14','江南女','崔致遠','唐','唐诗','tang','','[]','江南蕩風俗，養女嬌且憐。',77,'全唐诗/poet.tang.54000.json','["江南蕩風俗，養女嬌且憐。", "性冶耻針線，妝成調管弦。", "所學非雅音，多被春心牽。", "自謂芳華色，長占艷陽年。", "却笑鄰家女，終朝弄機杼。", "機杼縱勞身，羅衣不到汝。", "（同前）。"]'),
('e02fe492-cef9-43ff-a99e-36edbe385843','寓興','崔致遠','唐','唐诗','tang','','[]','願言扃利門，不使損遺體。',53,'全唐诗/poet.tang.54000.json','["願言扃利門，不使損遺體。", "爭奈探珠者，輕生入海底。", "心榮塵易染，心垢正難洗。", "澹泊與誰論，世路嗜甘醴。", "（同前）。"]'),
('17a338d9-290d-4161-9eb2-2be1af506c03','蜀葵花','崔致遠','唐','唐诗','tang','','[]','寂寞荒田側，繁花壓柔枝。',96,'全唐诗/poet.tang.54000.json','["寂寞荒田側，繁花壓柔枝。", "香輕梅雨歇，影帶麥風欹。", "車馬誰見賞，蜂蝶徒相窺。", "自慚生地賤，堪恨人棄遺。", "（同前。", "以上五首皆錄自《中央民族學院學報》一九八五年第一期刊金東勳《晚唐著名詩人崔致遠》一文）。"]'),
('66902634-b5dc-4888-a4d0-019d93afd78f','夢中作','崔致遠','唐','唐诗','tang','','[]','糞墻師有誡，經笥我無慙。',123,'全唐诗/poet.tang.54000.json','["糞墻師有誡，經笥我無慙。", "亂世成何事，唯添七不堪。", "（《大正藏》本《唐大薦福寺故寺主翻經大德法藏和尚傳》）（按：此詩爲崔致遠天復四年春夢中遇宰予、邊孝先二賢，前二句爲二賢句，後二句爲崔續成之。", "按：崔致遠歸國後詩，今獲見十一首，附錄於次，以便參考。", "）。"]'),
('04406278-b18b-4a06-835c-42fa5fecbcd1','題伽倻山讀書堂瀑布','崔致遠','唐','唐诗','tang','','[]','狂噴壘石吼重巒，人語難分咫尺間。',56,'全唐诗/poet.tang.54000.json','["狂噴壘石吼重巒，人語難分咫尺間。", "常恐是非聲到耳，故教流水盡籠山。", "（何鳴雁文引。", "又見《新增東國輿地勝覽》卷三十）。"]'),
('3c080567-c543-4f0f-a1b1-c783a397d881','鄉樂雜詠五首 金丸','崔致遠','唐','唐诗','tang','','[]','迴身掉臂弄金丸，月轉星浮滿眼看。',32,'全唐诗/poet.tang.54000.json','["迴身掉臂弄金丸，月轉星浮滿眼看。", "縱有宜僚那勝此，定知鯨海息波瀾。"]'),
('2e44cb95-1cf7-4687-bcab-705f24a2b2ed','鄉樂雜詠五首 月顛','崔致遠','唐','唐诗','tang','','[]','肩高項縮髮崔嵬，攘臂羣儒鬬酒盃。',32,'全唐诗/poet.tang.54000.json','["肩高項縮髮崔嵬，攘臂羣儒鬬酒盃。", "聽得歌聲人盡笑，夜頭旗幟曉頭催。"]'),
('533487dd-4d88-4d15-899b-32f5bcd8cfb7','鄉樂雜詠五首 大面','崔致遠','唐','唐诗','tang','','[]','黃金面色是其人，手抱珠鞭役鬼神。',32,'全唐诗/poet.tang.54000.json','["黃金面色是其人，手抱珠鞭役鬼神。", "疾步徐趍呈雅舞，宛如丹鳳舞堯春。"]'),
('804becb2-16d1-431c-b205-7980c2445c94','鄉樂雜詠五首 束毒','崔致遠','唐','唐诗','tang','','[]','蓬頭藍面異人間，押隊來庭學舞鸞。',32,'全唐诗/poet.tang.54000.json','["蓬頭藍面異人間，押隊來庭學舞鸞。", "打鼓冬冬風瑟瑟，南奔北躍也無端。"]'),
('810d0298-1abf-42e2-85e0-801dfe762534','鄉樂雜詠五首 狻猊','崔致遠','唐','唐诗','tang','','[]','遠涉流沙萬里來，毛衣破盡着塵埃。',44,'全唐诗/poet.tang.54000.json','["遠涉流沙萬里來，毛衣破盡着塵埃。", "搖頭擺尾馴仁德，雄氣寧同百獸才。", "（《三國史記》卷三二）。"]'),
('78e13878-40f4-4110-8589-1000402027fc','寄顥源上人','崔致遠','唐','唐诗','tang','','[]','終日低頭弄筆端，從人杜口話心難。',80,'全唐诗/poet.tang.54000.json','["終日低頭弄筆端，從人杜口話心難。", "遠離塵世雖堪喜，爭奈風情未肯闌。", "影鬬晴霞紅葉徑，聲連夜雨白雲湍。", "吟魂對景無羇絆，四海深機憶道安。", "（《新增東國輿地勝覽》卷三十）。"]'),
('931fced3-e35c-4b6a-ae80-f9cea62f01f1','贈金川寺主','崔致遠','唐','唐诗','tang','','[]','白雲溪畔創仁寺，三十年來此住持。',43,'全唐诗/poet.tang.54000.json','["白雲溪畔創仁寺，三十年來此住持。", "笑指門前一條路，纔離山下有千歧。", "（《東文選》卷十九）。"]'),
('0cd33da5-b179-4f6a-9e89-d7134989f533','入山詩','崔致遠','唐','唐诗','tang','','[]','僧乎莫道青山好，山好何事更出山。',54,'全唐诗/poet.tang.54000.json','["僧乎莫道青山好，山好何事更出山。", "試看他日吾蹤跡，一入青山更不還。", "（見《漢詩選集》。", "以上二首錄自金東勳文。", "）。"]'),
('97b03652-9ffb-4173-b629-cc994c9558e1','智異山花開洞','崔致遠','唐','唐诗','tang','','[]','東國花開洞，壺中別有天。',66,'全唐诗/poet.tang.54000.json','["東國花開洞，壺中別有天。", "仙人推玉枕，身世倏千年。", "（見趙書印編《韓國文苑》卷七，注出《擇里志》題注云：「宣廟時有僧得之巖石間云。", "」）。"]'),
('9c666833-fbc0-4cec-95f2-5663400c5d86','臨鏡臺','崔致遠','唐','唐诗','tang','','[]','烟巒簇簇水溶溶，鏡裏人家對碧峰。',382,'全唐诗/poet.tang.54000.json','["烟巒簇簇水溶溶，鏡裏人家對碧峰。", "何處孤帆飽風去，瞥然飛鳥杳無踪。", "（錄自韋旭升《朝鮮文學史》）（按：據金東勳說，崔詩除《全唐詩逸》及《桂苑筆耕集》〖已收《全唐詩補逸》〗所收外，《三國史記》存五首，《東文選》收三十首，另見於石刻、方志者尚有十餘首，共存百首左右。", "今所得僅二十餘首，尚缺二十首左右。", "據前引各文所述，未見者有《饒州鄱陽亭》、《夜贈樂官》、《芋江驛灣》、《贈智光上人》等。", "又按：《朝鮮文學史》錄崔匡裕《長安春日有感》云：「麻衣難拂路歧塵，鬢改顏衰曉鏡新。", "上國好花愁裏艷，故園芳樹夢中春。", "扁舟煙月思浮海，羸馬關河倦問津。", "只爲未酬螢雪志，綠楊鶯語太傷神。", "」又謂其另有《郊居呈知己》、《憶南李處士》等詩，崔承祐有《送曹松入羅浮》、朴仁範有《九成宮懷古》、《涇州龍朔寺》、《江行呈張秀才》詩。", "諸詩皆新羅人在唐時所作，因未注出處，世次不明，又僅錄一首，姑附識於此。", "）。"]'),
('214c74a9-c04a-4830-b7a3-6eb38f9c3437','下第商山對緋桃','陳光','唐','唐诗','tang','','[]','半夜東風力，霞光一片新。',67,'全唐诗/poet.tang.54000.json','["半夜東風力，霞光一片新。", "細看初着雨，繁豔欲燒人。", "得意開當日，無言空過春。", "東堂失意客，歸去倍傷神。", "（影印本《詩淵》第四冊第二五二一頁）。"]'),
('4d69090f-0fc9-4714-9a71-522b9e64e199','旅館','陳光','唐','唐诗','tang','','[]','對坐庭梧下，風凉月色新。',62,'全唐诗/poet.tang.54000.json','["對坐庭梧下，風凉月色新。", "遠砧來迥夜，孤館未眠人。", "何計成他事，唯憂老此身。", "不知霄漢路，誰與脫凡鱗？", "（同前第五冊第三三六八頁）。"]'),
('0bd84015-0bf8-442a-9d48-cdf32de1e6e9','送人歸新羅','陳光','唐','唐诗','tang','','[]','巨浸隔鄉關，離城日已殘。',62,'全唐诗/poet.tang.54000.json','["巨浸隔鄉關，離城日已殘。", "日將程共遠，風與浪爭難。", "岸盡霞光落，天光海色寒。", "扶桑歸到後，萬里夢長安。", "（同前第六冊第四三八二頁）。"]'),
('f2dd59a7-443e-4db0-8c6f-9a732e904495','送人游交趾','陳光','唐','唐诗','tang','','[]','掛席天涯去，想君萬里心。',59,'全唐诗/poet.tang.54000.json','["掛席天涯去，想君萬里心。", "人間無別業，海外訪知音。", "浪歇龍涎聚，沙虛象跡深。", "往來應隔闊，須自惜光陰。", "（同前第四四四九頁）。"]'),
('0b8517b9-f00c-4092-ba4b-c665ffd63395','句','王輿','唐','唐诗','tang','','[]','天漢尚不正，河源爭得清。',109,'全唐诗/poet.tang.54000.json','["天漢尚不正，河源爭得清。", "（見曾慥《類說》卷十二《紀異記》引）（〖1〗《紀異記》：「王輿有詩名，嘗有一聯云：『天漢尚不正，河源爭得清。", "』崔胤相國聞之，大不悅。", "竟流落而死。", "」按：南唐時有王輿，事烈祖，似與此詩作者無涉。", "）。"]'),
('1af97d4a-b03d-470d-8a94-f0544ac5e5a2','蟋蟀詩','尚顏','唐','唐诗','tang','','[]','無風來竹院，有月在沙（《詩學指南》本作「莎」）亭。',44,'全唐诗/poet.tang.54000.json','["無風來竹院，有月在沙（《詩學指南》本作「莎」）亭。", "（見《吟窗雜錄》卷十四《詩中旨格》）。"]'),
('c5161dbd-3852-4db6-b11a-dccd7f7627d9','句','歸仁','唐','唐诗','tang','','[]','舟歸范蠡五湖上，國破西施一笑中。',40,'全唐诗/poet.tang.54000.json','["舟歸范蠡五湖上，國破西施一笑中。", "（見《吟窗雜錄》卷十三《進士王氏詩要格律》。", "）。"]'),
('094c8577-b51e-4ed6-a9fd-14bbeb6b2492','五言長句','林仙人','唐','唐诗','tang','','["\u9ec4\u6cb3"]','此境極岧嶤，登臨近斗杓。',288,'全唐诗/poet.tang.54000.json','["此境極岧嶤，登臨近斗杓。", "天元諸聖會，地勢萬峰朝。", "西揖崑丘峻，東連蓬海遙。", "泉甘生玉頂，壇穩壓金腰。", "泰華三峰立，黃河一帶漂。", "五更觀海日，半夜聽簫韶。", "落月低龍嶺，寒煙鎖虹橋。", "雪鷄聲喔喔，風竹韻蕭蕭。", "雲屋香煙起，芝燈瑞彩銷。", "麻籠騰秀氣，藥櫃顯靈苗。", "丹井猶清淺，神鐘又寂寥。", "八岡齊岌岌，雙鶴對飄飄。", "瀑水銀垂線，霞城綺建標。", "池清深見底，柏聳翠凌霄。", "道館新居壯，真公舊事遼。", "幾瞻青嶂上，時有白雲飄。", "石室虛難問，臺松老不凋。", "巖花鋪錦繡，溪溜漱瓊瑤。", "洞壑非塵趣，林巒隔世囂。", "軒皇開綵仗，王母閴鸞軺。", "旦暮陰陽變，炎涼節候調。", "暝猿啼復歇，晴靄合還消。", "歌詠聊能紀，工夫豈易描？", "妙齡希郄桂，晚歲樂顏瓢。"]'),
('e6f0e9ad-4ad7-4376-9d4c-5fa0e0b0865c','七言三首 一','林仙人','唐','唐诗','tang','','[]','萬壑松蘿拂紫煙，丹臺秘邃集神仙。',64,'全唐诗/poet.tang.54000.json','["萬壑松蘿拂紫煙，丹臺秘邃集神仙。", "乾坤結秀真靈嶽，日月飛根照洞天。", "塵世暗移知幾代，蟠桃初熟未經年。", "時人莫測幽微事，五色雲封種王田。"]'),
('df438850-e841-42e6-be92-da7c1ada4bb9','七言三首 二','林仙人','唐','唐诗','tang','','[]','清虛小有洞中天，銀座金腰玉頂堅。',64,'全唐诗/poet.tang.54000.json','["清虛小有洞中天，銀座金腰玉頂堅。", "芝草秀從龍漢劫，丹砂結自赤明年。", "洗參井紀燕蘿子，聚虎平川白水仙。", "寄語避秦溝裏客，茅齋先蓋兩三椽。"]'),
('f2c46e5c-7020-444a-b9a5-cd5e9390ec57','七言三首 三','林仙人','唐','唐诗','tang','','[]','白石磷磷上接天，青松鬱鬱下臨川。',93,'全唐诗/poet.tang.54000.json','["白石磷磷上接天，青松鬱鬱下臨川。", "草生福地皆爲藥，人在名山總是仙。", "待客遠尋巖下蕨，烹茶滿酌洞中泉。", "前生恐是白雲子，今世還來臥翠顛。", "（以上四首皆見《正統道藏》本杜光庭《天壇王屋山聖迹記》）。"]'),
('8f9a4168-0a03-4115-9241-3064c61b2ddb','七言三十韻','通真道人','唐','唐诗','tang','','[]','擺脫塵纓淡無欲，閑閱圖經尋嶽瀆。',386,'全唐诗/poet.tang.54000.json','["擺脫塵纓淡無欲，閑閱圖經尋嶽瀆。", "林泉何處愜予心，收拾琴書將卜築。", "崎嶇不敢千里辭，東自太行入王屋。", "先探藏花塢裏春，蟠桃畢竟何時熟？", "燕羅故宅陽臺宮，九龍戲珠畫幈簇。", "丹井沉沉浸月明，丫髻仙童抱參斸。", "昂頭貪看華蓋峰，驀然悮入紫微谷。", "上方樓閣與雲閑，金碧交光射林麓。", "避秦溝有避秦人，夜半聞歌《採芝曲》。", "策杖窮躋瘦龍嶺，嶮似劍關西向蜀。", "捫參歷井上沖真，千仞斷崖橫獨木。", "自辰及酉脚力窮，恰到紫金堂下宿。", "再拜新嘗太一泉，頓覺洒然消病骨。", "恍兮惚兮九霄間，萬頃嵐光醒醉目。", "恭叩仙壇禱真境，壇與天通隔塵俗。", "銀座金腰玉頂寒，帝遣仙官分部屬。", "小有中藏萬里地，都壓洞天三十六。", "日精月華左右奇，黛色倚空如削玉。", "東觀大海日輪紅，西望窮邊壇影綠。", "煉丹爐下土猶香，抱出神丹知幾斛。", "處山使者持太阿，保護聖軀誰敢黷？", "王母洞深非可測，雷霆屢震蛟龍窟。", "遙指三官校勘臺，樵人幾度聞絲竹。", "抱朴巖前採藥童，手撚金芝身薜服。"]'),
('5c64c56a-3682-4088-9254-e213f22ea8f0','白雀歌（幷進表）','張永進','唐','唐诗','tang','','[]','白雀飛來過白亭，鼓翅翻身入帝城。',424,'全唐诗/poet.tang.54000.json','["白雀飛來過白亭，鼓翅翻身入帝城。", "深向後宮呈寶瑞，玉樓高處送嘉聲。", "白衣白鞟白紗巾，白馬銀鞍珮白纓。", "自古不聞書不戰，一劍能却百萬兵。", "王母本住在崑崙，爲貢白環來入秦。", "漢武遙指東方朔，朕感白霞天上人。", "紫亭南嶺白狼遊，爲效禎祥屬此州，昔日周王呈九尾，爭似如今耀斗牛。", "白旗白紱白旄頭，白玉雕鞍白瑞鳩，築壇待拜天郊後，自有金星助冕旒。", "白巖聖迹俯王都，玉女乘虛定五湖。", "白廣山巔雲繚繞，人歌聖德滿長衢。", "金鞍山上白犛牛，擺撼霜毛始舉頭。", "遶泉百匝騰空去，保王社稷定徽猷。", "白山隄下白澄津，一道長河夾岸春。", "白雪梨花連萬朶，王向東樓擁白雲。", "東苑西園池白蘋（王校作「蓰」），白渠流水好陽春。", "六宮盡是名家子，白羅綽約玉顏新。", "平河北澤白龍宮，賀拔爲王此處逢。", "昨來再起興雲雨，爲贊君王瑞一同。", "嵯峨萬丈聳金山，白雲凝霜古聖壇。", "金鞍長掛湫南樹，神通日夜助王歡。", "山出西南獨秀高，白霞爲蓋繞周遭。", "山腹有泉深萬丈，白龍時復震波濤。", "白樓素屏白銀鈎，砌玉龍墀對五侯。", "雉尾扇移香案出，似月如霜複殿幽。"]'),
('00f9447c-48bf-4e40-a0b8-5a01968c9688','頌曰','張永進','唐','唐诗','tang','','[]','白銀槍懸太白旗，白虎三旌三戟枝。',148,'全唐诗/poet.tang.54000.json','["白銀槍懸太白旗，白虎三旌三戟枝。", "五方色中白爲上，不是我王爭得知。", "樓成白璧聳儀形，蜀地求才讚聖明。", "自從湯帝昇遐後，白雀無因宿帝廷。", "今來降瑞報成康，果見河西再冊[王]（玉）。", "韓白滿朝謀似雨，國門長鎮成燉煌。", "（以上二首均見伯二五九四、伯二八六四卷，參王重民《金山國墜簡零拾》，收入《敦煌遺書論文集》）。"]'),
('024c8fe2-6196-4be7-8de3-ced338a34b6e','龍泉神劍歌','張文徹','唐','唐诗','tang','','["\u9ec4\u6cb3"]','龍泉寶劍出豐城，彩氣衝天上接辰。',440,'全唐诗/poet.tang.54000.json','["龍泉寶劍出豐城，彩氣衝天上接辰。", "不獨漢朝今亦有，金鞍山下是長津。", "天符下降到龍沙，便有明君膺紫霞，天子猶來是天補，橫截河西是一家。", "堂堂美貌實天顏，□德昂藏鎮玉關。", "國號金山白衣帝，應須早築拜天壇。", "日月雙旌耀虎旗，御樓寶砌建丹墀。", "出警從茲排法駕，每行青道要先和。", "我帝金懷海量□（疑爲「寬」字），目似流星鼻筆端。", "相好與堯同一體，應知天分數千般。", "一從登極未逾年，德比陶唐初受禪。", "百靈効祉賀鴻壽，足踏坤維手握乾。", "明明聖日出當時，上膺星辰下有期。", "神劍新磨須使用，定疆廣宇未爲遲。", "東取河蘭廣武城，西取天山澣海軍。", "北掃燕然□嶺鎮，南盡戎羗邏莎平。", "三軍壯，甲馬興，萬里橫行河湟清。", "結親只爲圖長國，永霸龍沙截海鯨。", "我帝威雄人未知，叱吒風雲自有時。", "祁連山下留名迹，破却甘州必□遲。", "金風初動虜兵來，點齪干戈會將臺。", "戰馬鐵衣舖雁翅，金河東岸陣雲開。", "慕良將，揀人材，出天入地選良枚（王錄作「牧」，近是，惟不協韻）。", "先鋒委付渾鷂子，須向將軍劍下摧。", "左右衝□搏虜塵，疋馬單槍陰舍人，前衝虜連渾穿透，一段英雄遠近聞。"]'),
('5fa2c91b-8b9b-4e8e-8d46-bb2b017c5426','兵要望江南 委任第一（京本作「占委任第一」二十六首） 一','易靜','唐','唐诗','tang','','[]','兵之道，切忌起無名。',57,'全唐诗/poet.tang.54000.json','["兵之道，切忌起無名。", "不止（京本作「正」）少功虛效力，逡巡反（川本作「及」）禍復（京本作「復禍」）危傾。", "容易勿言兵。"]'),
('8ad0248d-c5f9-44aa-8922-0ecb3d500f06','兵要望江南 委任第一（京本作「占委任第一」二十六首） 二','易靜','唐','唐诗','tang','','[]','統軍（京本作「兵」）帥，不可比[鹽]（醎）（據川本、辛本、京本改）梅。',57,'全唐诗/poet.tang.54000.json','["統軍（京本作「兵」）帥，不可比[鹽]（醎）（據川本、辛本、京本改）梅。", "相政乖虧猶可救，朝綱雖失亦能回，兵敗國傾危。"]'),
('947bf0cc-02d1-46cf-a615-255323753607','兵要望江南 委任第一（京本作「占委任第一」二十六首） 三','易靜','唐','唐诗','tang','','[]','當權將，其責重如山。',47,'全唐诗/poet.tang.54000.json','["當權將，其責重如山。", "社稷存亡全在爾，安危君父一時間。", "須要立功還（川本、辛本作「爵祿帝王頒」）。"]'),
('6fc0c903-dd96-49ef-8d16-a83b32e82d21','兵要望江南 委任第一（京本作「占委任第一」二十六首） 四','易靜','唐','唐诗','tang','','[]','銓大將（京本作「帥」），須要素知（京本作「司」）[兵]（名）（據辛本、川本、京本改。',92,'全唐诗/poet.tang.54000.json','["銓大將（京本作「帥」），須要素知（京本作「司」）[兵]（名）（據辛本、川本、京本改。", "）非是等閒虛譽職，莫將軍印（京本作「兵柄」）任（辛本、川本作「委」、京本作「付」）狂生，輕擁甲兵行。"]'),
('44c83909-db58-4074-b233-8a105495a181','兵要望江南 委任第一（京本作「占委任第一」二十六首） 五','易靜','唐','唐诗','tang','','[]','諸屬幕，必（京本作「須」）是選賢（辛本、川本作「堪」、京本作「沉」）良。',92,'全唐诗/poet.tang.54000.json','["諸屬幕，必（京本作「須」）是選賢（辛本、川本作「堪」、京本作「沉」）良。", "勿取（京本作「使」）門高（京本作「風」）當勢位，無私親舊與鄉邦（京本作「同鄉」）。", "曲順（京本作「邪曲」）定爲殃。"]'),
('e16f367c-c970-40d0-900c-fd7c2df2c47c','兵要望江南 委任第一（京本作「占委任第一」二十六首） 六','易靜','唐','唐诗','tang','','[]','攻敵策，謀乃勝之原（京本作「源」）。',103,'全唐诗/poet.tang.54000.json','["攻敵策，謀乃勝之原（京本作「源」）。", "勿使（辛本、川本、京本作「祗」）迎兵（京本作「軍」）交血刃，休憑角（京本作「勇」）力靠兵官，勇是禍之端。", "（經曰：善戰者不怒，善勝者不爭。", "非智者不能行，非賢者不能用也。", "）。"]'),
('a84f4f74-669f-47cf-9362-9136d5fde4d6','兵要望江南 委任第一（京本作「占委任第一」二十六首） 七','易靜','唐','唐诗','tang','','[]','統軍帥，智慮有明謀。',32,'全唐诗/poet.tang.54000.json','["統軍帥，智慮有明謀。", "善識天文能勇敢，更兼威德賞勤勞。", "士卒自英豪。"]'),
('4a61cd72-2a1e-4b09-a515-4ef3b5188056','兵要望江南 委任第一（京本作「占委任第一」二十六首） 八','易靜','唐','唐诗','tang','','[]','爲將帥，筮卜識機緣。',32,'全唐诗/poet.tang.54000.json','["爲將帥，筮卜識機緣。", "更用一人高術士，精通占候要知言，凶吉預聞先。"]'),
('0b8aa14f-b88f-4ec4-9205-35b93370b061','兵要望江南 委任第一（京本作「占委任第一」二十六首） 九','易靜','唐','唐诗','tang','','[]','覘彼勢，虛實要先評。',58,'全唐诗/poet.tang.54000.json','["覘彼勢，虛實要先評。", "兵有正奇將勝敗（京本作「關將敏」），有（京本作「勢」）無強弱在軍精（辛本作「情」），料敵不須驚。"]'),
('252d50a5-51e5-4da6-b19d-356760fc3de0','兵要望江南 委任第一（京本作「占委任第一」二十六首） 十','易靜','唐','唐诗','tang','','[]','量彼敵，將勇戒驕盈。',51,'全唐诗/poet.tang.54000.json','["量彼敵，將勇戒驕盈。", "整暇正須期死戰，凱旋猶懼有驕（辛本、京本作「生」）兵，養氣勿輕迎（辛本作「臨」）。"]'),
('d16bbfb2-23cd-4e1a-964e-de5afaa954aa','兵要望江南 委任第一（京本作「占委任第一」二十六首） 十一','易靜','唐','唐诗','tang','','[]','戰危事，上將戒貪行（辛本作「兵」）。',71,'全唐诗/poet.tang.54000.json','["戰危事，上將戒貪行（辛本作「兵」）。", "閫（京本作「國」）計豈應（辛本作「能」，京本作「令」）求（京本作「圖」）小利，師行自古有常經，紀律要精明。"]'),
('fe14394a-5b8a-4d30-bf04-0931b33a7d92','兵要望江南 委任第一（京本作「占委任第一」二十六首） 十二','易靜','唐','唐诗','tang','','[]','參彼將，德（京本作「得」）性好攻心。',82,'全唐诗/poet.tang.54000.json','["參彼將，德（京本作「得」）性好攻心。", "仔細究情（辛本作「精」）隨彼好，中行離[反]（問）（據辛本、京本改）詭相親，設利誘前擒。", "（覆兵敗將，攻其便，究其情，伐其機。", "）。"]'),
('175bb395-30f2-427c-ad23-f97a0b11d38e','兵要望江南 委任第一（京本作「占委任第一」二十六首） 十三','易靜','唐','唐诗','tang','','[]','統軍將（辛本、川本作「兵帥」），剛暴自殘兵。',44,'全唐诗/poet.tang.54000.json','["統軍將（辛本、川本作「兵帥」），剛暴自殘兵。", "有勇有勞無賞罰，却將傲慢事行刑，彼將定欺淩。"]'),
('8f1a577b-0774-4725-a95e-57bfefc6b02b','兵要望江南 委任第一（京本作「占委任第一」二十六首） 十四','易靜','唐','唐诗','tang','','[]','審向道（京本作「彼將」），測（京本作「斥」，辛本作「情」）候要分明。',86,'全唐诗/poet.tang.54000.json','["審向道（京本作「彼將」），測（京本作「斥」，辛本作「情」）候要分明。", "莫爲時多蒙（辛本作「朦」）躁進（京本作「莫與兵徒萌躁進」），勿從剛暴速兼程，慮（京本作「虞」）彼伏潛兵。"]'),
('1be2326d-924d-456f-bde8-22140b6443f3','兵要望江南 委任第一（京本作「占委任第一」二十六首） 十五','易靜','唐','唐诗','tang','','[]','途頓止，調節要（京本作「力」）均停。',60,'全唐诗/poet.tang.54000.json','["途頓止，調節要（京本作「力」）均停。", "力若有餘兵有（京本作「軍自」）鋭，縱逢強賊（京本作「卒逢賊馬」）亦堪征，不致有惶驚。"]'),
('512fcfba-4101-4d08-8450-d712c8480f12','兵要望江南 委任第一（京本作「占委任第一」二十六首） 十六','易靜','唐','唐诗','tang','','[]','量強弱，彼我孰優長？',66,'全唐诗/poet.tang.54000.json','["量強弱，彼我孰優長？", "敵若勢雄兵將廣（辛本作「兵將廣大」），吾軍衰弱亦（京本作「何弱力」）難當，主帥要參詳（京本作「奇計可施張」）。", "。"]'),
('a6c7ddb0-fa3a-48d7-bbe0-6dfbfbbbac15','兵要望江南 委任第一（京本作「占委任第一」二十六首） 十七','易靜','唐','唐诗','tang','','[]','將權柄，識務辨（京本作「職務長」）春秋。',69,'全唐诗/poet.tang.54000.json','["將權柄，識務辨（京本作「職務長」）春秋。", "須是先施仁與惠，後行刑戮（京本作「獄」）擇其尤（辛本作「由」），威令（辛本、京本作「愛」）自然收。"]'),
('ee4d503d-87ab-407a-9283-306b00102fd8','兵要望江南 委任第一（京本作「占委任第一」二十六首） 十八','易靜','唐','唐诗','tang','','[]','賞與罰，須是要均平。',60,'全唐诗/poet.tang.54000.json','["賞與罰，須是要均平。", "不可狥（辛本作「循」）私行喜怒，稍（京本作「私」）偏親舊失軍情，如此（辛本、京本作「否則」）禍灾生。"]'),
('7c1a8376-8f7f-40d9-b3a6-54872e7df8c6','兵要望江南 委任第一（京本作「占委任第一」二十六首） 十九','易靜','唐','唐诗','tang','','[]','水與陸，兩勢作艟{舟朋}。',51,'全唐诗/poet.tang.54000.json','["水與陸，兩勢作艟{舟朋}。", "陸有勢形水（京本作「湖」）亦有，舟車捷力（京本作「利」）不相爭，專在將能明。"]'),
('06f8831b-6d09-4571-9da6-5a43c3d95311','兵要望江南 委任第一（京本作「占委任第一」二十六首） 二十','易靜','唐','唐诗','tang','','[]','統軍帥，不可妄行刑。',32,'全唐诗/poet.tang.54000.json','["統軍帥，不可妄行刑。", "莫以軍威行殺戮，人生一失永無生，誤損命天嗔。"]'),
('6239f50e-35cd-443f-826f-197de56ae0ba','兵要望江南 委任第一（京本作「占委任第一」二十六首） 二十一','易靜','唐','唐诗','tang','','[]','統軍帥，職爵受皇恩。',10,'全唐诗/poet.tang.54000.json','["統軍帥，職爵受皇恩。"]'),
('12bc7190-fc8a-4ea9-976a-d797672f5ddc','兵要望江南 委任第一（京本作「占委任第一」二十六首） 二十二','易靜','唐','唐诗','tang','','[]','如信佞，叛背事皆訛。',44,'全唐诗/poet.tang.54000.json','["如信佞，叛背事皆訛。", "自古兩邦難並立（辛本、川本作「立廟」），當朝忠孝賜恩多，世代盡包羅。"]'),
('09dc2a2d-6c23-40d6-bb1e-8466f71bc8f3','兵要望江南 委任第一（京本作「占委任第一」二十六首） 二十三','易靜','唐','唐诗','tang','','[]','狂（京本作「征」）寇走（辛本、川本、京本作「定」），乘馬復還京（京本作「軍」）。',103,'全唐诗/poet.tang.54000.json','["狂（京本作「征」）寇走（辛本、川本、京本作「定」），乘馬復還京（京本作「軍」）。", "結局奏（京本作「有」）功須均（京本作「當」）賞，莫將親識（京本作「舊」）冒功陞，[反]（及）（據辛本、川本、京本改）掩勇無名。"]'),
('433354b8-0df8-4730-a23b-6baf5e13dc76','兵要望江南 委任第一（京本作「占委任第一」二十六首） 二十四','易靜','唐','唐诗','tang','','[]','鋒（辛本、川本作「蜂」、京本作「封」）城壘，謹守保邊隅。',50,'全唐诗/poet.tang.54000.json','["鋒（辛本、川本作「蜂」、京本作「封」）城壘，謹守保邊隅。", "莫恃雄強侵彼境，復從奸佞起兵夫。", "虛國死無辜。"]'),
('83161a1e-2c8e-4097-92db-03cafbc948ed','兵要望江南 委任第一（京本作「占委任第一」二十六首） 二十五','易靜','唐','唐诗','tang','','[]','太平世，積食（京本作「粟」）養雄兵。',79,'全唐诗/poet.tang.54000.json','["太平世，積食（京本作「粟」）養雄兵。", "不可輒忘征戰意（京本作「備」），常時論武（京本作「常須講習」）使兵（辛本、川本作「令」）精，防寇犯（京本作「彼寇」）邊庭。"]'),
('8b9cc812-ccbe-49b0-88ed-3faca70785e0','兵要望江南 委任第一（京本作「占委任第一」二十六首） 二十六','易靜','唐','唐诗','tang','','[]','吾勢鋭，人馬總精雄。',129,'全唐诗/poet.tang.54000.json','["吾勢鋭，人馬總精雄。", "財寶（京本作「貨」）滿盈軍用足（辛本、川本、京本作「足用」），更詳天象審蒼穹，灾禍免（辛本、川本、京本作「那」）軍中。", "（經曰：「用兵者，非信義不立，非陰陽不順，非奇正不列，非詭譎不戰，謀藏於心，事見於迹，心與迹同者敗，心與迹異者勝。", "」）。"]'),
('81ea17c3-4d62-468b-a7fd-d68f69b28072','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 一','易靜','唐','唐诗','tang','','[]','興兵道，風角最爲先。',44,'全唐诗/poet.tang.54000.json','["興兵道，風角最爲先。", "若是逆風（辛本、川本作「迎風」）權且住，後來風助合蒼天，大戰我當先。"]'),
('62b93e10-ab60-45d4-8f78-c71643fbceac','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 二','易靜','唐','唐诗','tang','','[]','春屬木，風自震方來。',32,'全唐诗/poet.tang.54000.json','["春屬木，風自震方來。", "纔起微微聲不大，終無禍福不須猜。", "疑慮却成災。"]'),
('e743a43f-eeb3-4231-89e8-eadf52fe4573','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 三','易靜','唐','唐诗','tang','','[]','離與兌，壬癸子（辛本、川本、京本作「自」）三方。',46,'全唐诗/poet.tang.54000.json','["離與兌，壬癸子（辛本、川本、京本作「自」）三方。", "飄作如春依逐分，不須多慮與張惶，有寇整兵當。"]'),
('705a0532-f11e-40e1-a2ab-63cdc7a09aff','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 四','易靜','唐','唐诗','tang','','[]','四季內，或（京本作「忽」）有猛風聲。',86,'全唐诗/poet.tang.54000.json','["四季內，或（京本作「忽」）有猛風聲。", "倒（京本作「捲」）瓦揚沙急（京本作「幾」）似箭，隨來方所擺（京本作「擁」）精兵，急備彼軍情（辛本、川本作「人」，京本作「急急備軍人」）。"]'),
('7c084ff1-6615-4e65-94fe-84964c7b724c','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 五','易靜','唐','唐诗','tang','','[]','猛風過，如箭便（京本作「更」）無踪，名曰{風昔}{風革}當速備，風聲纔斷賊來攻，日後（京本作「日入」）愈爲凶。',55,'全唐诗/poet.tang.54000.json','["猛風過，如箭便（京本作「更」）無踪，名曰{風昔}{風革}當速備，風聲纔斷賊來攻，日後（京本作「日入」）愈爲凶。"]'),
('148af7e1-9136-44dd-9cb2-fad4aaab9a44','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 六','易靜','唐','唐诗','tang','','[]','兵行次，[黯黯]（點點）（據辛本、京改）久陰沉。',46,'全唐诗/poet.tang.54000.json','["兵行次，[黯黯]（點點）（據辛本、京改）久陰沉。", "不雨又無光色現，下人謀上恨情深，細意要搜尋。"]'),
('394bf6cb-4137-4efb-b1c4-a471d904cca3','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 七','易靜','唐','唐诗','tang','','[]','軍出（京本作「離」）國，風自背邊生（京本作「興」）。',57,'全唐诗/poet.tang.54000.json','["軍出（京本作「離」）國，風自背邊生（京本作「興」）。", "大則大贏爲大勝（京本作「吉兆」），小風小勝總堪征，天意助吾行。"]'),
('6b01abf8-0b78-4ca3-8514-1fd9ac3eb077','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 八','易靜','唐','唐诗','tang','','[]','軍（京本作「兵」）大舉，方出帝王城。',48,'全唐诗/poet.tang.54000.json','["軍（京本作「兵」）大舉，方出帝王城。", "逆面風來軍恐懼，合將人馬結營停，守過待時更（京本作「行」）。"]'),
('04a9de63-b8af-49c0-bd32-15f7773865de','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 九','易靜','唐','唐诗','tang','','[]','軍行次，風猛逆狂吹。',43,'全唐诗/poet.tang.54000.json','["軍行次，風猛逆狂吹。", "出陣若逢如此兆，不如抽退得全歸，免損將兵（辛本、川本作「軍」）危。"]'),
('e0baa42a-7c56-4566-81ad-be574e0bc9df','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 十','易靜','唐','唐诗','tang','','[]','吾撃彼，參審（京本作「審彼」）主人方。',92,'全唐诗/poet.tang.54000.json','["吾撃彼，參審（京本作「審彼」）主人方。", "莫問四時並氣候，風來後助便（辛本、川本作「得」）無妨（京本作「休論刑殺旺衰鄉」），逆面主灾殃（辛本、川本作「迎面莫征狂」，京本作「風要細推詳」）。"]'),
('2cba493d-d41b-4667-a2f6-9e21512b6bce','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 十一','易靜','唐','唐诗','tang','','[]','敵居所，風起自他方。',32,'全唐诗/poet.tang.54000.json','["敵居所，風起自他方。", "便有精兵宜固守，若言舉動禍之殃，實語莫猜量。"]'),
('282d5e5c-9ffc-4ea3-a933-1c9bdc15f1ef','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 十二','易靜','唐','唐诗','tang','','[]','假令（京本作「今」）法，且論在三冬。',63,'全唐诗/poet.tang.54000.json','["假令（京本作「今」）法，且論在三冬。", "彼國守乾吾欲討，風生（辛本、川本、京本作「顛」）西北不堪征（京本作「攻」），以此較餘宮。", "。"]'),
('eb26041a-a763-4b34-886e-2dd24ffc58db','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 十三','易靜','唐','唐诗','tang','','[]','雖是應（京本作「風雖應」），還則（京本作「即」）應他方。',75,'全唐诗/poet.tang.54000.json','["雖是應（京本作「風雖應」），還則（京本作「即」）應他方。", "也是彼贏吾負家，候（京本作「當」）其風止或攻傍（京本作「成殃」），不可不參詳（京本作「量」）。"]'),
('83ac6f39-d3bc-406e-9e9c-29dbaae8970b','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 十四','易靜','唐','唐诗','tang','','[]','假令法，彼國在離間。',83,'全唐诗/poet.tang.54000.json','["假令法，彼國在離間。", "我擁軍前（辛本、川本作「前軍」、京本作「全軍」）時正夏，南征（辛本、川本、京本作「侵」）北敵（京本作「狄」）苦冬寒。", "隨象撃傾（京本作「急摧」）殘。"]'),
('a8482d78-ccd2-4eeb-9515-2d97d139e7e7','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 十五','易靜','唐','唐诗','tang','','[]','八方法，推（辛本、川本、京本作「准」）此定成功。',76,'全唐诗/poet.tang.54000.json','["八方法，推（辛本、川本、京本作「准」）此定成功。", "好事（京本作「是」）急乘他事（辛本、川本、京本作「氣」）逆，勿拘朝暮速吞攻（京本作「功」），莫放彼從容。"]'),
('3cb279cc-b613-49ff-9053-24d0d5a4b4b2','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 十六','易靜','唐','唐诗','tang','','[]','己亥角，辰[戌]（成）（從辛本、京本改）便爲商。',76,'全唐诗/poet.tang.54000.json','["己亥角，辰[戌]（成）（從辛本、京本改）便爲商。", "丑未寅甲皆（京本作「俱」）屬[徴]（子）（據辛本、京本改），宮音子午正相當，卯酉羽爲方（京本作「旁」）。"]'),
('35601d1b-ea94-45dd-9a87-5147c2401d23','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 十七','易靜','唐','唐诗','tang','','[]','占風法，申（京本作「甲」）子是貪狼。',55,'全唐诗/poet.tang.54000.json','["占風法，申（京本作「甲」）子是貪狼。", "丑戌謂之公正位，奸邪辰位自然當。", "細審（辛本、川本、京本作「審細」）看來方。"]'),
('eccc9dfb-99e5-41e7-b17b-c3726795aef2','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 十八','易靜','唐','唐诗','tang','','[]','亥卯位（辛本、川本作「未」），陰賊內（京本作「在」）中藏。',93,'全唐诗/poet.tang.54000.json','["亥卯位（辛本、川本作「未」），陰賊內（京本作「在」）中藏。", "己酉（辛本、川本、京本作「巳酉」）謂之寬大日（京本作「位」），亷貞寅午位（辛本、川本作「未」）其方，知（京本作「加」）意細推詳。"]'),
('37ed8661-a7cc-40c3-b2fe-86e82445fb68','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 十九','易靜','唐','唐诗','tang','','[]','占飄起，客認納音風。',46,'全唐诗/poet.tang.54000.json','["占飄起，客認納音風。", "徴羽宮商幷角姓，盡爲主客（辛本、川本、京本作「位」）辨方蹤，勝負在其中。"]'),
('73acb629-d2c2-4d33-98c0-fe862c18344b','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 二十','易靜','唐','唐诗','tang','','[]','納音土，欲得角來風。',40,'全唐诗/poet.tang.54000.json','["納音土，欲得角來風。", "土是客軍水（京本作「本」）是主，風從己亥發來衝，客敗主收功。"]'),
('a5970d88-b54f-4335-96c9-f8f1be37534f','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 二十一','易靜','唐','唐诗','tang','','[]','納音土，風向羽來吹。',39,'全唐诗/poet.tang.54000.json','["納音土，風向羽來吹。", "（卯酉位也）。", "水被土淩能尅伏，定知主敗客來追，莫要展旌旗。"]'),
('d3247281-5e3a-44d4-8c44-680f7011d22b','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 二十二','易靜','唐','唐诗','tang','','[]','軍營內，忽有旋風來（京本作「卯酉羽風吹」）。',95,'全唐诗/poet.tang.54000.json','["軍營內，忽有旋風來（京本作「卯酉羽風吹」）。", "吹折鎗旗幷倒屋，奸謀惡黨幷來推（辛本、川本、京本作「欲來摧」），暗有賊兵欺（京本作「來」。", "又防火。", "京本注：「風從內起謀在裏，風從外入賊在內。", "」）。"]'),
('3320e040-fa7b-4fa3-be0b-b360e29c264a','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 二十三','易靜','唐','唐诗','tang','','[]','風來處，如式（辛本作「遇」）作泥人。',40,'全唐诗/poet.tang.54000.json','["風來處，如式（辛本作「遇」）作泥人。", "葦箭挑弓披髮向，望空搭箭射來蹤。", "禳厭禍消鎔。"]'),
('aadd8c95-d639-4ccc-8af1-4d8a17121bb1','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 二十四','易靜','唐','唐诗','tang','','[]','泥人子，手執木桃弓。',60,'全唐诗/poet.tang.54000.json','["泥人子，手執木桃弓。", "披髮仰頭風上指，張弓搭箭射來蹤，禳厭禍消鎔。", "（禳惡風法。", "）（按：此首僅見京本，似爲前一首之別本。", "）。"]'),
('45ef0f27-f300-4150-934f-b4b735d807ad','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 二十五','易靜','唐','唐诗','tang','','[]','風衣起（京本作「動」），晝則不聞聲。',60,'全唐诗/poet.tang.54000.json','["風衣起（京本作「動」），晝則不聞聲。", "寇賊夜行明則伏，遣人窺（辛本、川本作「探」）視（京本作「伺候」）莫教停，防備夜偷營。"]'),
('8d814b6d-8baf-463a-b4a0-b8004dc0eb1b','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 二十六','易靜','唐','唐诗','tang','','[]','邦（京本作「郡」）與邑，風猛似雷聲。',68,'全唐诗/poet.tang.54000.json','["邦（京本作「郡」）與邑，風猛似雷聲。", "折木飛沙幷（京本作「兼」）走石，搖門拔戶禍應生，第一怕三刑。", "（京本注：「寅申己亥辰戌丑未之類。", "」）。"]'),
('0af9a195-8dda-4730-ac70-b0509bba2ae4','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 二十七','易靜','唐','唐诗','tang','','[]','軍營內，風猛突然來。',32,'全唐诗/poet.tang.54000.json','["軍營內，風猛突然來。", "若在歲刑憂歲內，月刑之內必爲灾，准備莫遲回。"]'),
('b9c34d7a-045b-4f5d-80db-c30bb5566490','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 二十八','易靜','唐','唐诗','tang','','[]','乾與坎，艮震巽離宮。',72,'全唐诗/poet.tang.54000.json','["乾與坎，艮震巽離宮。", "坤兌八方真正位，敵軍（京本作「人」）居守起方風，狂（辛本、川本、京本作「枉」）戰我無[功]（攻）（據辛本、川本、京本改。", "）。"]'),
('80737bb6-93b8-4d20-8303-e687f185a032','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 二十九','易靜','唐','唐诗','tang','','[]','吾攻彼，審令看風情。',70,'全唐诗/poet.tang.54000.json','["吾攻彼，審令看風情。", "令不順方兵（辛本、川本、京本作「吾」）莫（京本作「可」）撃，風如（京本作「仍」）順我必攻城（京本件「成」），降虜出前迎。"]'),
('cb24699d-54e1-4c99-bd1d-4b7d8d9df87f','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 三十','易靜','唐','唐诗','tang','','[]','營下畢，風卒似雷聲。',84,'全唐诗/poet.tang.54000.json','["營下畢，風卒似雷聲。", "吹倒鎗旗幷（辛本、川本、京本作「旗鎗飄」）帳幕，須防敵騎欲偷（辛本、川本作「棄」、京本作「奪」）營，大戰血交幷。", "（天風起，有雷聲吼，三朝五日同。", "）。"]'),
('20955656-8d03-4e64-bf43-77e9c69c05b9','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 三十一','易靜','唐','唐诗','tang','','[]','兵行次，風卒亂（辛本、京本作「突」）軍旗。',60,'全唐诗/poet.tang.54000.json','["兵行次，風卒亂（辛本、京本作「突」）軍旗。", "人馬驚奔皆恐懼（京本作「悸恐」），前程必有廟堂期（京本作「基」），祭拜免灾危。"]'),
('c0b090fd-86ff-4558-88e5-eca082178477','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 三十二','易靜','唐','唐诗','tang','','[]','臨陣次（京本作「處」），風向後飄（京本作「頭」）來。',66,'全唐诗/poet.tang.54000.json','["臨陣次（京本作「處」），風向後飄（京本作「頭」）來。", "旗幟翩翩吹向敵（京本作「從敵上」），天威默助凱歌回，賊敗息（京本作「悉」）塵埃。"]'),
('d4587105-a4e7-4d84-8ae7-cac6bf13cd6e','兵要望江南 風角第二（辛本作「占風角第二」、京本作「占風第三」。三十三首） 三十三','易靜','唐','唐诗','tang','','[]','臨陣次（京本作「處」），風起四維間。',67,'全唐诗/poet.tang.54000.json','["臨陣次（京本作「處」），風起四維間。", "兵近塞（京本作「寨」）邊先備敵，更（辛本、京本作「便」）從豹尾撃黃幡。", "殺敵（京本作「賊」）不爲難。"]'),
('e852fd25-d81c-4180-b29a-66472c692ab7','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 一','易靜','唐','唐诗','tang','','[]','兵若進，先（辛本、京本作「須」）要（京本作「是」）識浮雲。',75,'全唐诗/poet.tang.54000.json','["兵若進，先（辛本、京本作「須」）要（京本作「是」）識浮雲。", "雲氣順時（京本作「隨」）當急（京本作「速」）戰，毋（京本作「勿」）令雲散後交兵，莫問晝陰晴。"]'),
('128d8bb1-efe5-4205-a3be-b2a3720fa296','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 二','易靜','唐','唐诗','tang','','[]','商音姓，軍陣見[雲從]（從營）（從辛本、京本改。',106,'全唐诗/poet.tang.54000.json','["商音姓，軍陣見[雲從]（從營）（從辛本、京本改。", "）白與黑時（京本作「兮」）吾大吉，青雲亦（京本作「主」）勝赤雲凶，黃者兩平蹤。", "（辛本注：「主取天子姓，不主出帥姓。", "」京本注：「天子出，取天子姓，不出則以主將。", "」）。"]'),
('32585424-8dbb-4498-9e12-31a17756b6b2','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 三','易靜','唐','唐诗','tang','','[]','角音姓，青氣見（辛本作「寓」）晴空。',48,'全唐诗/poet.tang.54000.json','["角音姓，青氣見（辛本作「寓」）晴空。", "黃赤二雲軍（京本作「兵」）亦勝，黑雲陰助喜先鋒，白色定爲凶。"]'),
('5e7ec5d6-d38e-4c6e-bafe-85a7b9929b7b','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 四','易靜','唐','唐诗','tang','','[]','宮音姓，黃色（京本作「赤」）要先逢。',56,'全唐诗/poet.tang.54000.json','["宮音姓，黃色（京本作「赤」）要先逢。", "青色氣（京本作「雲」）來軍大敗，更兼兵死將無功，黑氣利先攻（京本作「鋒」）。"]'),
('c310e938-13b3-468a-a989-8535710eec49','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 五','易靜','唐','唐诗','tang','','[]','徴音姓，赤色火燒金。',70,'全唐诗/poet.tang.54000.json','["徴音姓，赤色火燒金。", "非火（京本作「是」）剋金成大器，青雲（京本作「贏」）黃助黑雲凶（辛本作「白雲黑氣現黃雲」）。", "軍將禍（京本作「盡」）殃深。"]'),
('223e7f38-b662-4347-b2f5-7c2e770a6da4','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 六','易靜','唐','唐诗','tang','','[]','羽音姓，惟是（辛本作「事」）要青（京本作「黑雲」）青，列陣賊來先自（京本作「是」）走，赤黃白黑（京本作「赤雲遍處」）總非贏，宜退（京本作「去」）不宜征。',76,'全唐诗/poet.tang.54000.json','["羽音姓，惟是（辛本作「事」）要青（京本作「黑雲」）青，列陣賊來先自（京本作「是」）走，赤黃白黑（京本作「赤雲遍處」）總非贏，宜退（京本作「去」）不宜征。"]'),
('ee2e6c87-2762-4d04-8bdd-4a2e4e6c18cd','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 七','易靜','唐','唐诗','tang','','[]','雲起處（京本作「氣至」），形色（辛本、川本作「行色」）重而烏。',71,'全唐诗/poet.tang.54000.json','["雲起處（京本作「氣至」），形色（辛本、川本作「行色」）重而烏。", "暗伏賊兵（京本作「師」）軍不見，露其形體（京本作「體象」）在高隅，一半是番胡。", "。"]'),
('d21fa859-ae31-4ebb-b36f-c9fa2060de6c','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 八','易靜','唐','唐诗','tang','','[]','雲起處（京本作「氣至」），低覆似人形。',66,'全唐诗/poet.tang.54000.json','["雲起處（京本作「氣至」），低覆似人形。", "此是賊軍（辛本作「兵」）謀我象（京本作「重」），須防入境起征凶（京本作「凶征」），遣將用精兵。"]'),
('540c2b33-83d5-48e5-89d9-bafe658d5aa0','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 九','易靜','唐','唐诗','tang','','[]','雲似虎，或若豹行形（京本作「形行」）。',70,'全唐诗/poet.tang.54000.json','["雲似虎，或若豹行形（京本作「形行」）。", "及似穿連走匹練（首本注：「一作驄」。", "辛本、川本作「絹」）。", "暴師入境却偷營，排（京本作「摆」）陣整兵迎。"]'),
('81c3fbad-d7a2-4aeb-853c-9f72fa6d3e37','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 十','易靜','唐','唐诗','tang','','[]','四方現，雲色（京本作「氣」）競腾過。',48,'全唐诗/poet.tang.54000.json','["四方現，雲色（京本作「氣」）競腾過。", "黯淡相親（京本作「侵」）來我寨，賊來請命未爲和，賢將莫蹉跎。"]'),
('d6b09894-b618-4465-a493-e5899148cba6','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 十一','易靜','唐','唐诗','tang','','[]','雲起現，片片或舒長。',32,'全唐诗/poet.tang.54000.json','["雲起現，片片或舒長。", "有似舒繩排椽木，名爲愁氣不相當，現處將憂喪。"]'),
('a2c3fc33-44b2-4db1-9fa9-70e25deed05f','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 十二','易靜','唐','唐诗','tang','','[]','雲氣赤，尤更接連綿。',57,'全唐诗/poet.tang.54000.json','["雲氣赤，尤更接連綿。", "有似成長藤無（京本作「幷」）斷續，外邦賊起入（京本作「及」）中原，主戰在秋天（京本作「前」）。"]'),
('191c2ecc-54e3-4c3c-ae68-8f93de7c45ae','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 十三','易靜','唐','唐诗','tang','','[]','雲氣赤，那更滿蒼（京本作「青」）天。',48,'全唐诗/poet.tang.54000.json','["雲氣赤，那更滿蒼（京本作「青」）天。", "必定賊來侵我界，黑雲中赤亦徒然，吾將必（京本作「莫」）遷延。"]'),
('5b59efa1-3b80-47d0-8452-d5921088ff86','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 十四','易靜','唐','唐诗','tang','','[]','雲來往，有似兩[爭龍]（龍爭）（從辛本、川本改，京本作「兩條龍」）。',56,'全唐诗/poet.tang.54000.json','["雲來往，有似兩[爭龍]（龍爭）（從辛本、川本改，京本作「兩條龍」）。", "只在外軍盤頂上，賊邦兵將必逢凶，我帥顯英雄。"]'),
('330a9757-9a93-41c3-9373-4afe3a40a4eb','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 十五','易靜','唐','唐诗','tang','','[]','軍似鳥，盤繞在其（京本作「軍」）中。',57,'全唐诗/poet.tang.54000.json','["軍似鳥，盤繞在其（京本作「軍」）中。", "此時（京本作「是」）上方天（京本作「蒼加」）助順，不宜復見黑雲峰，連赤亦爲凶。"]'),
('67d8bcdd-4a0d-48f4-ac5a-5b90563fb73c','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 十六','易靜','唐','唐诗','tang','','[]','甲乙日，大（辛本、川本作「將」）忌白雲前。',61,'全唐诗/poet.tang.54000.json','["甲乙日，大（辛本、川本作「將」）忌白雲前。", "若奔吾軍還勢急，理當速退（京本作「去」）捨平川，守固在（京本作「固守險」）高原。"]'),
('6e06652d-5b32-487e-b9da-9615e2968115','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 十七','易靜','唐','唐诗','tang','','[]','丙丁日，若（京本作「前」）遇黑雲攔（辛本、川本作「閑」）。',78,'全唐诗/poet.tang.54000.json','["丙丁日，若（京本作「前」）遇黑雲攔（辛本、川本作「閑」）。", "莫恃兵多兼將勇，也宜堅守（京本作「壁」）引師還。", "征戰（京本作「伐」）必遭[殘]（殃）（從京本改）。"]'),
('040b43c4-4252-461f-8242-4d80f517a099','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 十八','易靜','唐','唐诗','tang','','[]','戊己日，前面有雲青。',103,'全唐诗/poet.tang.54000.json','["戊己日，前面有雲青。", "忽止忽行權且住（辛本、川本作「急止匆行權住在」，京本作「急止勿行權住寨」，似以京本爲長），軍人訛（辛本、川本作「須」）語審詳聽，施德惠於（京本作「其」）兵（辛本、川本作「施惠得中旌」）。"]'),
('9a0fbb80-5700-459a-90d3-655f488b8699','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 十九','易靜','唐','唐诗','tang','','[]','庚辛日，前忌赤雲來。',56,'全唐诗/poet.tang.54000.json','["庚辛日，前忌赤雲來。", "勢緊迫（京本作「迎」）吾須大戰，彼軍得勝我軍摧，守險固顛危。", "（過旬〖京本作「日」〗中却行）。"]'),
('8b5a7e49-0867-4350-ae13-7593ccfc673b','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 二十','易靜','唐','唐诗','tang','','[]','壬癸日，雲忌暗（京本作「色」）而黃。',70,'全唐诗/poet.tang.54000.json','["壬癸日，雲忌暗（京本作「色」）而黃。", "此兆主灾軍（京本作「兵」）將損（辛本、川本作「迎老將」），無緣兵廣恣猖狂，謀者審（京本作「貴密」）而詳。"]'),
('c0c69b7d-798c-43d7-a887-b4a3873c44e2','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 二十一','易靜','唐','唐诗','tang','','[]','[觀]（現）（從辛本、京本改）雲氣，擇士細詳（京本作「汝當」）看。',101,'全唐诗/poet.tang.54000.json','["[觀]（現）（從辛本、京本改）雲氣，擇士細詳（京本作「汝當」）看。", "晝夜[用]（同）（從辛本改）心精審究（京本作「却須精細審」），莫將此事以（京本作「擬」）爲閑，風色便（辛本作「辨」，京本作「旺」）相干。"]'),
('fedee86a-f555-499c-91e2-ee7484c724cf','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 二十二','易靜','唐','唐诗','tang','','[]','軍營上，雲若似飛烏。',32,'全唐诗/poet.tang.54000.json','["軍營上，雲若似飛烏。", "有似盖來幷伏虎，此爲勝氣不須疑，攻則定疎虞。"]'),
('7b576c18-6f98-4b63-bc6b-3e128eca6e54','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 二十三','易靜','唐','唐诗','tang','','[]','軍營上，雲若死灰揚。',63,'全唐诗/poet.tang.54000.json','["軍營上，雲若死灰揚。", "若似（辛本、川本作「盖」）臥魚或乍見，此爲衰氣不須張，不動將兵（辛本、川本作「軍」）亡。", "（移寨遠處吉。", "）。"]'),
('7ed997bb-6b1e-4066-8fb8-a5139624dc05','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 二十四','易靜','唐','唐诗','tang','','[]','城頭上，突出赤色雲。',32,'全唐诗/poet.tang.54000.json','["城頭上，突出赤色雲。", "或是黃紅雲上現，城中不久喜來臻，以此得和平。"]'),
('204ee8e7-7094-4b79-8539-06653309ea73','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 二十五','易靜','唐','唐诗','tang','','[]','占候法，雞羽作爲車。',32,'全唐诗/poet.tang.54000.json','["占候法，雞羽作爲車。", "二者勿惟牙帳內，敵人千里外須圖，知辨在須臾。"]'),
('b6de7054-5f2b-4d1c-af17-77a799fb2033','兵要望江南 占雲第三（京本作「占雲第二十四○二十六首」） 二十六','易靜','唐','唐诗','tang','','[]','將軍善，識得氣妖祥。',81,'全唐诗/poet.tang.54000.json','["將軍善，識得氣妖祥。", "風角鳥占能總解，心無機巧計從長，報國效忠良。", "（既有其象，當隨其景，就謀術，以破其軍。", "）（按：以上二首據京本補，首本等入《占氣第四》，稍異。", "）。"]'),
('85878ab8-60b8-4782-b771-175dd99823b2','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 一','易靜','唐','唐诗','tang','','[]','占氣色（辛本作「法」），雞羽爲輪車。',40,'全唐诗/poet.tang.54000.json','["占氣色（辛本作「法」），雞羽爲輪車。", "二者勿離牙帳內，敵人千里外須知，圖變在須臾。"]'),
('d3b88e51-e2d2-4e92-b013-67ebb9518d17','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 二','易靜','唐','唐诗','tang','','[]','軍既舉，惟以氣爲先。',32,'全唐诗/poet.tang.54000.json','["軍既舉，惟以氣爲先。", "兵若精雄加氣銳，超關投石可攻前，鼓作在英賢。"]'),
('2fdd6603-5605-4a75-b55c-849c014278a0','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 三','易靜','唐','唐诗','tang','','[]','將軍善（一作「位」），識得（一作「善識」）氣妖祥。',109,'全唐诗/poet.tang.54000.json','["將軍善（一作「位」），識得（一作「善識」）氣妖祥。", "風角鳥雲能總解，機[籌]（策）謀略[又]（應）（均從辛本改）相當，取勝應功良（一作「征討又功強」）。", "（按：此首又重見于「觀氣色」一首之後，今刪去，異文注爲「一作」。", "）。"]'),
('e7fab689-1c0d-4b82-baa8-7e23881c0532','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 四','易靜','唐','唐诗','tang','','[]','軍（辛本、川本、京本作「兵」）進撃，覩（京本作「觀」）氣合參詳。',70,'全唐诗/poet.tang.54000.json','["軍（辛本、川本、京本作「兵」）進撃，覩（京本作「觀」）氣合參詳。", "不似（京本作「必」）攻城幷野戰，度其形狀自（京本作「細」）斟量，稍錯便乖張。"]'),
('a1d8a363-cd5d-4f6b-a678-98e5f141c928','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 五','易靜','唐','唐诗','tang','','[]','城營內，氣似鳳（京本作「似鳳或」）如龍。',76,'全唐诗/poet.tang.54000.json','["城營內，氣似鳳（京本作「似鳳或」）如龍。", "更若大（京本作「太」）山幷類蓋，猶如（辛本作「人」）火（京本作「人大」）赤降城中，其下不堪攻。", "（下必有貴人。", "）。"]'),
('6775560a-fe53-47cb-abd3-576d3577b96e','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 六','易靜','唐','唐诗','tang','','[]','高空現，拂拂又微微。',41,'全唐诗/poet.tang.54000.json','["高空現，拂拂又微微。", "透闕（京本作「秀潤」）輕籠煙靉靉，一般黃氣色依依，慶賀兩朝期。"]'),
('39e7af64-bc20-4f82-bc61-64a4a63eb858','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 七','易靜','唐','唐诗','tang','','[]','猛將氣，龍虎兩（京本作「氣」）兩連。',48,'全唐诗/poet.tang.54000.json','["猛將氣，龍虎兩（京本作「氣」）兩連。", "掛翳蔽天兼掠地，蔓瓜蓋路（京本作「地」）覆平川，堅守莫爭先。"]'),
('cd1d8010-4e65-48b7-9343-1ce47231f5f9','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 八','易靜','唐','唐诗','tang','','[]','猛將氣，樓閣及旌幢。',49,'全唐诗/poet.tang.54000.json','["猛將氣，樓閣及旌幢。", "或似長堤形淼淼，更如華（京本作「兵」）蓋與王良（京本作「蟲狼」），其下莫能當。"]'),
('6f9ce01d-6317-4365-9ca1-e1aa7544852c','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 九','易靜','唐','唐诗','tang','','[]','猛將氣，黑色似龍形。',62,'全唐诗/poet.tang.54000.json','["猛將氣，黑色似龍形。", "或似（辛本、川本、京本作「類」）虎形（京本作「熊」）幷猛獸，當（京本作「形」）其敵上或城營，不可向前征。"]'),
('94fdeaf2-0211-41f1-b123-9a98f73b18b6','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 十','易靜','唐','唐诗','tang','','[]','猛將氣，顯赫（京本作「象」）又衝天。',52,'全唐诗/poet.tang.54000.json','["猛將氣，顯赫（京本作「象」）又衝天。", "或似雙蛇山岳（辛本、川本作「兵」）樣，又如倉廩及濃烟，休戰最爲先。", "。"]'),
('bad32cda-c272-448d-b41d-49c571299ed5','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 十一','易靜','唐','唐诗','tang','','[]','猛將氣，持戟（京本作「戈」）又（辛本、川本、京本作「或」）持刀。',54,'全唐诗/poet.tang.54000.json','["猛將氣，持戟（京本作「戈」）又（辛本、川本、京本作「或」）持刀。", "林下森森弓弩樣，色兼青白若脂膏，將士盡雄豪。"]'),
('68dbeea2-3143-43a4-91aa-5d18d188c1aa','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 十二','易靜','唐','唐诗','tang','','[]','猛將氣，如虎黑霞遮。',32,'全唐诗/poet.tang.54000.json','["猛將氣，如虎黑霞遮。", "或似門樓旗立內，又如氣出若蛟蛇，其下將堪誇。"]'),
('7674abc6-bbd9-43cd-a88e-b4fd94eef592','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 十三','易靜','唐','唐诗','tang','','[]','暴兵氣，如火又如烟。',79,'全唐诗/poet.tang.54000.json','["暴兵氣，如火又如烟。", "或似旗{旛巾=方}幷戰（京本作「五」）馬，低頭仰（京本作「傾」）[尾]（面）（從辛本、川本、京本改）向軍前（京本作「前軍」），觸戰血成川。"]'),
('9d424b3f-89d8-4f5b-a7fa-fb1896ef0468','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 十四','易靜','唐','唐诗','tang','','[]','伏兵氣，渾渾又能圓。',88,'全唐诗/poet.tang.54000.json','["伏兵氣，渾渾又能圓。", "黑（京本作「赤」）氣中間環赤色（辛本、川本作「色」，京本作「含黑氣」），又如赤杵黑霞連（京本作「邊」），其下立戈鋋。", "（狀如赤杵在黑氣中[也]）（據京本補）。"]'),
('6773e2e7-f7ec-4394-88af-93b95d6cfdbf','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 十五','易靜','唐','唐诗','tang','','[]','降兵氣，叉手盡低頭。',46,'全唐诗/poet.tang.54000.json','["降兵氣，叉手盡低頭。", "形似成行相把手，三朝五日敵兵（辛本、川本、京本作「來」）求，指日倒戈矛。"]'),
('b22abf99-faa6-424f-8e53-7f1433eca1fb','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 十六','易靜','唐','唐诗','tang','','[]','降兵氣，髣髴狀如樓。',63,'全唐诗/poet.tang.54000.json','["降兵氣，髣髴狀如樓。", "兼有似人形黑赤，或如（京本作「如逢」）山岳立（辛本、川本、京本作「覆」）崗丘（京本作「頭」），其下有戈矛。"]'),
('502c990d-a912-4b6b-8414-71ef7d9c9af0','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 十七','易靜','唐','唐诗','tang','','[]','兵發（京本作「發兵」）日，天氣久陰沉。',57,'全唐诗/poet.tang.54000.json','["兵發（京本作「發兵」）日，天氣久陰沉。", "不雨又無光彩色，奸人謀事（京本作「士」）恨懷心，仔細速（京本作「早」）推尋。"]'),
('d52c81b0-bcd8-47b0-b677-8fce834d65b2','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 十八','易靜','唐','唐诗','tang','','[]','[觀]（現）（從京本、辛本、川本改）氣色，日月氣來衝。',57,'全唐诗/poet.tang.54000.json','["[觀]（現）（從京本、辛本、川本改）氣色，日月氣來衝。", "北面氣來還北壯，氣南南壯或西東，常（京本作「俱」）以此爲宗。"]'),
('81236630-a4c7-418e-86e7-6b9830ca61d5','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 十九','易靜','唐','唐诗','tang','','[]','城上氣，結似犬羊（京本作「作犬頭」）形。',50,'全唐诗/poet.tang.54000.json','["城上氣，結似犬羊（京本作「作犬頭」）形。", "象主血流圍邑破，好持降類出門迎，方免血（京本作「死」）殘兵。"]'),
('8378571f-c123-4e6c-8f64-71f7eda02f21','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 二十','易靜','唐','唐诗','tang','','[]','占蒙氣，鬱鬱達（辛本作「遶」）城營。',40,'全唐诗/poet.tang.54000.json','["占蒙氣，鬱鬱達（辛本作「遶」）城營。", "其氣周迴如帛遶，分毫不入此城中，休撃此般城。"]'),
('c621dceb-bf49-4a2c-98e6-0bbd675942e6','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 二十一','易靜','唐','唐诗','tang','','[]','城營寨，有氣入城中。',32,'全唐诗/poet.tang.54000.json','["城營寨，有氣入城中。", "必主奸謀事已定，安排大戰奪吾城，謹守令嚴明。"]'),
('31eff90a-e8d2-4e67-b8f9-adce082ff623','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 二十二','易靜','唐','唐诗','tang','','[]','軍上氣，漸漸變成雲。',43,'全唐诗/poet.tang.54000.json','["軍上氣，漸漸變成雲。", "或作山形於直上，內中將有大（辛本作「大有將」）機謀，要撃且休休。", "。"]'),
('f7e00c92-bc24-414b-b47c-f875801f3959','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 二十三','易靜','唐','唐诗','tang','','[]','臨陣次，赤氣後前生。',46,'全唐诗/poet.tang.54000.json','["臨陣次，赤氣後前生。", "必有伏兵埋氣下，事[須]（雖）（從辛本、川本改）謹慎探其情，固守莫胡行。"]'),
('18317edc-f254-4831-96a5-3153101df3e5','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 二十四','易靜','唐','唐诗','tang','','[]','占敗氣，如綱又如蛇。',32,'全唐诗/poet.tang.54000.json','["占敗氣，如綱又如蛇。", "赤氣照天營上起，又如破屋壞毡車，其下死如麻。"]'),
('4b5b9b96-6cb0-4d00-adea-9c20496e709e','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 二十五','易靜','唐','唐诗','tang','','[]','占敗氣，捲（京本作「掃」）帚似猪羊。',57,'全唐诗/poet.tang.54000.json','["占敗氣，捲（京本作「掃」）帚似猪羊。", "藤蔓死蛟幷（京本作「蛇兼」）死狗，塵埃走鹿又（京本作「及」）驚獐，不戰自奔亡。"]'),
('6a5e9614-4496-44ee-859e-0907105bea1f','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 二十六','易靜','唐','唐诗','tang','','[]','占敗氣，羣鳥似低頭。',43,'全唐诗/poet.tang.54000.json','["占敗氣，羣鳥似低頭。", "或類揚灰魚臥樣（辛本、京本作「死」），懸鐘映暈或牽牛，纔戰若星流。"]'),
('74a4f0bc-8445-4998-bb37-2c77d3b884f2','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 二十七','易靜','唐','唐诗','tang','','[]','占敗氣，掃（京本作「如」）帚又如虹。',49,'全唐诗/poet.tang.54000.json','["占敗氣，掃（京本作「如」）帚又如虹。", "捲席（京本作「鑼鼓」）懸衣灰色樣，臥屍無首覆船同，戰彼不須攻。"]'),
('87d19542-9134-4279-b351-fc99edcdc311','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 二十八','易靜','唐','唐诗','tang','','[]','敗軍（京本作「占敗」）氣，鳩尾及鷹（京本作「鸚」）飛。',67,'全唐诗/poet.tang.54000.json','["敗軍（京本作「占敗」）氣，鳩尾及鷹（京本作「鸚」）飛。", "或似壞山幷破屋，彼軍形（京本作「有」）現敗無疑，一戰自（京本作「纔戰便」）奔馳。"]'),
('1f2612e2-46a9-49fe-b362-96292cf15460','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 二十九','易靜','唐','唐诗','tang','','[]','敗軍氣，乍有（京本作「大」）乍微纖（京本作「微」）。',67,'全唐诗/poet.tang.54000.json','["敗軍氣，乍有（京本作「大」）乍微纖（京本作「微」）。", "一去一來皆斷續，又如霞氣入青天（京本作「在平田」），俱是敗之先（京本作「亡原」）。"]'),
('8b380bf7-87a3-47e5-967d-753efd87ded4','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 三十','易靜','唐','唐诗','tang','','[]','敗軍氣，千萬似人頭。',49,'全唐诗/poet.tang.54000.json','["敗軍氣，千萬似人頭。", "更有（京本作「似」）偃魚零落樹，如灰（京本作「又如」）瓦礫覆城樓，其下血交流。"]'),
('2140b750-7738-4996-8dd1-157af986ec75','兵要望江南 占氣第四（京本作「占氣第二十三」○三十一首） 三十一','易靜','唐','唐诗','tang','','[]','黑氣現，其象若胡人。',48,'全唐诗/poet.tang.54000.json','["黑氣現，其象若胡人。", "又似虜兵（京本作「軍」）排列陣，八方夷夏（京本作「狄」）起烟塵，民戮屋燒焚。"]'),
('bef88a68-8749-4f24-a706-150cb6a9a36d','兵要望江南 占霧第五（京本列第八○十首） 一','易靜','唐','唐诗','tang','','[]','天霧者，不止四時生。',44,'全唐诗/poet.tang.54000.json','["天霧者，不止四時生。", "陽不順時陰成霧，陰不和上霧昏沉（辛本、川本作「昏昏」）。", "邪氣事難精。"]'),
('9cef37f2-c21e-456f-ad7f-90da7b8b4275','兵要望江南 占霧第五（京本列第八○十首） 二','易靜','唐','唐诗','tang','','[]','天之霧，五七日當占。',32,'全唐诗/poet.tang.54000.json','["天之霧，五七日當占。", "有雨時時且平吉，若無雨時疫瘟纏。", "民病有災愆。"]'),
('f5e5f336-a5a8-4f75-94ba-a49bb6ce5905','兵要望江南 占霧第五（京本列第八○十首） 三','易靜','唐','唐诗','tang','','[]','相對敵，有霧敵（京本作「客」）邊來。',65,'全唐诗/poet.tang.54000.json','["相對敵，有霧敵（京本作「客」）邊來。", "似雨紛紛來（京本作「須」）勢急，如烟入眼目（京本作「眼」）難開。", "馬步一齊（京本作「時」）來。", "。"]'),
('e7e5001a-a109-423a-b567-9d30c38826ae','兵要望江南 占霧第五（京本列第八○十首） 四','易靜','唐','唐诗','tang','','[]','兵發日，霧氣晝昏昏（京本作「紛紛」）。',83,'全唐诗/poet.tang.54000.json','["兵發日，霧氣晝昏昏（京本作「紛紛」）。", "一（辛本、川本、京本作「欲」）似露來兼灑（京本作「霧來兼似」）雨，此爲天泣淚（京本作「血」）紛紛，須駐（京本作「駐泊」）賞三軍。"]'),
('b5c13885-8ffc-433d-ad69-c62eb2560cdd','兵要望江南 占霧第五（京本列第八○十首） 五','易靜','唐','唐诗','tang','','[]','久陰霧，顏色帶紅鮮。',62,'全唐诗/poet.tang.54000.json','["久陰霧，顏色帶紅鮮。", "更被黃（辛本、川本、京本作「黑」）風吹上去，兵戈即日（京本作「目」）展平川，速備（京本作「避」）莫遷延。"]'),
('e95475ac-f40c-4da5-af35-7ee7365f0840','兵要望江南 占霧第五（京本列第八○十首） 六','易靜','唐','唐诗','tang','','[]','城營上，有霧似懸屍。',40,'全唐诗/poet.tang.54000.json','["城營上，有霧似懸屍。", "爲將且須觀此象，所居營寨即那（京本作「須」）移。", "不去將當之。"]'),
('2b5f04de-add4-4b4c-8510-173b5e037fab','兵要望江南 占霧第五（京本列第八○十首） 七','易靜','唐','唐诗','tang','','[]','軍營內，大霧數朝濃（首本作「昏」，從辛本、川本、京本改）。',65,'全唐诗/poet.tang.54000.json','["軍營內，大霧數朝濃（首本作「昏」，從辛本、川本、京本改）。", "晝夜不開相對敵，客軍先敗走奔衝，排陣（辛本、川本、京本作「隊」）襲其蹤。"]'),
('473e24b2-fe52-4649-9287-f6e001e46888','兵要望江南 占霧第五（京本列第八○十首） 八','易靜','唐','唐诗','tang','','[]','城（京本作「軍」）營內，大霧起城頭。',72,'全唐诗/poet.tang.54000.json','["城（京本作「軍」）營內，大霧起城頭。", "白色似（京本作「沙」）烟兵戰起（辛本、川本、京本作「喜」），三朝五日簇戈矛，准備好（京本作「防備外」）方遊。"]'),
('71f72f07-85b9-4c9b-8c71-78b4e4f3e300','兵要望江南 占霧第五（京本列第八○十首） 九','易靜','唐','唐诗','tang','','[]','大（京本作「青」）黃霧，騰{曰/卓}（京本作「勝氣」）掩山川。',70,'全唐诗/poet.tang.54000.json','["大（京本作「青」）黃霧，騰{曰/卓}（京本作「勝氣」）掩山川。", "乍合乍開防詐僞，須防內外有（京本作「與外」）相連，不悟血侵（京本作「浸」）田。"]'),
('dc2789fc-874d-490a-9a4a-a105ec4f18c3','兵要望江南 占霧第五（京本列第八○十首） 十','易靜','唐','唐诗','tang','','[]','周迴霧，城內沒些兒。',32,'全唐诗/poet.tang.54000.json','["周迴霧，城內沒些兒。", "欲要攻城攻不得，其城天助有軍威，謹守自安宜。"]'),
('9853c522-724c-4606-8100-24d675eea285','兵要望江南 占霞第六（京本列第二十六○十一首） 一','易靜','唐','唐诗','tang','','[]','占霞色，似氣不相成。',32,'全唐诗/poet.tang.54000.json','["占霞色，似氣不相成。", "形若似雲雲不是，形如拖掃氣紛紛，識者自詳因。"]'),
('56577629-1041-4f9c-a848-5b1e399811c0','兵要望江南 占霞第六（京本列第二十六○十一首） 二','易靜','唐','唐诗','tang','','[]','兵發日，占顧（京本作「看」）面前霞。',50,'全唐诗/poet.tang.54000.json','["兵發日，占顧（京本作「看」）面前霞。", "甲乙怕逢霞氣白，丙丁黑氣向前遮，大戰不應差（京本作「定交加」）。"]'),
('0ee0b974-0039-47ef-b2f2-b9df8bbbdf94','兵要望江南 占霞第六（京本列第二十六○十一首） 三','易靜','唐','唐诗','tang','','[]','兵發日，霞氣日辰幷（辛本、川本作「兵」）。',83,'全唐诗/poet.tang.54000.json','["兵發日，霞氣日辰幷（辛本、川本作「兵」）。", "縱有前程應（京本作「勿」）大戰，逢霞生日應須贏，拗日不宜（京本作「須」）征（辛本、川本作「多精」。", "甲乙日黃、戊己日黑之類）。"]'),
('96d7fd0b-70e9-476b-9c90-873215e071cf','兵要望江南 占霞第六（京本列第二十六○十一首） 四','易靜','唐','唐诗','tang','','[]','觀霞氣（辛本、川本作「氣色」），霞氣日辰裁（京本作「諧」）。',52,'全唐诗/poet.tang.54000.json','["觀霞氣（辛本、川本作「氣色」），霞氣日辰裁（京本作「諧」）。", "兵進前途交戰勝，開疆玉帛積成堆，人馬盡驅來。"]'),
('bfdc79d2-dee0-49a2-b810-e67fe0ad519e','兵要望江南 占霞第六（京本列第二十六○十一首） 五','易靜','唐','唐诗','tang','','[]','兵發日，五氣辨灾祥。',40,'全唐诗/poet.tang.54000.json','["兵發日，五氣辨灾祥。", "角姓怕逢霞氣白，羽音黃氣莫禁（京本作「相」）當，宮姓怕青蒼。"]'),
('96aa2740-2606-4658-b308-a37a0a0fa811','兵要望江南 占霞第六（京本列第二十六○十一首） 六','易靜','唐','唐诗','tang','','[]','商音姓，前怕赤霞攔。',40,'全唐诗/poet.tang.54000.json','["商音姓，前怕赤霞攔。", "徴姓黑霞幷黑氣，皆爲鬼賊怕相殘（京本作「攀」），不得視爲閑。"]'),
('7d67c71e-70bc-47be-86dd-87fe0e9a3e08','兵要望江南 占霞第六（京本列第二十六○十一首） 七','易靜','唐','唐诗','tang','','[]','城營上，五色氣幷霞。',66,'全唐诗/poet.tang.54000.json','["城營上，五色氣幷霞。", "盡是賊（京本作「敗」）軍天預顯，早須爲計好防他（辛本、川本作「警覺較量些」、京本作「警悟較些些」）。", "否則死如麻。"]'),
('30d8c69c-091e-4655-b64a-52df149843b0','兵要望江南 占霞第六（京本列第二十六○十一首） 八','易靜','唐','唐诗','tang','','[]','霞與氣，二件或相兼。',42,'全唐诗/poet.tang.54000.json','["霞與氣，二件或相兼。", "氣若色黃赤白好，霞如黑色亦（京本作「氣色一」）同占，髣髴在良賢。"]'),
('9ecb0c6e-7203-42b4-835c-d7d657dad140','兵要望江南 占霞第六（京本列第二十六○十一首） 九','易靜','唐','唐诗','tang','','[]','霞似虎（辛本作「似席」、京本作「與氣」），雲即便（京本作「變」）爲龍。',92,'全唐诗/poet.tang.54000.json','["霞似虎（辛本作「似席」、京本作「與氣」），雲即便（京本作「變」）爲龍。", "龍虎相交軍必戰（川本、辛本作「勝」），臨時勝負更看風（辛本、川本作「辨誰凶」），逐（辛本、川本作「遂」）我彼軍凶。"]'),
('b9d376c9-62bc-44c5-90d8-190fb3e65cf8','兵要望江南 占霞第六（京本列第二十六○十一首） 十','易靜','唐','唐诗','tang','','[]','出軍日，霞氣莫前攔。',43,'全唐诗/poet.tang.54000.json','["出軍日，霞氣莫前攔。", "我後氣來風更順，從他前銳後寬嚴（辛本、川本作「寬」），軍馬獲平安。"]'),
('9c1479cf-6f49-4175-891d-d20680aacd0c','兵要望江南 占霞第六（京本列第二十六○十一首） 十一','易靜','唐','唐诗','tang','','[]','攻城寨，先料水清源（首本作「源情」、辛本、川本作「情源」，此從京本）。',57,'全唐诗/poet.tang.54000.json','["攻城寨，先料水清源（首本作「源情」、辛本、川本作「情源」，此從京本）。", "上有大流堪決灌，不須交刃損兵員，勿縱暴剛權。"]'),
('fae03a94-8286-4f27-87d2-76a614bdb218','兵要望江南 占虹霓第七（京本作「占虹第九」○十一首） 一','易靜','唐','唐诗','tang','','[]','虹霓現，因雨影東西。',32,'全唐诗/poet.tang.54000.json','["虹霓現，因雨影東西。", "晨現必當雨未止，晚來東現日光輝，術者細觀之。"]'),
('3db87bc4-ae57-42bb-8741-bb8c8a8499ee','兵要望江南 占虹霓第七（京本作「占虹第九」○十一首） 二','易靜','唐','唐诗','tang','','[]','兵行次，虹貫日（京本作「路」）邊傍。',75,'全唐诗/poet.tang.54000.json','["兵行次，虹貫日（京本作「路」）邊傍。", "禦（京本作「預」）備伏兵前有阻，且須審細自（京本作「更」）商量，移寨避灾殃（辛本、川本、京本作「終不得開疆」）。", "。"]'),
('a90b0985-951f-4afa-8f71-2a618b92d3aa','兵要望江南 占虹霓第七（京本作「占虹第九」○十一首） 三','易靜','唐','唐诗','tang','','[]','虹霓現，城寨可攻之。',62,'全唐诗/poet.tang.54000.json','["虹霓現，城寨可攻之。", "虹（辛本、川本作「蛇」）直入來爲病疫，淺虹兵瘴（京本作「青虹兵戰」）要須知，移寨避灾宜（京本作「危」）。"]'),
('a0d7cfef-2d17-4f6b-983f-ed65c3dff9a2','兵要望江南 占虹霓第七（京本作「占虹第九」○十一首） 四','易靜','唐','唐诗','tang','','[]','虹赤白，盡是阻軍行。',48,'全唐诗/poet.tang.54000.json','["虹赤白，盡是阻軍行。", "若是（京本作「似」）虹橋欄着路，且須盤泊犒（京本作「靠」）軍兵，不久却回程。"]'),
('2fe129d5-d149-4ff3-acb0-8f50048d8e89','兵要望江南 占虹霓第七（京本作「占虹第九」○十一首） 五','易靜','唐','唐诗','tang','','[]','虹入井，盡是敗軍情。',48,'全唐诗/poet.tang.54000.json','["虹入井，盡是敗軍情。", "或有（京本作「似」）鼠形營上現，忽然交戰血成坑，防（京本作「勿」）撃保城營。"]'),
('7c1f0ae4-dada-485d-a817-cc932bb685d7','兵要望江南 占虹霓第七（京本作「占虹第九」○十一首） 六','易靜','唐','唐诗','tang','','[]','虹如暈，更復（京本作「或」）似弓形。',60,'全唐诗/poet.tang.54000.json','["虹如暈，更復（京本作「或」）似弓形。", "有若白虹形斷續，兼之五六見城營，皆主血光成（京本作「生」。", "京本注：「或見五六月」）。"]'),
('1a2571ec-f313-41ac-9a3b-695ebd446b8d','兵要望江南 占虹霓第七（京本作「占虹第九」○十一首） 七','易靜','唐','唐诗','tang','','[]','虹霓見，更或似弓形。',43,'全唐诗/poet.tang.54000.json','["虹霓見，更或似弓形。", "有若暈來如斷續，兵興五日定（辛本、川本作「便」）回程。", "久住必灾成。"]'),
('50da9443-962b-4d51-a2db-92084b98e1e4','兵要望江南 占虹霓第七（京本作「占虹第九」○十一首） 八','易靜','唐','唐诗','tang','','[]','白赤虹，單見色無雙。',32,'全唐诗/poet.tang.54000.json','["白赤虹，單見色無雙。", "如氣冲天或橫過，蚩尤旗號動戈鎗，起處必爲殃。"]'),
('2cb99ff8-0c0b-40c2-8d66-a760adba5c7f','兵要望江南 占虹霓第七（京本作「占虹第九」○十一首） 九','易靜','唐','唐诗','tang','','[]','虹起處，頭尾地侵天。',32,'全唐诗/poet.tang.54000.json','["虹起處，頭尾地侵天。", "其虹見時非有雨，晴天見者血成川，民更有灾愆。"]'),
('a7f9cfd6-7f54-4737-9d0d-ada81cb18e68','兵要望江南 占虹霓第七（京本作「占虹第九」○十一首） 十','易靜','唐','唐诗','tang','','[]','白虹見，晝（川本作「盡」）見地侵（辛本、川本作「青」）天。',51,'全唐诗/poet.tang.54000.json','["白虹見，晝（川本作「盡」）見地侵（辛本、川本作「青」）天。", "其地一方皆主亂，衆人喧鬧有灾纏，年內應其占。"]'),
('4874dc2a-9909-4205-b5da-4907c0724484','兵要望江南 占虹霓第七（京本作「占虹第九」○十一首） 十一','易靜','唐','唐诗','tang','','[]','白赤虹，晝（川本作「盡」）見莫興兵。',40,'全唐诗/poet.tang.54000.json','["白赤虹，晝（川本作「盡」）見莫興兵。", "更有虹霓垂軍上，彼軍殺將且須停，動必有灾迍。"]'),
('29041e3a-e091-452c-a3e1-f627290636be','兵要望江南 占雨第八（京本列第二○十七首） 一','易靜','唐','唐诗','tang','','[]','凡論雨，二氣是陰陽。',32,'全唐诗/poet.tang.54000.json','["凡論雨，二氣是陰陽。", "升則爲雲降則雨，若逢兵動合灾祥，良將要參詳。"]'),
('b2e1b93b-a166-4002-87ae-32c3bd4fdc42','兵要望江南 占雨第八（京本列第二○十七首） 二','易靜','唐','唐诗','tang','','[]','師在道，或始出郊城。',51,'全唐诗/poet.tang.54000.json','["師在道，或始出郊城。", "雷雨如傾溪澗阻，沐（京本作「淋」）屍凶象不堪行，勿要（辛本、川本作「足」）與天爭。"]'),
('7653d8c6-c52e-46e5-931f-8c7b26379bca','兵要望江南 占雨第八（京本列第二○十七首） 三','易靜','唐','唐诗','tang','','[]','兵（辛本、川本、京本作「軍」）始進，雨急立成泥。',122,'全唐诗/poet.tang.54000.json','["兵（辛本、川本、京本作「軍」）始進，雨急立成泥。", "名曰沐（京本作「淋」）屍當立（辛本、川本、京本作「速」）止，別詮吉日與良時，強進必（京本作「有」）凶危。", "（京本注：軍讖曰：兵行日暴風猛雨，折旗幟不止，此天怒也，不可進兵。", "待天象和明，別擇日行。", "）。"]'),
('f4b9534a-0993-4476-ad06-c32d51a3fcb2','兵要望江南 占雨第八（京本列第二○十七首） 四','易靜','唐','唐诗','tang','','[]','軍發日，微雨灑軍（京本作「潤兵」）行。',50,'全唐诗/poet.tang.54000.json','["軍發日，微雨灑軍（京本作「潤兵」）行。", "此是潤軍兵（京本作「兵人」）必利，旌旗前指最爲精，所向定須贏。"]'),
('58202681-d2d3-4587-bf8d-e203db829a22','兵要望江南 占雨第八（京本列第二○十七首） 五','易靜','唐','唐诗','tang','','[]','兵始進，旗幟繞於鎗。',32,'全唐诗/poet.tang.54000.json','["兵始進，旗幟繞於鎗。", "半雨半晴霞氣過，且須盤泊好參詳，去即陣難當。"]'),
('acd85db9-01f5-4562-8f08-d7fc531e15ef','兵要望江南 占雨第八（京本列第二○十七首） 六','易靜','唐','唐诗','tang','','[]','天數日，半雨半兼（川本作「無」）晴。',56,'全唐诗/poet.tang.54000.json','["天數日，半雨半兼（川本作「無」）晴。", "營內有奸謀結叛，先晴後雨叛難成（京本作「擒」），先雨後晴興（京本作「兵」）。"]'),
('c2850b91-69a3-40d3-a078-d6ac86176067','兵要望江南 占雨第八（京本列第二○十七首） 七','易靜','唐','唐诗','tang','','[]','兵（首本作「風」，此從辛本）發日，風雨逆沾人。',112,'全唐诗/poet.tang.54000.json','["兵（首本作「風」，此從辛本）發日，風雨逆沾人。", "天意示（辛本作「欲」）知教我記，不須前進恐危身，見陣潰亡軍。", "（《軍行志》：如行軍見暴風猛雨，倒折旗鎗，大雨不止者，天之怒也，軍不可進。", "宜待天象和明，別擇日時門戶，軍行方吉也。", "）。"]'),
('0429157b-f8a7-4f1e-93b1-c62efb53115f','兵要望江南 占雨第八（京本列第二○十七首） 八','易靜','唐','唐诗','tang','','[]','天雨物，形體不能聲。',32,'全唐诗/poet.tang.54000.json','["天雨物，形體不能聲。", "其分凶灾主兵寇，功臣遭戮國須傾，固守得平平。"]'),
('a9d07678-d45b-44e9-861e-598342a2927c','兵要望江南 占雨第八（京本列第二○十七首） 九','易靜','唐','唐诗','tang','','[]','天雨血，賢退進邪人。',32,'全唐诗/poet.tang.54000.json','["天雨血，賢退進邪人。", "血染金革皆不喜，急移營寨賞三軍，無罪受王刑。"]'),
('288b7967-d1ee-4b95-aeff-70808b9c9763','兵要望江南 占雨第八（京本列第二○十七首） 十','易靜','唐','唐诗','tang','','[]','天雨鳥，爪翅及諸般。',32,'全唐诗/poet.tang.54000.json','["天雨鳥，爪翅及諸般。", "若在彼軍他主敗，我軍逢此不能安，必見損兵官。"]'),
('39012c83-a706-4160-8bdd-d673a9ec8bcb','兵要望江南 占雨第八（京本列第二○十七首） 十一','易靜','唐','唐诗','tang','','[]','天雨蛩，在敵不能（辛本作「宜」）攻。',53,'全唐诗/poet.tang.54000.json','["天雨蛩，在敵不能（辛本作「宜」）攻。", "或鱉或魚皆凶（首本作「吉」，今從辛本）兆，我軍見者便回程，不動必遭凶。"]'),
('5891aaab-1641-447a-9dcd-35b1a0a93264','兵要望江南 占雨第八（京本列第二○十七首） 十二','易靜','唐','唐诗','tang','','[]','天雨毛，主將信邪奸。',32,'全唐诗/poet.tang.54000.json','["天雨毛，主將信邪奸。", "急宜謹亷須固守，莫將輕慢事非凡，天意報君顏。"]'),
('472645c0-9f19-4265-bae3-20926fe9f567','兵要望江南 占雨第八（京本列第二○十七首） 十三','易靜','唐','唐诗','tang','','[]','無雲霧，一色見天晴。',32,'全唐诗/poet.tang.54000.json','["無雲霧，一色見天晴。", "此象無雲而雨降，謂之天泣事難禁，主帥未安心。"]'),
('62017bd4-e5d3-451a-a49e-95ff91f4a112','兵要望江南 占雨第八（京本列第二○十七首） 十四','易靜','唐','唐诗','tang','','[]','黑雲現，橫截在天河。',32,'全唐诗/poet.tang.54000.json','["黑雲現，橫截在天河。", "見此天河新作換，來朝有雨報君家，此語不曾差。"]'),
('33385ca1-a3be-4a4b-8b78-a2c05497fed6','兵要望江南 占雨第八（京本列第二○十七首） 十五','易靜','唐','唐诗','tang','','[]','天河內，閃電見光明。',32,'全唐诗/poet.tang.54000.json','["天河內，閃電見光明。", "隨即來朝遭大雨，自然霶霈若盆傾，平地水汪盈。"]'),
('9704a4de-1346-405a-9bf9-7ec56af65838','兵要望江南 占雨第八（京本列第二○十七首） 十六','易靜','唐','唐诗','tang','','[]','月生暈，月暈暈參星。',32,'全唐诗/poet.tang.54000.json','["月生暈，月暈暈參星。", "或暈井宿遭雨降，五朝七日不差分，空裏似盆傾。"]'),
('37fae4a7-339a-4f58-8591-04c7e3f24f32','兵要望江南 占雨第八（京本列第二○十七首） 十七','易靜','唐','唐诗','tang','','[]','密雲現，雨陣黑濃濃。',48,'全唐诗/poet.tang.54000.json','["密雲現，雨陣黑濃濃。", "驀地攔前轟霹靂，天雷驚震擁（首本作「攤」，茲從辛本、川本）來攻，有雨不多分。"]'),
('672487db-43fe-4754-b059-64c58d59cd1a','兵要望江南 占雷第九（京本列第二十五○三十一首）','易靜','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.54000.json','["。"]'),
('9454b108-a48f-4343-99f2-e1604abb56eb','兵要望江南 占雷第九（京本列第二十五○三十一首） 一','易靜','唐','唐诗','tang','','[]','老陽極，出地變成雷。',32,'全唐诗/poet.tang.54000.json','["老陽極，出地變成雷。", "出聲之先收聲後，此爲灾怪號非時，兵起主荒饑。"]'),
('bb3c5b7b-98dc-4510-925c-7df888bc16c6','兵要望江南 占雷第九（京本列第二十五○三十一首） 二','易靜','唐','唐诗','tang','','[]','占雷法，大怕出非時。',45,'全唐诗/poet.tang.54000.json','["占雷法，大怕出非時。", "皆是守官無政法，酷民枉法有天知，天怒震權威（辛本、川本作「震威摧」）。"]'),
('20ee4136-2255-4f11-ac5d-a19b4fa7a4b6','兵要望江南 占雷第九（京本列第二十五○三十一首） 三','易靜','唐','唐诗','tang','','[]','兵發日，風吼忽雷鳴。',32,'全唐诗/poet.tang.54000.json','["兵發日，風吼忽雷鳴。", "戰馬盡驚旗倒折，前程必有賊來迎，大戰血交幷。"]'),
('afcc1b89-f13e-4ea0-aa4d-9caa19cc2b55','兵要望江南 占雷第九（京本列第二十五○三十一首） 四','易靜','唐','唐诗','tang','','[]','兵發日，雲氣與雷聲。',32,'全唐诗/poet.tang.54000.json','["兵發日，雲氣與雷聲。", "雲趁我軍雷逐後，天威神助大軍行，此去必須贏。"]'),
('ed56bfb9-5dca-41ac-8c3d-c19735566093','兵要望江南 占雷第九（京本列第二十五○三十一首） 五','易靜','唐','唐诗','tang','','[]','兵發日，雷動我軍營。',32,'全唐诗/poet.tang.54000.json','["兵發日，雷動我軍營。", "天助威靈軍得勝，若居彼上我勞軍，審細聽其聲。"]'),
('c61bc2b8-a0f8-4ead-aae7-2dbaeede3aae','兵要望江南 占雷第九（京本列第二十五○三十一首） 六','易靜','唐','唐诗','tang','','[]','冬三月，何事忽雷鳴？只利客居（川本作「軍」）非利主（辛本、川本作「土」），高旗先舉定須贏，後戰必無成。',51,'全唐诗/poet.tang.54000.json','["冬三月，何事忽雷鳴？只利客居（川本作「軍」）非利主（辛本、川本作「土」），高旗先舉定須贏，後戰必無成。"]'),
('13021139-d964-4084-9976-56152184b30f','兵要望江南 占雷第九（京本列第二十五○三十一首） 七','易靜','唐','唐诗','tang','','[]','雷霹靂，樹木及諸般。',32,'全唐诗/poet.tang.54000.json','["雷霹靂，樹木及諸般。", "若在彼軍營寨上，天威殺氣我難當，移寨始爲安。"]'),
('092363d0-4667-4d22-93df-9c83b782fabe','兵要望江南 占雷第九（京本列第二十五○三十一首） 八','易靜','唐','唐诗','tang','','[]','營寨上，雷止一聲鳴。',32,'全唐诗/poet.tang.54000.json','["營寨上，雷止一聲鳴。", "定是命來應迅速，不然急詔事叮嚀，上將好詳聽。"]'),
('b66972eb-d920-4390-bccd-fecfb7f378cc','兵要望江南 占雷第九（京本列第二十五○三十一首） 九','易靜','唐','唐诗','tang','','[]','營郡邑，天上忽雷鳴（辛本、川本作「聲」）。',76,'全唐诗/poet.tang.54000.json','["營郡邑，天上忽雷鳴（辛本、川本作「聲」）。", "欲似雷鳴還不是（辛本、川本作「似」），多應土地注長（二字據辛本、川本補）傾，否則（辛本、川本作「即」）戰將爭。"]'),
('2cc1914e-b6f6-4c06-859f-893f8aee1387','兵要望江南 占雷第九（京本列第二十五○三十一首） 十','易靜','唐','唐诗','tang','','[]','兵發日，風送逆雷聲。',102,'全唐诗/poet.tang.54000.json','["兵發日，風送逆雷聲。", "天意欲將（京本作「顯然」）兵仔細，不宜先舉恐傷危，遇敵恐（京本作「必」）遭摧。", "（京本注：夫雷霆者，天地之成，震則以驚萬物，兵者尤宜祭之。", "凡雷霆於將軍士卒，宜擐甲張弦，其兵得天助也。", "）。"]'),
('60971608-4da6-4526-84d9-5233a77566ee','兵要望江南 占雷第九（京本列第二十五○三十一首） 十一','易靜','唐','唐诗','tang','','[]','無雲氣，天色十分晴。',58,'全唐诗/poet.tang.54000.json','["無雲氣，天色十分晴。", "驀地一聲如雷響，或如霹靂野鷄驚，龍出沒灾刑。", "（經曰：「謂之天鼓，亦主兵火。", "」又曰：「龍出。", "」）。"]'),
('3684cd13-485e-4a31-a1f4-1e1a0f8a7032','兵要望江南 占雷第九（京本列第二十五○三十一首） 十二','易靜','唐','唐诗','tang','','[]','將軍衆，驀地一聲雷。',32,'全唐诗/poet.tang.54000.json','["將軍衆，驀地一聲雷。", "次後幷無雷附矣，將軍兵衆必行之，舉處可先爲。"]'),
('17473fe1-6806-4229-a954-74a30fffdb40','兵要望江南 占雷第九（京本列第二十五○三十一首） 十三','易靜','唐','唐诗','tang','','[]','春三月，甲子共庚寅。',33,'全唐诗/poet.tang.54000.json','["春三月，甲子共庚寅。", "乙丑戊子幷辛卯，雷鳴霹靂恐傷人，大戰月旬驚。", "。"]'),
('20020aaa-af8d-4fdf-8ff1-ca18d1fe940a','兵要望江南 占雷第九（京本列第二十五○三十一首） 十四','易靜','唐','唐诗','tang','','[]','將戰次，臨陣有雷聲。',32,'全唐诗/poet.tang.54000.json','["將戰次，臨陣有雷聲。", "從我軍中謀至敵，敵軍必敗我軍贏，反此一同情。"]'),
('09002079-f47c-4c52-a61f-ce597c60f2c2','兵要望江南 占雷第九（京本列第二十五○三十一首） 十五','易靜','唐','唐诗','tang','','[]','天陰久，不雨數朝期。',44,'全唐诗/poet.tang.54000.json','["天陰久，不雨數朝期。", "忽有雷鳴我軍上，前程得捷便占（辛本、川本作「占便」）宜，反此我軍危。"]'),
('eb48857c-9585-4bd5-bf1c-ddc4a270c9b3','兵要望江南 占雷第九（京本列第二十五○三十一首） 十六','易靜','唐','唐诗','tang','','[]','雷四起，南北與東西。',32,'全唐诗/poet.tang.54000.json','["雷四起，南北與東西。", "其勢往還鳴不定，合當迴避不須遲，大戰兩傷之。"]'),
('8bc871ca-2d2c-4c81-87a0-56ea400bee32','兵要望江南 占雷第九（京本列第二十五○三十一首） 十七','易靜','唐','唐诗','tang','','[]','聲渾渾，其勢又圓長。',32,'全唐诗/poet.tang.54000.json','["聲渾渾，其勢又圓長。", "起處來方我軍上，若還征戰定無妨，又助我軍強。"]'),
('746bf485-19b8-4db8-b545-7a3f076daf14','兵要望江南 占雷第九（京本列第二十五○三十一首） 十八','易靜','唐','唐诗','tang','','[]','霹靂震，牙（首本作「手」，茲從辛本、川本）帳震聲雄。',48,'全唐诗/poet.tang.54000.json','["霹靂震，牙（首本作「手」，茲從辛本、川本）帳震聲雄。", "忽速搜尋休要住，須知營寨有奸凶，尋覓莫從容。"]'),
('e67038af-eeb4-4917-8a89-8f90de449ed4','兵要望江南 占雷第九（京本列第二十五○三十一首） 十九','易靜','唐','唐诗','tang','','[]','密雲見，踴躍若傾河。',82,'全唐诗/poet.tang.54000.json','["密雲見，踴躍若傾河。", "或（辛本作「忽」）有雷聲先大作，其時有雨也無多，說處莫（川本作「沒」）偏頗（辛本作「說出遍遍無。", "」）（按：首本此處缺一頁，以下五首據辛本補。", "）。"]'),
('09d0ba03-dfc3-429d-b1ad-3735d3591fa3','兵要望江南 占雷第九（京本列第二十五○三十一首） 二十','易靜','唐','唐诗','tang','','[]','雷忽震，震處衆人驚。',32,'全唐诗/poet.tang.54000.json','["雷忽震，震處衆人驚。", "若雷又非聲振怒，我軍之上必摧傾，移寨免憂驚。"]'),
('b860c987-5ed6-4773-8303-c63db5c830d9','兵要望江南 占雷第九（京本列第二十五○三十一首） 二十一','易靜','唐','唐诗','tang','','[]','雷聲震，連日不收聲。',32,'全唐诗/poet.tang.54000.json','["雷聲震，連日不收聲。", "此象正爲多失信，爲他官吏不能清，天令與人聞。"]'),
('a11b05ff-90c9-45af-8b4a-7d9d3112e54b','兵要望江南 占雷第九（京本列第二十五○三十一首） 二十二','易靜','唐','唐诗','tang','','[]','雷震雹，隨即雪空飛。',32,'全唐诗/poet.tang.54000.json','["雷震雹，隨即雪空飛。", "陰氣勝陽因此得，賊臣將起事須疑，主吏損心知。"]'),
('10076299-e598-4a37-b58d-5441fd1b527f','兵要望江南 占雷第九（京本列第二十五○三十一首） 二十三','易靜','唐','唐诗','tang','','[]','兵發日，雷發我軍中。',32,'全唐诗/poet.tang.54000.json','["兵發日，雷發我軍中。", "天助神威兵大勝，若居彼上我軍凶，詳細辨雷轟。"]'),
('8aced8bf-c825-4a65-bfec-0c1eae6defb1','兵要望江南 占雷第九（京本列第二十五○三十一首） 二十四','易靜','唐','唐诗','tang','','[]','兵發日，霞氣與雷聲。',32,'全唐诗/poet.tang.54000.json','["兵發日，霞氣與雷聲。", "霞隨我軍雷隨彼，威感應之我軍停，此去必成功。"]'),
('148bb9e8-09be-4c53-9407-df874f451bd3','兵要望江南 占雷第九（京本列第二十五○三十一首） 二十五','易靜','唐','唐诗','tang','','[]','兵發日，須要識鳴方。',44,'全唐诗/poet.tang.54000.json','["兵發日，須要識鳴方。", "雷自我軍營上起，主軍大勝客軍傷，天意助吾祥。", "（以下七首從京本補。", "）。"]'),
('dcb654e2-0d12-47c6-93d2-9d8aebe37bf5','兵要望江南 占雷第九（京本列第二十五○三十一首） 二十六','易靜','唐','唐诗','tang','','[]','兵發日，雷向敵軍鳴。',32,'全唐诗/poet.tang.54000.json','["兵發日，雷向敵軍鳴。", "彼勝我輸宜罷戰，不然城寨定遭迍，預計不宜征。"]'),
('2380383c-be53-4103-bf07-a8c2aee0b3fc','兵要望江南 占雷第九（京本列第二十五○三十一首） 二十七','易靜','唐','唐诗','tang','','[]','軍營內，無雨及無雲。',33,'全唐诗/poet.tang.54000.json','["軍營內，無雨及無雲。", "營上忽然雷霹靂，主軍大敗急移營，不爾禍來侵。", "。"]'),
('15748310-175b-44f7-b60c-e02e049356cf','兵要望江南 占雷第九（京本列第二十五○三十一首） 二十八','易靜','唐','唐诗','tang','','[]','占雷兆，初發那方鳴。',32,'全唐诗/poet.tang.54000.json','["占雷兆，初發那方鳴。", "乾上主興多士卒，坎方大水阻行兵，艮位病臨營。"]'),
('dbb990e9-e9dc-4be7-bdcb-859b1a804c50','兵要望江南 占雷第九（京本列第二十五○三十一首） 二十九','易靜','唐','唐诗','tang','','[]','占雷兆，初若震方鳴。',32,'全唐诗/poet.tang.54000.json','["占雷兆，初若震方鳴。", "決主其年穀高貴，預收糧餉賑軍民，巽上旱灾臨。"]'),
('1034da59-1e7d-4f5c-a326-79e87804e303','兵要望江南 占雷第九（京本列第二十五○三十一首） 三十','易靜','唐','唐诗','tang','','[]','占雷兆，初動在離方。',32,'全唐诗/poet.tang.54000.json','["占雷兆，初動在離方。", "恐有火灾兼旱孽，坤宮損稼總宜禳，兌位起兵忙。"]'),
('bc3c276e-3d44-4872-b012-a25c626c4705','兵要望江南 占雷第九（京本列第二十五○三十一首） 三十一','易靜','唐','唐诗','tang','','[]','商音姓，鳴忌在離方。',138,'全唐诗/poet.tang.54000.json','["商音姓，鳴忌在離方。", "角姓兌乾宮震巽，羽防坤艮及中央，徴姓坎方殃。", "（天子出取天子姓，不出只以主將姓幷日干爲主，以八方生尅斷。", "訣云：甲乙兌乾方，丙丁坎上當。", "戊己防震巽，庚辛離有殃。", "壬癸艮坤位，中央總不祥。", "我尅他軍敗，他尅我軍傷。", "生他雖用計，生我自投降。", "上天昭應驗，良將細推詳。", "）。"]'),
('eea67d90-f8a8-438b-8625-b436e40c5547','兵要望江南 占天第十（十一首） 一','易靜','唐','唐诗','tang','','[]','天之道，爲父又爲君。',32,'全唐诗/poet.tang.54000.json','["天之道，爲父又爲君。", "清靜麗明爲順吉，昏暗陰散缺忠臣，諂佞近王庭。"]'),
('9481a25e-9b23-459e-86c0-b8bc926a7edd','兵要望江南 占天第十（十一首） 二','易靜','唐','唐诗','tang','','[]','天氣赤，蔭地一般紅。',100,'全唐诗/poet.tang.54000.json','["天氣赤，蔭地一般紅。", "人物盡來如屠血，來兵必戰有災凶，兵敗莫西東。", "（宋咸淳甲戌七月初六日庚辰酉時，在天有一丈餘高霞，映地如血，當年十二月過江，至丙子納降，江淮軍民遭塗炭。", "）（按：此條原注爲後人附加。", "）。"]'),
('2fc22068-9b54-4aeb-af87-080c1bb63dd0','兵要望江南 占天第十（十一首） 三','易靜','唐','唐诗','tang','','[]','天之道，哀響又兼鳴。',32,'全唐诗/poet.tang.54000.json','["天之道，哀響又兼鳴。", "此處必主興王道，異謀革位少良臣，年內見其因。"]'),
('19507ce9-e37a-4299-86ac-ccb53c4e7a33','兵要望江南 占天第十（十一首） 四','易靜','唐','唐诗','tang','','[]','天之道，其象號乾方。',32,'全唐诗/poet.tang.54000.json','["天之道，其象號乾方。", "或若分爲於兩半，分常別土亂征傷，人主見憂惶。"]'),
('d72280d2-5540-4738-b3f5-c188c1dd7d90','兵要望江南 占天第十（十一首） 五','易靜','唐','唐诗','tang','','[]','天之道，忽裂見樓臺。',51,'全唐诗/poet.tang.54000.json','["天之道，忽裂見樓臺。", "皆主兵荒人世亂，千般祥瑞忽爲災，其怪報人來。", "（以上五首首本缺，據辛本、川本補。", "）。"]'),
('bc42cd3a-534e-46b7-a75b-628a57a20a8c','兵要望江南 占天第十（十一首） 六','易靜','唐','唐诗','tang','','[]','天河分，忽若似鎗（辛本、川本作「戟」）尖。',43,'全唐诗/poet.tang.54000.json','["天河分，忽若似鎗（辛本、川本作「戟」）尖。", "兵世當興逢此兆，諸川郡府見憂煎。", "塗炭遍山川。"]'),
('aaca596a-09e8-4da6-b874-418b5f240394','兵要望江南 占天第十（十一首） 七','易靜','唐','唐诗','tang','','[]','天色白，慘慘甚昏曚。',62,'全唐诗/poet.tang.54000.json','["天色白，慘慘甚昏曚。", "久陰不雨陰謀事，必爲兵火事難通（「通」字據辛本、川本補）。", "年內始知蹤（首本作「通」，茲從辛本、川本。", "）。"]'),
('705a91c4-2444-472d-b3eb-87db7d9235f6','兵要望江南 占天第十（十一首） 八','易靜','唐','唐诗','tang','','[]','天忽響，鳴鬧在蒼穹。',32,'全唐诗/poet.tang.54000.json','["天忽響，鳴鬧在蒼穹。", "多是子憂當父感，天鳴臣怒鑒君同，君主可寬刑。"]'),
('056e7255-220e-4b50-8571-c196ba29a39d','兵要望江南 占天第十（十一首） 九','易靜','唐','唐诗','tang','','[]','天道慘，慘色變深黃。',44,'全唐诗/poet.tang.54000.json','["天道慘，慘色變深黃。", "必主大風三二日，船行急止莫徜徉（辛本、川本作「滄洋」），預報與君忙。"]'),
('e425bbfd-f1c2-4ede-b421-2292e19d7543','兵要望江南 占天第十（十一首） 十','易靜','唐','唐诗','tang','','[]','天忽見，有虹赤紅黃。',40,'全唐诗/poet.tang.54000.json','["天忽見，有虹赤紅黃。", "貫北斗極星還遶，君生賢聖主（辛本作「至」）非常。", "此事甚相當。"]'),
('ef3a6dad-4d00-4024-96ab-37317ff65c7e','兵要望江南 占天第十（十一首） 十一','易靜','唐','唐诗','tang','','[]','天久旱，無雨水盆流。',39,'全唐诗/poet.tang.54000.json','["天久旱，無雨水盆流。", "此是天時雨不潤，不能下降令人憂（辛本、川本作「奔高流」）。"]'),
('2579964d-891f-41a0-bf73-b7ba79c4d084','兵要望江南 占日第十一（京本列第六○五十六首） 一','易靜','唐','唐诗','tang','','[]','太陽位，爲主正爲君。',32,'全唐诗/poet.tang.54000.json','["太陽位，爲主正爲君。", "兆主國君家國事，通行循度總和平，昏蝕主憂驚。"]'),
('fd313dc7-b2db-4bca-bced-bc1d596f8be1','兵要望江南 占日第十一（京本列第六○五十六首） 二','易靜','唐','唐诗','tang','','[]','日旁氣，赤色若（京本作「似」）懸鐘。',57,'全唐诗/poet.tang.54000.json','["日旁氣，赤色若（京本作「似」）懸鐘。", "所見之時（辛本、川本、京本作「遊所見邊」）須將死，不論春夏與秋冬，所舉總成空。"]'),
('f2e925b6-23f4-4525-ab01-a4cb723e765c','兵要望江南 占日第十一（京本列第六○五十六首） 三','易靜','唐','唐诗','tang','','[]','日生暈，上下兩重交。',51,'全唐诗/poet.tang.54000.json','["日生暈，上下兩重交。", "必有彼疆亡將過（京本作「軍亡將帥」），中謀獨霸不成韜，終是舉（京本作「起」）鎗刀。"]'),
('ef04e329-3686-489c-95b2-79b515bff7ee','兵要望江南 占日第十一（京本列第六○五十六首） 四','易靜','唐','唐诗','tang','','[]','日左（辛本、川本作「在」）右，白氣若虹交。',51,'全唐诗/poet.tang.54000.json','["日左（辛本、川本作「在」）右，白氣若虹交。", "兆（京本作「即」）主血流成大戰，緣君失政作成妖，無法可禳消。"]'),
('27a1dee4-7d6f-42da-a706-c6d62eec4a34','兵要望江南 占日第十一（京本列第六○五十六首） 五','易靜','唐','唐诗','tang','','[]','日光暈，暈珥有陰風。',66,'全唐诗/poet.tang.54000.json','["日光暈，暈珥有陰風。", "左右並同爲吉兆，三般變動日時逢（京本作「同」），日月在羅籠。", "（日邊耳，經曰：日有抱暈於野，皆有降軍降將至也。", "）。"]'),
('e49b0261-1a88-438a-9500-46f3eb713b39','兵要望江南 占日第十一（京本列第六○五十六首） 六','易靜','唐','唐诗','tang','','[]','日光暈，有暈要須知。',48,'全唐诗/poet.tang.54000.json','["日光暈，有暈要須知。", "闕處預先防（京本作「隄」）備吉，忽然不闕亦（京本作「不」）須疑，三日雨淋漓。"]'),
('91a50d96-2d1d-4c19-95c2-297c2b5fb52e','兵要望江南 占日第十一（京本列第六○五十六首） 七','易靜','唐','唐诗','tang','','[]','日中暈，上蓋下爲陰（京本作「纓」）。',40,'全唐诗/poet.tang.54000.json','["日中暈，上蓋下爲陰（京本作「纓」）。", "向暈即凶背暈吉，若無征戰有風聲，霞氣雨還成。"]'),
('fbdb1dce-f893-4b6e-814c-e96a719da426','兵要望江南 占日第十一（京本列第六○五十六首） 八','易靜','唐','唐诗','tang','','[]','暈不合，垂在兩邊生（京本作「旁」）。',48,'全唐诗/poet.tang.54000.json','["暈不合，垂在兩邊生（京本作「旁」）。", "城內有人謀不就，且饒緩慢看軍（京本作「牽」）情，一事也無成。"]'),
('0bc50941-5029-4af4-8f66-df307a1ea579','兵要望江南 占日第十一（京本列第六○五十六首） 九','易靜','唐','唐诗','tang','','[]','暈邊氣，入則外軍贏。',41,'全唐诗/poet.tang.54000.json','["暈邊氣，入則外軍贏。", "隨氣攻之應大勝，忽然內出外軍傾，勝負預先明（京本作「征」）。", "。"]'),
('68e0da6d-5134-4221-8727-364f1e269564','兵要望江南 占日第十一（京本列第六○五十六首） 十','易靜','唐','唐诗','tang','','[]','暈邊珥，一珥喜來生。',46,'全唐诗/poet.tang.54000.json','["暈邊珥，一珥喜來生。", "兩珥欲來相解意，又言敗（川本、辛本、京本作「拜」）將攝公卿，此術甚分明。"]'),
('5ee110d1-6399-4862-8b1c-0e9c13069767','兵要望江南 占日第十一（京本列第六○五十六首） 十一','易靜','唐','唐诗','tang','','[]','日月背，順吉背須凶。',32,'全唐诗/poet.tang.54000.json','["日月背，順吉背須凶。", "若背東方西面勝，背西東面獲其功，南北並皆同。"]'),
('202a9fde-6ab5-4184-9975-91ecd7403c0a','兵要望江南 占日第十一（京本列第六○五十六首） 十二','易靜','唐','唐诗','tang','','[]','占日月，主客要先知。',63,'全唐诗/poet.tang.54000.json','["占日月，主客要先知。", "晝把（京本作「犯」）太陽將作主，夜憑星月驗安危，客認（京本作「與」）氣隨時。", "（日月星爲主，雲霞氣爲客。", "）。"]'),
('88e19d51-d770-4626-84e9-d319bc49debf','兵要望江南 占日第十一（京本列第六○五十六首） 十三','易靜','唐','唐诗','tang','','[]','相鬬（京本作「聞」）敵，兩日見分明。',71,'全唐诗/poet.tang.54000.json','["相鬬（京本作「聞」）敵，兩日見分明。", "必有拔營離寨去，正當日下（京本作「夜」）看拋城，大戰血交幷（京本作「兵」。", "首本缺此首，茲據辛本、川本。", "）。"]'),
('4809e6a8-80e8-45f1-9f0c-61c58a7268b2','兵要望江南 占日第十一（京本列第六○五十六首） 十四','易靜','唐','唐诗','tang','','[]','相鬭（京本作「聞」）敵，日鬬對城營（京本作「營城」）。',91,'全唐诗/poet.tang.54000.json','["相鬭（京本作「聞」）敵，日鬬對城營（京本作「營城」）。", "交戰血流看主客，必應主敗客軍贏，日度算還生。", "（辛本、川本注：「算太陽分野。", "」京本注：「精算太陽分野，在日度算還生第十三首。", "」）。"]'),
('2bfdbcea-6a2d-4f06-abee-25940d9b3124','兵要望江南 占日第十一（京本列第六○五十六首） 十五','易靜','唐','唐诗','tang','','[]','日中暈，日被白虹穿。',52,'全唐诗/poet.tang.54000.json','["日中暈，日被白虹穿。", "天下大兵看即（京本作「帥」）起，又兼烈士報仇冤，奮怒氣沖天。", "（荆軻入秦時有此兆。", "）。"]'),
('d8708bb1-c17d-4d1e-b3e3-b0488918b609','兵要望江南 占日第十一（京本列第六○五十六首） 十六','易靜','唐','唐诗','tang','','[]','兵發日，日偶蝕幷虧。',55,'全唐诗/poet.tang.54000.json','["兵發日，日偶蝕幷虧。", "莫往前程尋大戰，天垂威（辛本、川本作「戒」）象遣（京本作「上天垂象欲」）人知，去則將難歸。"]'),
('75df246a-b4f1-42da-ad33-5e3c03572143','兵要望江南 占日第十一（京本列第六○五十六首） 十七','易靜','唐','唐诗','tang','','[]','冠纓日（京本作「者」），日上即爲冠。',48,'全唐诗/poet.tang.54000.json','["冠纓日（京本作「者」），日上即爲冠。", "右（京本作「在」）下爲纓擎捧日，冠爲喜兆將須歡，纓則將心攢。"]'),
('4822d29c-5ffd-4bd2-ba1f-a8493c054ed1','兵要望江南 占日第十一（京本列第六○五十六首） 十八','易靜','唐','唐诗','tang','','[]','兩日鬬，少時（京本作「小將」）及明朝。',76,'全唐诗/poet.tang.54000.json','["兩日鬬，少時（京本作「小將」）及明朝。", "倘或必（辛本、川本、京本作「忽」）聞如此兆，外藩草莽競（京本作「盡」）興妖，進步即嚎啕（辛本、川本作「疾兵消」）。"]'),
('f4a95824-3853-4fd2-849a-18fc89c45bba','兵要望江南 占日第十一（京本列第六○五十六首） 十九','易靜','唐','唐诗','tang','','[]','日邊氣，如杵赤而明。',32,'全唐诗/poet.tang.54000.json','["日邊氣，如杵赤而明。", "既顯不當軍將出，執迷堅往損其兵，一半不回程。"]'),
('ea676116-d757-4b4b-98c4-b3b075119cee','兵要望江南 占日第十一（京本列第六○五十六首） 二十','易靜','唐','唐诗','tang','','[]','日旁暈，狀若死蛇圍。',72,'全唐诗/poet.tang.54000.json','["日旁暈，狀若死蛇圍。", "其兆主（京本作「生」）災先舉（京本作「損」）將，師徒半出不能回，宜改（京本作「後」）擁師歸。", "（此首首本缺，據辛本、川本。", "）。"]'),
('4edf1f57-5cd7-4e2c-abd5-9ae94f6dcc68','兵要望江南 占日第十一（京本列第六○五十六首） 二十一','易靜','唐','唐诗','tang','','[]','日邊暈，抱日一邊生。',40,'全唐诗/poet.tang.54000.json','["日邊暈，抱日一邊生。", "順抱敵人須可撃，還如逆抱戰無贏，隨衆（京本作「象」）舉其兵。"]'),
('583aa2f6-9630-40d4-a998-662d3afff2c5','兵要望江南 占日第十一（京本列第六○五十六首） 二十二','易靜','唐','唐诗','tang','','[]','日下氣，赤氣列三層。',32,'全唐诗/poet.tang.54000.json','["日下氣，赤氣列三層。", "天下流亡兵競起，黎民失業禍災生，鹿走霸圖爭。"]'),
('723f0856-dced-484e-9de5-daf617b16762','兵要望江南 占日第十一（京本列第六○五十六首） 二十三','易靜','唐','唐诗','tang','','[]','日四耳，多在四隅邊。',32,'全唐诗/poet.tang.54000.json','["日四耳，多在四隅邊。", "宮闕儲君生太子，歡欣期降定三年，人馬罷征權。"]'),
('12240cab-6120-4744-a958-7d6a19ae16cf','兵要望江南 占日第十一（京本列第六○五十六首） 二十四','易靜','唐','唐诗','tang','','[]','日中氣，上下黑衝過。',40,'全唐诗/poet.tang.54000.json','["日中氣，上下黑衝過。", "長子建謀興大逆，速當根究莫蹉跎，遲便舉（京本作「起」）干戈。"]'),
('ab3e6636-9410-4d35-86d1-d7046bf56ff6','兵要望江南 占日第十一（京本列第六○五十六首） 二十五','易靜','唐','唐诗','tang','','[]','兩陣近，青氣日邊生。',32,'全唐诗/poet.tang.54000.json','["兩陣近，青氣日邊生。", "其狀分明如半月，順其形氣速前征，交戰必須贏。"]'),
('a1930509-cf2c-45c4-b08e-f9eed0ef3a78','兵要望江南 占日第十一（京本列第六○五十六首） 二十六','易靜','唐','唐诗','tang','','[]','太陽畔，八字氣分明。',32,'全唐诗/poet.tang.54000.json','["太陽畔，八字氣分明。", "下若鹿麞形勢走，將亡兵潰禍災生，固守保關營。"]'),
('df6760b8-1b99-4b13-bcea-92b184247bbf','兵要望江南 占日第十一（京本列第六○五十六首） 二十七','易靜','唐','唐诗','tang','','[]','太陽畔，雲氣傘張形。',46,'全唐诗/poet.tang.54000.json','["太陽畔，雲氣傘張形。", "又若飛烟星在（辛本、川本、京本作「影」）裏，火星傍出血成坑，堅守不宜行。"]'),
('e868be57-d002-4c9e-9294-f24c999c69b5','兵要望江南 占日第十一（京本列第六○五十六首） 二十八','易靜','唐','唐诗','tang','','["\u6cf0\u5c71"]','太陽畔，突出泰山端。',43,'全唐诗/poet.tang.54000.json','["太陽畔，突出泰山端。", "紫氣盤旋供（辛本、川本作「俱」）不散，城中軍勝賊當殘，臨陣審詳看。"]'),
('47361c66-4816-4329-82b1-d88a2f2f8e54','兵要望江南 占日第十一（京本列第六○五十六首） 二十九','易靜','唐','唐诗','tang','','[]','太陽畔，氣蓋（京本作「貫」）日當中。',58,'全唐诗/poet.tang.54000.json','["太陽畔，氣蓋（京本作「貫」）日當中。", "白色東西連卯酉，主憂社稷（京本作「宗社」）重災凶，改號任神龍。", "（龍名曰喪門。", "）。"]'),
('8c05442b-e188-492a-a6f5-cf3ccedeb201','兵要望江南 占日第十一（京本列第六○五十六首） 三十','易靜','唐','唐诗','tang','','[]','太陽畔，九曜旋（辛本、川本、京本作「簇」）於邊。',81,'全唐诗/poet.tang.54000.json','["太陽畔，九曜旋（辛本、川本、京本作「簇」）於邊。", "似火如燈光爛爛（京本作「燁燁」），九州大亂水滔天（京本作「血流川」），王道苦（京本作「若」）憂煎。", "（又主兵戈。", "）。"]'),
('a0a163f2-4e96-4a11-981d-9e9a28fa95c1','兵要望江南 占日第十一（京本列第六○五十六首） 三十一','易靜','唐','唐诗','tang','','[]','太陽畔，牛鬬競爭時。',59,'全唐诗/poet.tang.54000.json','["太陽畔，牛鬬競爭時。", "更有傍邊持戟立，戟人無首影依稀，宗廟必傾危。", "（首本此首兩收，前二句一作「太陽鬬，競與日爭時」。", "）。"]'),
('2e4b43f8-dbab-4ccf-a9e8-75ac39acdd15','兵要望江南 占日第十一（京本列第六○五十六首） 三十二','易靜','唐','唐诗','tang','','[]','太陽畔，如幕（京本作「蔓」）又如花。',49,'全唐诗/poet.tang.54000.json','["太陽畔，如幕（京本作「蔓」）又如花。", "相繼相連不間（京本作「黏不」）斷，嬪妃皇后亂其家，術士見生涯。"]'),
('89c4529f-6061-4fe2-b35b-6a625f127680','兵要望江南 占日第十一（京本列第六○五十六首） 三十三','易靜','唐','唐诗','tang','','[]','太陽畔，氣如剪刀形。',57,'全唐诗/poet.tang.54000.json','["太陽畔，氣如剪刀形。", "更有散花桃杏（京本作「李」）雜，君王失政后妃稱（京本作「嗔」），鮮潔（京本作「解結」）愈爲精。"]'),
('6dc7e5a1-066e-4354-9b87-7a06aff50f2c','兵要望江南 占日第十一（京本列第六○五十六首） 三十四','易靜','唐','唐诗','tang','','[]','太陽畔，氣若璧形圓。',86,'全唐诗/poet.tang.54000.json','["太陽畔，氣若璧形圓。", "其影團圓（京本作「團」）如暈色，羣（京本作「郡」）邦臣下反（京本作「反主」）謀專，奪我境邊田。", "（主小臣謀反分國。", "京本注：「主小臣謀叛分國侵奪之事。", "」）。"]'),
('d2ea4b58-0946-4eca-89ee-e5e292f5d0c7','兵要望江南 占日第十一（京本列第六○五十六首） 三十五','易靜','唐','唐诗','tang','','[]','太陽畔，一樹蒂根成。',41,'全唐诗/poet.tang.54000.json','["太陽畔，一樹蒂根成。", "兩（京本作「雨」）氣橫生成長拽出，殺君自縊叛臣情，隨帝應其徴。"]'),
('d750c4c2-dd91-49bc-9570-82803629edb3','兵要望江南 占日第十一（京本列第六○五十六首） 三十六','易靜','唐','唐诗','tang','','[]','太陽畔（京本一作「時」），如鼠樹枝（京本一作「林」）間。',103,'全唐诗/poet.tang.54000.json','["太陽畔（京本一作「時」），如鼠樹枝（京本一作「林」）間。", "又似雞形雙（京本一作「頭」）翅舉（京本作「頤頸勢」），看（京本作「舉」）看洪水作爲（京本作「危」）難，移寨向（京本作「上」）高山。", "（京本此首兩見。", "）。"]'),
('81d2ccca-03a2-4011-a9b6-d61e8d23e7e4','兵要望江南 占日第十一（京本列第六○五十六首） 三十七','易靜','唐','唐诗','tang','','[]','太陽畔，帆幔氣堪疑。',66,'全唐诗/poet.tang.54000.json','["太陽畔，帆幔氣堪疑。", "又若破船來向（京本作「泊」）岸，仍居乾位帝京基（辛本、川本作「隳」、京本作「墮」），帆落勢傾時（京本作「危」）。"]'),
('55f140dd-6b2b-4d57-9fbd-e0f637287091','兵要望江南 占日第十一（京本列第六○五十六首） 三十八','易靜','唐','唐诗','tang','','[]','太陽畔，五色氣鮮（京本作「祥」）明。',48,'全唐诗/poet.tang.54000.json','["太陽畔，五色氣鮮（京本作「祥」）明。", "下有奔麞形象具，忠臣遭戮又妖興（京本作「兵」），不可不留情。"]'),
('c0327eee-0983-4409-8845-d4ef8cee9b39','兵要望江南 占日第十一（京本列第六○五十六首） 三十九','易靜','唐','唐诗','tang','','[]','太陽畔，十字在中張，大禍欲來先露兆，奸凶懷恨（京本作「詐」）作妖祥，齋醮早消禳。',40,'全唐诗/poet.tang.54000.json','["太陽畔，十字在中張，大禍欲來先露兆，奸凶懷恨（京本作「詐」）作妖祥，齋醮早消禳。"]'),
('b6bb088a-64db-4c7f-97dd-043c337c5816','兵要望江南 占日第十一（京本列第六○五十六首） 四十','易靜','唐','唐诗','tang','','[]','太陽畔，氣色似人兵。',32,'全唐诗/poet.tang.54000.json','["太陽畔，氣色似人兵。", "若在離邊移寨上，君王易代表臨坰，賢者得其情。"]'),
('3b685c43-98d2-4a76-8182-83010f457eb0','兵要望江南 占日第十一（京本列第六○五十六首） 四十一','易靜','唐','唐诗','tang','','[]','太陽畔，兩手在其傍。',72,'全唐诗/poet.tang.54000.json','["太陽畔，兩手在其傍。", "更有金星圓出現，后妃作孽亂生狂，乾地（京本作「帝」）應其殃。", "（乾符六年二月十八日午時現。", "京本「乾符」前有「唐禧宗」三字。", "）。"]'),
('5d05faab-c9ed-494d-858e-8fcccbc2e307','兵要望江南 占日第十一（京本列第六○五十六首） 四十二','易靜','唐','唐诗','tang','','[]','太陽畔，舉手若兩（京本作「首若雙」）分。',68,'全唐诗/poet.tang.54000.json','["太陽畔，舉手若兩（京本作「首若雙」）分。", "或作箒形居兩手，君王帝位欲分更，不散決然成。", "（辛本、川本、京本注：「氣現久不散，其殃必應。", "」）。"]'),
('e1516d1d-bec5-4b2c-816f-814cf1bb6678','兵要望江南 占日第十一（京本列第六○五十六首） 四十三','易靜','唐','唐诗','tang','','[]','太陽畔，青氣散如飛。',32,'全唐诗/poet.tang.54000.json','["太陽畔，青氣散如飛。", "變作雁行分勢列，外邦小國賊臣欺，謀反禍相隨。"]'),
('86db0564-1cc1-4efb-b041-886c94c8c15d','兵要望江南 占日第十一（京本列第六○五十六首） 四十四','易靜','唐','唐诗','tang','','[]','太陽畔，若對斗牛間。',49,'全唐诗/poet.tang.54000.json','["太陽畔，若對斗牛間。", "更有一虹迎面見，三公流國戰無還，遷改莫辭難。", "（京本注：「國主政權應自失。", "」）。"]'),
('628fe1cb-2503-4038-b269-1a06e74de787','兵要望江南 占日第十一（京本列第六○五十六首） 四十五','易靜','唐','唐诗','tang','','[]','日邊氣，皆應在蚩尤。',41,'全唐诗/poet.tang.54000.json','["日邊氣，皆應在蚩尤。", "申酉且須看獬豸，喪門申未午時求，見處便堪愁（京本作「憂」）。", "。"]'),
('b04aa730-35af-4038-9621-8c86e8c37d14','兵要望江南 占日第十一（京本列第六○五十六首） 四十六','易靜','唐','唐诗','tang','','[]','日之外，有耳兩邊生。',61,'全唐诗/poet.tang.54000.json','["日之外，有耳兩邊生。", "必有和通同好事（辛本、川本作「善」，京本作「同通好喜」），兩軍不戰結歡欣（京本作「情」），四海得安寧。"]'),
('1925c70f-46ce-47fc-bbda-13ddd3f80625','兵要望江南 占日第十一（京本列第六○五十六首） 四十七','易靜','唐','唐诗','tang','','[]','青天象，日月氣來衝。',60,'全唐诗/poet.tang.54000.json','["青天象，日月氣來衝。", "北面氣衝北面旺，南衝南旺任（川本、辛本、京本作「認」）西東，取此以爲宗（川本、辛本、京本作「蹤」）。"]'),
('849b07e0-2078-44c2-a188-d0cf375d6a4f','兵要望江南 占日第十一（京本列第六○五十六首） 四十八','易靜','唐','唐诗','tang','','[]','日色異，黃赤病之源。',40,'全唐诗/poet.tang.54000.json','["日色異，黃赤病之源。", "色若白時多死兆，更兼兵起禍凶年（京本作「連」），疾疫湊來纏。"]'),
('edce20af-b8c7-4dad-990b-58e32f7bb113','兵要望江南 占日第十一（京本列第六○五十六首） 四十九','易靜','唐','唐诗','tang','','[]','日五色，或有氣稜層（京本作「稜」）。',40,'全唐诗/poet.tang.54000.json','["日五色，或有氣稜層（京本作「稜」）。", "其分國王權政失，躭迷酒色損生靈，修德滅奢矜。"]'),
('49329003-e0f3-450c-a871-da7114900836','兵要望江南 占日第十一（京本列第六○五十六首） 五十','易靜','唐','唐诗','tang','','[]','日紫色，名曰疾萎蕤。',41,'全唐诗/poet.tang.54000.json','["日紫色，名曰疾萎蕤。", "其分起兵多喪敗，且宜修德厭天機，勿起（京本作「忽即」）禍當時。"]'),
('f27e3f59-a622-480d-9d89-8a4fc041852f','兵要望江南 占日第十一（京本列第六○五十六首） 五十一','易靜','唐','唐诗','tang','','[]','日有耳，兩耳戰均平。',32,'全唐诗/poet.tang.54000.json','["日有耳，兩耳戰均平。", "厚處必贏軍占取，一邊有耳一邊贏，無戰喜交兵。"]'),
('c323cc15-90b8-4e00-bbd4-db87fe2faeff','兵要望江南 占日第十一（京本列第六○五十六首） 五十二','易靜','唐','唐诗','tang','','[]','日色青，其分國堪傷。',32,'全唐诗/poet.tang.54000.json','["日色青，其分國堪傷。", "或似火光兼火影，皆爲災亂殄忠良，防備賊臨疆。"]'),
('50592118-2c2f-4b1d-9ca5-c7c12643625e','兵要望江南 占日第十一（京本列第六○五十六首） 五十三','易靜','唐','唐诗','tang','','[]','日生暈，須有暈形圓。',59,'全唐诗/poet.tang.54000.json','["日生暈，須有暈形圓。", "其形如暈圓其圓（辛本、川本作「圓圓背」），皆主邦臣（辛本、川本作「那邦臣子」）叛謀專，奪取境邊田。"]'),
('f1890023-b479-44d0-af6f-9b64e9b2caf3','兵要望江南 占日第十一（京本列第六○五十六首） 五十四','易靜','唐','唐诗','tang','','[]','日四耳，頂上即爲冠。',64,'全唐诗/poet.tang.54000.json','["日四耳，頂上即爲冠。", "兩下爲纓須盡日，下爲履象不爲權，回報日須端。", "（經曰：「日上爲冠，下爲履，兩下爲耳，長而爲纓，朝抱日吉。", "」）。"]'),
('ac81882f-ff87-41b7-a50b-ffa6341bce97','兵要望江南 占日第十一（京本列第六○五十六首） 五十五','易靜','唐','唐诗','tang','','[]','太陽位，下復見形圓。',32,'全唐诗/poet.tang.54000.json','["太陽位，下復見形圓。", "便若白來其色黑，王更國變別憂權，一日見憂煎。"]'),
('9a7453c9-d52a-492c-a598-e5e1f023e418','兵要望江南 占日第十一（京本列第六○五十六首） 五十六','易靜','唐','唐诗','tang','','[]','日出現，便若似（川本作「是」）臙脂。',65,'全唐诗/poet.tang.54000.json','["日出現，便若似（川本作「是」）臙脂。", "蔭（辛本作「映」）地滿天血如染，此爲天（川本作「大」）殺苦軍權，七日雨平川。", "（無雨主火災。", "）。"]'),
('b1186db7-fc71-4745-9507-9f573a4b67c5','兵要望江南 占月第十二（京本列第七○二十三首） 一','易靜','唐','唐诗','tang','','[]','太陰位，爲后又爲臣。',43,'全唐诗/poet.tang.54000.json','["太陰位，爲后又爲臣。", "凡有象形凶吉定，行兵主帥要知明，一一細分清（辛本、川本作「情」）。"]'),
('846f9d10-5e6e-4d85-b15e-ae4a907735a6','兵要望江南 占月第十二（京本列第七○二十三首） 二','易靜','唐','唐诗','tang','','[]','占圓月，下小彼軍多。',64,'全唐诗/poet.tang.54000.json','["占圓月，下小彼軍多。", "若總（京本作「見」）大時占我衆（京本作「勝」），全（京本作「總」）無大小亦相和，青白定（京本作「早」）回戈。"]'),
('91b021a2-0896-45f1-842d-8b117d0d2c1f','兵要望江南 占月第十二（京本列第七○二十三首） 三','易靜','唐','唐诗','tang','','[]','出軍夜，看月好參詳。',54,'全唐诗/poet.tang.54000.json','["出軍夜，看月好參詳。", "有兔主人占大勝，兔無反（京本作「無兔還」）是客軍強，仔細審形相（京本作「須要細端詳」）。"]'),
('71f7f368-daa0-4eb6-8282-3305e9ea7c9a','兵要望江南 占月第十二（京本列第七○二十三首） 四','易靜','唐','唐诗','tang','','[]','占夜月，五色氣相當。',56,'全唐诗/poet.tang.54000.json','["占夜月，五色氣相當。", "此是（京本作「時」）交兵須謹（京本作「警」）慎，直須拚（京本作「挨」）得賞兒郎，慳吝必相傷。"]'),
('d37a1b7d-9e5e-4f27-9572-da345834353b','兵要望江南 占月第十二（京本列第七○二十三首） 五','易靜','唐','唐诗','tang','','[]','太陰內，有暈使人驚。',50,'全唐诗/poet.tang.54000.json','["太陰內，有暈使人驚。", "其象分明如刀字（京本作「刃」），奸臣謀反事將成，密究速加刑（京本作「庶無凶」）。"]'),
('388c03a4-2f45-4d69-b4ca-c1de24284cf5','兵要望江南 占月第十二（京本列第七○二十三首） 六','易靜','唐','唐诗','tang','','[]','守彼壘，吾督將須攻。',40,'全唐诗/poet.tang.54000.json','["守彼壘，吾督將須攻。", "月色無光灰（京本作「如」）粉樣，拔城不過一旬中，守將亦須凶。"]'),
('584228a5-3d00-4c91-90b5-9c04f8bb8261','兵要望江南 占月第十二（京本列第七○二十三首） 七','易靜','唐','唐诗','tang','','[]','看夜月，五色氣相衝。',48,'全唐诗/poet.tang.54000.json','["看夜月，五色氣相衝。", "皆（京本作「此」）是將災宜（京本作「須」）謹慎，直須重賞宴軍中，堅執禍相逢。"]'),
('5aabd0e1-e16e-4127-84f9-1fffa495c81a','兵要望江南 占月第十二（京本列第七○二十三首） 八','易靜','唐','唐诗','tang','','[]','月生暈，厚薄四方停。',46,'全唐诗/poet.tang.54000.json','["月生暈，厚薄四方停。", "此是三軍均力象，一邊有抱一（辛本、川本、京本作「抱」）邊贏，順抱若神兵。"]'),
('cca7b956-233b-4895-bc87-7ff87b2b7f91','兵要望江南 占月第十二（京本列第七○二十三首） 九','易靜','唐','唐诗','tang','','[]','月生暈，暈有珥兼生。',48,'全唐诗/poet.tang.54000.json','["月生暈，暈有珥兼生。", "將有火（京本作「大」）災難閃避，三朝有雨得安寧，無雨禍還（京本作「須」）成。"]'),
('ace2987b-8f5c-4902-a3df-ec385456e1f5','兵要望江南 占月第十二（京本列第七○二十三首） 十','易靜','唐','唐诗','tang','','[]','月生暈，暈內有流星。',32,'全唐诗/poet.tang.54000.json','["月生暈，暈內有流星。", "當有貴人奔出走。", "客星入側將當驚，國亦不安寧。"]'),
('242af7ff-2bb0-4c9c-92a5-f79e982d6c68','兵要望江南 占月第十二（京本列第七○二十三首） 十一','易靜','唐','唐诗','tang','','[]','月如赭，莫戰最爲良。',59,'全唐诗/poet.tang.54000.json','["月如赭，莫戰最爲良。", "若或不依（京本作「不依言」）須見敗，客軍得勝主軍傷，宜且守封疆。", "（京本注：「先出客，後出主。", "」）。"]'),
('29ee3d91-868c-4f44-bac1-1b61a111c3f6','兵要望江南 占月第十二（京本列第七○二十三首） 十二','易靜','唐','唐诗','tang','','[]','相鬬敵，月滿色無光。',40,'全唐诗/poet.tang.54000.json','["相鬬敵，月滿色無光。", "客勝主衰（京本作「虧」）須謹慎，忽然交戰主難當，城內欲投降。"]'),
('961decb8-29a5-4a81-a595-e8956c4c0442','兵要望江南 占月第十二（京本列第七○二十三首） 十三','易靜','唐','唐诗','tang','','[]','雙月現，現則有兵荒。',70,'全唐诗/poet.tang.54000.json','["雙月現，現則有兵荒。", "兩兩三三俱荒亂（辛本、川本、京本作「亂出」），當其現處有（辛本、川本、京本作「競」）猖狂，人馬兩（京本作「死及」）逃亡。"]'),
('c9a95070-b0b7-4a3b-8916-68d5f614e0ce','兵要望江南 占月第十二（京本列第七○二十三首） 十四','易靜','唐','唐诗','tang','','[]','兩月鬬，侯景犯梁朝。',56,'全唐诗/poet.tang.54000.json','["兩月鬬，侯景犯梁朝。", "倘或遭逢如此兆，外藩（京本作「番」）雄略（京本作「客」）有謀韜，俱廢若（京本作「永」）冰消。"]'),
('5bb1eeff-ce8e-493c-b6f9-7ea30aa51fb6','兵要望江南 占月第十二（京本列第七○二十三首） 十五','易靜','唐','唐诗','tang','','[]','兵在外，月色（辛本、川本作「蝕」、京本作「食」）八分強。',66,'全唐诗/poet.tang.54000.json','["兵在外，月色（辛本、川本作「蝕」、京本作「食」）八分強。", "軍欲還鄉須（京本作「休」）罷戰，忽然蝕盡倒城亡，將死向郊（京本作「饑」）荒。"]'),
('fbec7dbf-53ec-41f3-8827-ef8fdde96739','兵要望江南 占月第十二（京本列第七○二十三首） 十六','易靜','唐','唐诗','tang','','[]','太平夕（京本作「久」），月破作三分。',48,'全唐诗/poet.tang.54000.json','["太平夕（京本作「久」），月破作三分。", "四海荒荒興逆叛，都緣人主寵奢昏（京本作「民」），草寇輒稱尊。"]'),
('cb2bf5ad-a740-4dcc-8d18-06e6fb1e24cf','兵要望江南 占月第十二（京本列第七○二十三首） 十七','易靜','唐','唐诗','tang','','[]','月黃色，分野現明光。',40,'全唐诗/poet.tang.54000.json','["月黃色，分野現明光。", "此是將軍遷（京本作「還」）職象，彼師我衆兩無傷。", "各自守封疆。"]'),
('adecc713-ad00-4c20-bd4b-f9a0bf8d1557','兵要望江南 占月第十二（京本列第七○二十三首） 十八','易靜','唐','唐诗','tang','','[]','月邊氣，其象若羣猪。',40,'全唐诗/poet.tang.54000.json','["月邊氣，其象若羣猪。", "羽姓將軍兵大吉，宮商角徴不占拘（京本作「推」），把捉顧方隅。"]'),
('7a51eee9-858e-4e47-965a-6f1c52279208','兵要望江南 占月第十二（京本列第七○二十三首） 十九','易靜','唐','唐诗','tang','','[]','十五夜，月缺不團圓。',52,'全唐诗/poet.tang.54000.json','["十五夜，月缺不團圓。", "一面凸凹三兩處，近臣怪（辛本、川本作「懷」）怨（京本作「懷恨」）奪君權，急究反情原。"]'),
('0d194700-4a87-4344-8b4a-189745a2b844','兵要望江南 占月第十二（京本列第七○二十三首） 二十','易靜','唐','唐诗','tang','','[]','金入月，星朗月無光。',43,'全唐诗/poet.tang.54000.json','["金入月，星朗月無光。", "星蝕太陰臣造逆，月明星暗將身（辛本、川本作「星」）亡。", "星沒客軍傷。"]'),
('e2e93d77-9b8e-42a8-941e-a842f2cfbe5e','兵要望江南 占月第十二（京本列第七○二十三首） 二十一','易靜','唐','唐诗','tang','','[]','金與月，俱出在西方。',54,'全唐诗/poet.tang.54000.json','["金與月，俱出在西方。", "星北北方軍必勝，星南南面將身（辛本、川本作「星」）強，月白（辛本、川本作「向」）將兵亡。"]'),
('fe9b571a-8270-4a0c-9323-dc25311fb49a','兵要望江南 占月第十二（京本列第七○二十三首） 二十二','易靜','唐','唐诗','tang','','[]','金月暈，星暗月昏昏。',46,'全唐诗/poet.tang.54000.json','["金月暈，星暗月昏昏。", "客必敗亡須好認，木星三暈將（辛本、川本、京本作「宰」）臣奔。", "天象顯然分。"]'),
('19201806-2b56-4987-a781-4ab4c6e95950','兵要望江南 占月第十二（京本列第七○二十三首） 二十三','易靜','唐','唐诗','tang','','[]','月有暈，白虹向中穿。',43,'全唐诗/poet.tang.54000.json','["月有暈，白虹向中穿。", "天下大兵看即起，更兼壯士執仇冤，大（辛本、川本作「日」）怒氣衝天。"]'),
('dad0e9d4-85a8-4c63-8a7c-209131595324','兵要望江南 占星第十三（京本列第五○四十三首） 一','易靜','唐','唐诗','tang','','[]','兵要法（京本作「訣」），爲主認星辰。',66,'全唐诗/poet.tang.54000.json','["兵要法（京本作「訣」），爲主認星辰。", "伏逆遲留（京本作「留時」）須固守，更看金（京本作「堪全」）現便（京本作「使」）宜行，俱伏兩均平。"]'),
('a5368333-faa7-4b19-bff4-0043d4e23dc0','兵要望江南 占星第十三（京本列第五○四十三首） 二','易靜','唐','唐诗','tang','','[]','兵要訣，爲主（京本作「客」）認金星。',53,'全唐诗/poet.tang.54000.json','["兵要訣，爲主（京本作「客」）認金星。", "若也伏藏休動作，逆行逆戰亦均平，順則最宜行。", "（星退宜退，星進宜進。", "）。"]'),
('8131c769-af1f-4121-b4b9-5e46ff34f115','兵要望江南 占星第十三（京本列第五○四十三首） 三','易靜','唐','唐诗','tang','','[]','金與火，統帥識星無。',43,'全唐诗/poet.tang.54000.json','["金與火，統帥識星無。", "須算（辛本、川本作「等」）行藏知決勝，何須堅執講星孤，諸事細參圖。"]'),
('766a09c7-dfc9-471d-b0fe-c4ce36167fd2','兵要望江南 占星第十三（京本列第五○四十三首） 四','易靜','唐','唐诗','tang','','[]','土星合，相犯必爲災。',55,'全唐诗/poet.tang.54000.json','["土星合，相犯必爲災。", "分野居（京本作「老」、辛本作「若」）當須有事，本藩太守禍之胎，修德免災（京本作「殃」）來。"]'),
('65b3eb19-344e-41bc-8e11-724f51929fc4','兵要望江南 占星第十三（京本列第五○四十三首） 五','易靜','唐','唐诗','tang','','[]','三星聚，晉宋爲居（辛本、川本作「兼」、京本作「衛兼」）唐。',59,'全唐诗/poet.tang.54000.json','["三星聚，晉宋爲居（辛本、川本作「兼」、京本作「衛兼」）唐。", "此地將軍須就獄，總兵主帥作猖狂，斬首獻明（京本作「君」）王。"]'),
('fa166bba-5730-4cf7-b354-dfe796517607','兵要望江南 占星第十三（京本列第五○四十三首） 六','易靜','唐','唐诗','tang','','[]','四星聚，平地（辛本、川本、京本作「帝」）會張星。',62,'全唐诗/poet.tang.54000.json','["四星聚，平地（辛本、川本、京本作「帝」）會張星。", "王莽赤眉兵造起，後來光武掃餘（京本作「除」）兵，晉魏也曾更（京本作「經」）。"]'),
('8bbf0198-8139-48a1-99e8-cafd6247acd2','兵要望江南 占星第十三（京本列第五○四十三首） 七','易靜','唐','唐诗','tang','','[]','五星聚，漢祖得其時。',42,'全唐诗/poet.tang.54000.json','["五星聚，漢祖得其時。", "秦滅漢兵東井會，君王起事合天機，星會尾如（京本作「聚尾和」）箕。"]'),
('b2b0b4d6-2b30-453b-b76d-66595a442741','兵要望江南 占星第十三（京本列第五○四十三首） 八','易靜','唐','唐诗','tang','','[]','星落寨，爲將恐遭殃。',46,'全唐诗/poet.tang.54000.json','["星落寨，爲將恐遭殃。", "宜速移營方見吉，堅強舊所必凶傷，天降禍相（辛本、川本、京本作「難」）當。"]'),
('f78c9475-f92a-47de-976d-c5c9fdbaa6cb','兵要望江南 占星第十三（京本列第五○四十三首） 九','易靜','唐','唐诗','tang','','[]','星相打，攻守兩茫茫（京本作「忙忙」）。',55,'全唐诗/poet.tang.54000.json','["星相打，攻守兩茫茫（京本作「忙忙」）。", "遇戰血流交滿野（京本作「遇賊血流郊野滿」），攻城不下好隄防，宴犒賞兒郎。"]'),
('924ed5da-8031-4633-b1ab-ffdc06dc37d0','兵要望江南 占星第十三（京本列第五○四十三首） 十','易靜','唐','唐诗','tang','','[]','金星畔，邊有小星侵。',63,'全唐诗/poet.tang.54000.json','["金星畔，邊有小星侵。", "相去不過咫尺遠，客軍當敗將消沉，兵罷只如今。", "（凡金星爲將星，專主兵權兆。", "京本注：「金星專主兵權之事。", "」）。"]'),
('71c45c8c-73d3-43e7-ad70-f1df12b17617','兵要望江南 占星第十三（京本列第五○四十三首） 十一','易靜','唐','唐诗','tang','','[]','金星（京本作「行」）疾，急戰定應（京本作「須」）贏。',64,'全唐诗/poet.tang.54000.json','["金星（京本作「行」）疾，急戰定應（京本作「須」）贏。", "行若緩時須固守，星高攻（京本作「遠」）戰有功名，低害（京本作「則」）莫深征。"]'),
('0b78ca9e-ca3c-4036-bda3-0465f8528fd3','兵要望江南 占星第十三（京本列第五○四十三首） 十二','易靜','唐','唐诗','tang','','[]','金芒角（京本作「金星落」），隨角出軍征。',55,'全唐诗/poet.tang.54000.json','["金芒角（京本作「金星落」），隨角出軍征。", "若有焰光如掃箒，亦名天狗食妖兵，其下血成坑。", "（如螻赴水，其下必敗。", "）。"]'),
('ce43a491-58cb-4dbc-8d1d-105665ef7df2','兵要望江南 占星第十三（京本列第五○四十三首） 十三','易靜','唐','唐诗','tang','','[]','占星宿，伏現在西東。',43,'全唐诗/poet.tang.54000.json','["占星宿，伏現在西東。", "星若近南南必勝，忽然近北北宜攻，專祖此爲宗（辛本、川本作「蹤」）。"]'),
('4d561015-7f23-4259-a7e7-43e656dd5067','兵要望江南 占星第十三（京本列第五○四十三首） 十四','易靜','唐','唐诗','tang','','[]','金星出，出在卯中央。',78,'全唐诗/poet.tang.54000.json','["金星出，出在卯中央。", "東面兵強莫（京本作「休」）與戰，西出西方不可當（京本作「出西面酉酉難當」），勿與動鋒鎗（辛本、川本作「鬬刀鎗」，京本作「勿與鬬鋒芒」）。"]'),
('95111db8-d65f-459e-8bb8-01a03362fd92','兵要望江南 占星第十三（京本列第五○四十三首） 十五','易靜','唐','唐诗','tang','','[]','金西伏，木（京本作「未」）出現東方。',49,'全唐诗/poet.tang.54000.json','["金西伏，木（京本作「未」）出現東方。", "軍在西南休進戰，二星同出現東方，西若戰須亡。", "（或水或木星。", "）。"]'),
('301655e4-e93c-44a4-b275-4db4abfdb02c','兵要望江南 占星第十三（京本列第五○四十三首） 十六','易靜','唐','唐诗','tang','','[]','金東伏，木（京本作「未」）出現西方。',50,'全唐诗/poet.tang.54000.json','["金東伏，木（京本作「未」）出現西方。", "東北二方須敗走，忽然同出在西方（京本作「現在旁」），東面不能當。"]'),
('21b9d806-99f0-42b5-b0ff-bbe6fe124fa2','兵要望江南 占星第十三（京本列第五○四十三首） 十七','易靜','唐','唐诗','tang','','[]','同伏現，相去尺餘同。',49,'全唐诗/poet.tang.54000.json','["同伏現，相去尺餘同。", "交戰將兵須有應，水居月上戰應先（京本作「鬬」），月內必師還。", "（水在月上也。", "）。"]'),
('98d6d2c6-bb91-409f-a3f9-c5e840f2e6da','兵要望江南 占星第十三（京本列第五○四十三首） 十八','易靜','唐','唐诗','tang','','[]','欃星現，分野在（京本作「出」）何方。',40,'全唐诗/poet.tang.54000.json','["欃星現，分野在（京本作「出」）何方。", "若是正臨災在即，忽然頭尾也遭殃，仁德可脩禳。"]'),
('9259bcc5-03d9-42e5-b096-93af34071593','兵要望江南 占星第十三（京本列第五○四十三首） 十九','易靜','唐','唐诗','tang','','[]','星一箇，無尾赤（京本作「亦」）兼青。',40,'全唐诗/poet.tang.54000.json','["星一箇，無尾赤（京本作「亦」）兼青。", "直下落來營寨上，急須遷去別爲營，此地定無成。"]'),
('bcb02074-d9b8-47fa-ab24-50dfce2fb1d6','兵要望江南 占星第十三（京本列第五○四十三首） 二十','易靜','唐','唐诗','tang','','[]','金晝現，名號是經天。',44,'全唐诗/poet.tang.54000.json','["金晝現，名號是經天。", "其分用兵兵必罷，未曾動處却兵連，人馬滿郊田。", "（已動敗，未動易政。", "）。"]'),
('446a7137-32a0-4b65-8611-c3eb64cbf2cb','兵要望江南 占星第十三（京本列第五○四十三首） 二十一','易靜','唐','唐诗','tang','','[]','星晝隕，聲震響如雷。',32,'全唐诗/poet.tang.54000.json','["星晝隕，聲震響如雷。", "赤白或長三五丈，忽然更有小星陪，軍勢若寒灰。"]'),
('24fff1da-45d6-4878-a470-9578e7348c12','兵要望江南 占星第十三（京本列第五○四十三首） 二十二','易靜','唐','唐诗','tang','','[]','星晝隕，其地定爲災（京本作「其下地殃危」）。',60,'全唐诗/poet.tang.54000.json','["星晝隕，其地定爲災（京本作「其下地殃危」）。", "必有火焚軍寨柵，兼防將士涉沙泥（京本作「垝」），移寨（京本作「去」）莫徘徊。"]'),
('8fc5bb28-e3fc-47ea-b91d-c2349afac1b8','兵要望江南 占星第十三（京本列第五○四十三首） 二十三','易靜','唐','唐诗','tang','','[]','軍營內，斗大墜星來。',61,'全唐诗/poet.tang.54000.json','["軍營內，斗大墜星來。", "或是作聲長數丈，其間大戰將星移（京本作「身摧」），急去免災危。", "（京本注：「孔明、祖逖，皆有此兆。", "」）。"]'),
('e5b17e84-ca45-4f2a-b9fa-13a6e8acb403','兵要望江南 占星第十三（京本列第五○四十三首） 二十四','易靜','唐','唐诗','tang','','[]','軍營內，星隕落其間。',89,'全唐诗/poet.tang.54000.json','["軍營內，星隕落其間。", "拽尾或長三五尺（辛本、川本、京本作「丈」），皆爲敗陣（辛本、川本、京本作「證」）莫（京本作「欲」）相殘，急去免災（京本作「凶」）奸。", "（孔明、祖逖皆有此兆。", "）。"]'),
('3b8bc205-9493-4eeb-8416-3c43a522ffd3','兵要望江南 占星第十三（京本列第五○四十三首） 二十五','易靜','唐','唐诗','tang','','[]','軍營內，星隕作驢鳴（京本作「形」）。',61,'全唐诗/poet.tang.54000.json','["軍營內，星隕作驢鳴（京本作「形」）。", "兆是（京本作「此兆」）敗軍幷殺將，便須移寨不須（京本作「當返不當」）停，天意甚分明。", "。"]'),
('bf7aacfc-b8a3-49fc-a6cb-3da520ab2569','兵要望江南 占星第十三（京本列第五○四十三首） 二十六','易靜','唐','唐诗','tang','','[]','營寨內，星火殞其中。',40,'全唐诗/poet.tang.54000.json','["營寨內，星火殞其中。", "芒角光明兼（京本作「並」）曳尾，急須移寨避災凶，不去禍重重。"]'),
('0a50669f-557f-4d5a-aad3-08ef1302c5b9','兵要望江南 占星第十三（京本列第五○四十三首） 二十七','易靜','唐','唐诗','tang','','[]','出軍法，夜與日相殊。',40,'全唐诗/poet.tang.54000.json','["出軍法，夜與日相殊。", "彼上有光（京本作「星」）兼月朗，我軍上面暗稀疎，進戰決成輸。"]'),
('f8e7dea6-acd1-412e-8b60-44195e05778c','兵要望江南 占星第十三（京本列第五○四十三首） 二十八','易靜','唐','唐诗','tang','','[]','星晝隕，分作二三星。',42,'全唐诗/poet.tang.54000.json','["星晝隕，分作二三星。", "此是兵戈將欲動，須防敵國別來侵（京本作「必來爭」），陰賊逆謀生。"]'),
('4ce0c122-9618-430f-bdff-62bb68a25e4f','兵要望江南 占星第十三（京本列第五○四十三首） 二十九','易靜','唐','唐诗','tang','','[]','吾守壁，月內一星明。',40,'全唐诗/poet.tang.54000.json','["吾守壁，月內一星明。", "必是外奸來入壘，期于半夜害吾城，搜（京本作「招」）捉審奸情。"]'),
('5c1d548c-774b-4dea-920d-690a3ad3c09d','兵要望江南 占星第十三（京本列第五○四十三首） 三十','易靜','唐','唐诗','tang','','[]','提大衆，欲打破城牆。',40,'全唐诗/poet.tang.54000.json','["提大衆，欲打破城牆。", "月左（京本作「上」）有星占上角，城中賢將有謀方，速退莫施張。"]'),
('01a66910-926a-461e-9198-a925b02759fd','兵要望江南 占星第十三（京本列第五○四十三首） 三十一','易靜','唐','唐诗','tang','','[]','敵守壘，我力有餘攻。',32,'全唐诗/poet.tang.54000.json','["敵守壘，我力有餘攻。", "月下有星相近駐，彼城奸欲亂吾中，門戶審其蹤。"]'),
('bca0ae59-229e-4f69-bbbe-25776fb4bd95','兵要望江南 占星第十三（京本列第五○四十三首） 三十二','易靜','唐','唐诗','tang','','[]','圍彼久，月背一星隨。',40,'全唐诗/poet.tang.54000.json','["圍彼久，月背一星隨。", "壁（京本作「城」）內敵人謀走北，其城沉潰不須摧，捷報凱歌回。"]'),
('8742ec95-0651-45dc-8f8c-bb0aa5ec421c','兵要望江南 占星第十三（京本列第五○四十三首） 三十三','易靜','唐','唐诗','tang','','[]','觀敵壘，月背有（辛本、川本、京本作「見」）三星。',46,'全唐诗/poet.tang.54000.json','["觀敵壘，月背有（辛本、川本、京本作「見」）三星。", "狀若連珠敵便遁，不須攻打自安平，撫衆勿殘生。"]'),
('18b5146e-e8bf-4ae1-afe6-855543520bff','兵要望江南 占星第十三（京本列第五○四十三首） 三十四','易靜','唐','唐诗','tang','','[]','軍馬進，月畔見三星。',61,'全唐诗/poet.tang.54000.json','["軍馬進，月畔見三星。", "形似三星將月捧，攻城（京本作「圍」）不下戰無成，擇地設營停（京本作「再安營」。", "候過旬日，別看氣候。", "）。"]'),
('6bf50f0a-9757-48a7-8c73-1dd0af7690e0','兵要望江南 占星第十三（京本列第五○四十三首） 三十五','易靜','唐','唐诗','tang','','[]','攻彼（京本作「破」）壘，月下見（京本作「列」）三星。',72,'全唐诗/poet.tang.54000.json','["攻彼（京本作「破」）壘，月下見（京本作「列」）三星。", "城內詐降設（京本作「施」）巧計，急當準（京本作「整」）備出（京本作「突」）師征，莫信詐爲誠。"]'),
('54c2eca8-01ac-4b65-ae19-d1f796b800da','兵要望江南 占星第十三（京本列第五○四十三首） 三十六','易靜','唐','唐诗','tang','','[]','圍彼壘，月角露三星。',48,'全唐诗/poet.tang.54000.json','["圍彼壘，月角露三星。", "亦（京本作「形」）類三台侵抱月，其城難取枉亡（京本作「勞」）兵，別處設謀贏。"]'),
('d48c79c1-fb2b-48f7-b297-9bcfd649f9cb','兵要望江南 占星第十三（京本列第五○四十三首） 三十七','易靜','唐','唐诗','tang','','[]','彗星見，出在（京本作「自」）月旁邊。',40,'全唐诗/poet.tang.54000.json','["彗星見，出在（京本作「自」）月旁邊。", "必有弒君幷殺父，國中紛擾禍相連，更主易桑田。"]'),
('cfcd5eec-344d-4f45-8d79-4dd402aee152','兵要望江南 占星第十三（京本列第五○四十三首） 三十八','易靜','唐','唐诗','tang','','[]','金臨水（辛本、川本作「本」），三五寸金分。',43,'全唐诗/poet.tang.54000.json','["金臨水（辛本、川本作「本」），三五寸金分。", "少婦合憂生哭泣，又見鬬將見災凶，偏將喪郊中。"]'),
('01eedcf8-1414-494b-ac80-18a2630769df','兵要望江南 占星第十三（京本列第五○四十三首） 三十九','易靜','唐','唐诗','tang','','[]','星墜地，鳴下似雷聲。',55,'全唐诗/poet.tang.54000.json','["星墜地，鳴下似雷聲。", "著把（辛本、川本作「地」）更（辛本、川本作「便」）如焚薪狀，此爲天狗食人民。", "百日見災生。", "。"]'),
('4d818b5b-535d-4de9-a08d-75c389513e88','兵要望江南 占星第十三（京本列第五○四十三首） 四十','易靜','唐','唐诗','tang','','[]','慧星現，但看出何方。',43,'全唐诗/poet.tang.54000.json','["慧星現，但看出何方。", "定主國君喪性命，不過百日見驚亡，減（辛本、川本作「咸」）滅在君王。"]'),
('79894ba3-8429-45da-bb8a-002754e1d1e2','兵要望江南 占星第十三（京本列第五○四十三首） 四十一','易靜','唐','唐诗','tang','','[]','太白犯，昴畢二星纏。',32,'全唐诗/poet.tang.54000.json','["太白犯，昴畢二星纏。", "定主逆臣謀國主，馬奔人走喪中原，入昴赦人原。"]'),
('1d19e3c7-88ae-4649-8a78-9abee1744dd4','兵要望江南 占星第十三（京本列第五○四十三首） 四十二','易靜','唐','唐诗','tang','','[]','金與水，二曜若侵凌。',48,'全唐诗/poet.tang.54000.json','["金與水，二曜若侵凌。", "定主破軍幷殺將，水居（首本作「君」，茲從辛本、川本）金上客軍贏，在下主和平。"]'),
('62c8ab8c-2a0a-4a33-87cd-511d99afe525','兵要望江南 占星第十三（京本列第五○四十三首） 四十三','易靜','唐','唐诗','tang','','[]','慧星現，從斗向南行。',32,'全唐诗/poet.tang.54000.json','["慧星現，從斗向南行。", "經過垣牆天市界，外邊兵寇界相臨，損將血成坑。"]'),
('01dc0496-5517-410e-a6dc-837f1d88b613','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 一','易靜','唐','唐诗','tang','','[]','凡北斗，斗乃衆星魁。',32,'全唐诗/poet.tang.54000.json','["凡北斗，斗乃衆星魁。", "天上衆星難相犯，若來相犯有災危，占候者須知。"]'),
('d09993c7-f6c1-4040-a8d3-b2a53db60cc8','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 二','易靜','唐','唐诗','tang','','[]','斗口內，慧現出光芒。',40,'全唐诗/poet.tang.54000.json','["斗口內，慧現出光芒。", "海內兵戈俱大起，江河流絕業成（京本作「田」）荒，民作甲兵糧。"]'),
('d9618368-7ca4-4b4b-b75a-4a460be80315','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 三','易靜','唐','唐诗','tang','','[]','北斗內，穿出慧星輝。',49,'全唐诗/poet.tang.54000.json','["北斗內，穿出慧星輝。", "國內主君邊寨（京本作「塞」）將，陰謀惡黨起旌麾（京本作「強圍」），着意謹防危。"]'),
('7c953bb0-d5e1-456e-a7e9-2acc1d31386f','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 四','易靜','唐','唐诗','tang','','[]','北斗下，氣若破車輪。',32,'全唐诗/poet.tang.54000.json','["北斗下，氣若破車輪。", "白色漸生侵口內，饑荒不稔寇成羣，餘荒不堪論。"]'),
('b9ae0e16-046d-4e1b-9dd7-a607f2c67627','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 五','易靜','唐','唐诗','tang','','[]','黑色氣，守定斗口邊。',32,'全唐诗/poet.tang.54000.json','["黑色氣，守定斗口邊。", "父子相吞天下歉，水渰城郭少乾田，災害四方傳。"]'),
('65b75ae7-643f-4fb4-88c2-7388c0ca0a66','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 六','易靜','唐','唐诗','tang','','[]','占北斗，第一是妖星。',65,'全唐诗/poet.tang.54000.json','["占北斗，第一是妖星。", "却（京本作「都」）要分明軍（辛本、川本、京本作「君」）始吉，忽然不現衆星明。", "主將落奸情。", "（妖星乃貪狼星也。", "）。"]'),
('773a4dd4-3f7b-404a-9eb1-f630bfb64cfb','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 七','易靜','唐','唐诗','tang','','[]','占北斗，夜夜白霞遮。',67,'全唐诗/poet.tang.54000.json','["占北斗，夜夜白霞遮。", "不過七旬兵大起，橫屍千里臥如麻，忌戰日西斜。", "（斗爲主，霞爲客，有索戰，不可出。", "京本「有索戰」作「酉未來索戰」。", "）。"]'),
('60f2fefa-7da5-41bb-bfa5-c6a83be34849','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 八','易靜','唐','唐诗','tang','','[]','占北斗，黃（辛本、川本、京本作「紫」）氣在其中。',75,'全唐诗/poet.tang.54000.json','["占北斗，黃（辛本、川本、京本作「紫」）氣在其中。", "吉（京本作「喜」，辛本、川本作「有」）事欲來君且記，不過旬日（京本作「逾三月」）喜重重，萬姓賀堯風。", "。"]'),
('551df69e-5ccc-49e1-a6c5-d3f6ec38eabc','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 九','易靜','唐','唐诗','tang','','[]','占北斗，赤氣在其中。',62,'全唐诗/poet.tang.54000.json','["占北斗，赤氣在其中。", "萬萬雄風（辛本作「師」、川本作「帥」、京本作「兵」）徒（京本作「多」）費力，攻城盡死不成功，枉把庫厫空。"]'),
('aebb5850-3059-4c0c-b6ee-4ec5cac234da','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 十','易靜','唐','唐诗','tang','','[]','占北斗，兼有小星多。',32,'全唐诗/poet.tang.54000.json','["占北斗，兼有小星多。", "天下不安人失業，荒涼米貴遞相磨，處處動干戈。"]'),
('85f76249-4a29-4910-aadb-ced73e5325e7','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 十一','易靜','唐','唐诗','tang','','[]','青蒼氣，漸入斗心中。',40,'全唐诗/poet.tang.54000.json','["青蒼氣，漸入斗心中。", "定有賊來侵郡邑（京本作「縣」），不然裨將欲謀凶，大忌是三冬。"]'),
('628860de-e68a-4039-948a-13628c91966e','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 十二','易靜','唐','唐诗','tang','','[]','占北斗，明閃電光輝。',32,'全唐诗/poet.tang.54000.json','["占北斗，明閃電光輝。", "定主好人初出世，輔賢明德助人君，此兆即非輕。"]'),
('5e4decaa-896a-4c48-a57d-467626c3c858','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 十三','易靜','唐','唐诗','tang','','[]','占北斗，太白入其中。',57,'全唐诗/poet.tang.54000.json','["占北斗，太白入其中。", "定主將軍逢戰死，城營難守亂人民，大小在（辛本、川本作「走」）西東。", "（太白入斗，將星入度也。", "）。"]'),
('489030e8-b02c-4e4a-9ba8-70acbb351f82','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 十四','易靜','唐','唐诗','tang','','[]','黑雲氣，夜散（辛本、川本作「蔽」）星斗中。',51,'全唐诗/poet.tang.54000.json','["黑雲氣，夜散（辛本、川本作「蔽」）星斗中。", "如此三朝當有雨，急須準備候天情（辛本作「晴」），此理甚分明。"]'),
('3aa97cbf-41cf-478d-b45c-2b4d7a7484ee','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 十五','易靜','唐','唐诗','tang','','[]','占北斗，忽直或伸之。',32,'全唐诗/poet.tang.54000.json','["占北斗，忽直或伸之。", "衝入斗中奸事有，犯其星位各占之，術士亦須知。"]'),
('c5a61c80-f2c0-40fd-b12f-93abe865ed41','兵要望江南 占北斗第十四（京本作「占斗第四」○十六首） 十六','易靜','唐','唐诗','tang','','[]','占北斗，通夜黑雲遮。',32,'全唐诗/poet.tang.54000.json','["占北斗，通夜黑雲遮。", "定主來朝須有雨，急披雨笠候天涯，應兆不能差。"]'),
('40bfcc3c-a9f7-45f5-8764-2f043437d4db','兵要望江南 占地第十五（二十一首） 一','易靜','唐','唐诗','tang','','[]','地之道，與月一般稱。',10,'全唐诗/poet.tang.54000.json','["地之道，與月一般稱。"]'),
('857859d8-cfcf-4de2-9415-6300cf56d7ef','兵要望江南 占地第十五（二十一首） 二','易靜','唐','唐诗','tang','','[]','統軍帥，下寨要安營。',32,'全唐诗/poet.tang.54000.json','["統軍帥，下寨要安營。", "先是須知吉凶地，莫令誤地損兵軍，此理要精明。"]'),
('dfc370a1-37ff-423c-acbe-0a97eca4f39f','兵要望江南 占地第十五（二十一首） 三','易靜','唐','唐诗','tang','','[]','地名好，川破不堪安。',44,'全唐诗/poet.tang.54000.json','["地名好，川破不堪安。", "大路叉中休下寨，伏屍古墓見多般，將帥要知言。", "（主虛驚，賊來破寨。", "）。"]'),
('cd36b920-e7d8-457d-bb74-34520233bb8a','兵要望江南 占地第十五（二十一首） 四','易靜','唐','唐诗','tang','','[]','山窄地，泣滴莫安營。',76,'全唐诗/poet.tang.54000.json','["山窄地，泣滴莫安營。", "兩路中間休立寨，龍頭（辛本、川本作「勿投」）天竈怎持兵，仔細與軍（辛本、川本作「君」）尋。", "（天竈者，大谷之口；龍頭者，大山之端。", "）。"]'),
('dbcb5d12-86ce-4fed-9eeb-fd0844e6e840','兵要望江南 占地第十五（二十一首） 五','易靜','唐','唐诗','tang','','[]','戰場地，古廟與靈壇（首本作「臺」，茲從辛本、川本）。',70,'全唐诗/poet.tang.54000.json','["戰場地，古廟與靈壇（首本作「臺」，茲從辛本、川本）。", "攻破城營移（辛本、川本作「遺」）故地，盡言凶敗與傷殘，細說與軍（辛本、川本作「兵」）官。"]'),
('5a37aaea-0361-497a-904e-e45719f78d5b','兵要望江南 占地第十五（二十一首） 六','易靜','唐','唐诗','tang','','[]','山谷中，下寨忌逢之。',32,'全唐诗/poet.tang.54000.json','["山谷中，下寨忌逢之。", "前高後下居之險，地無草木主憂疑，明將總須知。"]'),
('21e51e18-c371-4c71-a62a-102c4978c636','兵要望江南 占地第十五（二十一首） 七','易靜','唐','唐诗','tang','','[]','大驛路，前後總須疑。',43,'全唐诗/poet.tang.54000.json','["大驛路，前後總須疑。", "或在高崗或在（辛本、川本作「近」）水，長深溪澗最無疑，下寨得便宜。"]'),
('b6f6cd31-0ddd-4dac-a19d-f1d144077975','兵要望江南 占地第十五（二十一首） 八','易靜','唐','唐诗','tang','','[]','營已下，須識有災非。',32,'全唐诗/poet.tang.54000.json','["營已下，須識有災非。", "地上忽生諸怪類，往來天象看來情，主將要知因。"]'),
('ff63b59e-3cde-4803-b95c-00ceca1cefd1','兵要望江南 占地第十五（二十一首） 九','易靜','唐','唐诗','tang','','[]','占其地，毛羽忽然生。',32,'全唐诗/poet.tang.54000.json','["占其地，毛羽忽然生。", "必主人君遭厄難，大兵侵國亂朝廷，百事應憂驚。"]'),
('88ec4b1e-8b80-4ce4-a85e-72c76cba249f','兵要望江南 占地第十五（二十一首） 十','易靜','唐','唐诗','tang','','[]','田地上，忽然便生毛。',32,'全唐诗/poet.tang.54000.json','["田地上，忽然便生毛。", "處處盡生人總見，此爲謀逆血流郊，百日主凶妖。"]'),
('59d14654-4f79-4dff-af88-63d9c86db36c','兵要望江南 占地第十五（二十一首） 十一','易靜','唐','唐诗','tang','','[]','城營內，火焰忽然（京本作「生」）光。',48,'全唐诗/poet.tang.54000.json','["城營內，火焰忽然（京本作「生」）光。", "將士敗亡看在速，急須移寨（京本作「轉」）免災殃，不去禍難當。"]'),
('7ec0e0f9-0582-4910-8ea9-d0228e7f0844','兵要望江南 占地第十五（二十一首） 十二','易靜','唐','唐诗','tang','','[]','城忽裂，必主起干戈。',44,'全唐诗/poet.tang.54000.json','["城忽裂，必主起干戈。", "山中地或如雷吼，敵軍來時看（辛本、川本作「速探」）如何，急避莫蹉跎。"]'),
('53ccc7fb-0fac-430f-bd9a-6548eed34454','兵要望江南 占地第十五（二十一首） 十三','易靜','唐','唐诗','tang','','[]','營寨（京本作「砦」）地，泉水及生塵。',48,'全唐诗/poet.tang.54000.json','["營寨（京本作「砦」）地，泉水及生塵。", "有戰不離於月內，早排兵甲敵邊隣，移寨避災迍。", "（先移後戰。", "）。"]'),
('fa8dd994-b1cc-4b0f-8101-48c524b47cb5','兵要望江南 占地第十五（二十一首） 十四','易靜','唐','唐诗','tang','','[]','城營（京本作「營內」）地，無故動還搖。',76,'全唐诗/poet.tang.54000.json','["城營（京本作「營內」）地，無故動還搖。", "大戰必應於歲月（京本作「內」，幷注：「城年營月也。", "」）直須移（京本作「離」）寨禍應消，不去（京本作「出」）將身招。"]'),
('747573f6-e086-4ff3-b041-35faf184705b','兵要望江南 占地第十五（二十一首） 十五','易靜','唐','唐诗','tang','','[]','城營內，地動起兵戈。',58,'全唐诗/poet.tang.54000.json','["城營內，地動起兵戈。", "且早移營於吉地（辛本、川本作「福上」），不然刑禍將身多，陣敗（辛本、川本、京本作「破」）自消磨。"]'),
('b1891bae-7d1b-4ff2-ac8d-33fd83b0dc0f','兵要望江南 占地第十五（二十一首） 十六','易靜','唐','唐诗','tang','','[]','城營内，忽見地生毛。',32,'全唐诗/poet.tang.54000.json','["城營内，忽見地生毛。", "所統精兵當便起，須臾不去禍應遭，禳醮保功勞。"]'),
('415c08f3-b064-427c-9b9e-0669e2c5f375','兵要望江南 占地第十五（二十一首） 十七','易靜','唐','唐诗','tang','','[]','城營內，地上起錢（京本作「殘」）花。',51,'全唐诗/poet.tang.54000.json','["城營內，地上起錢（京本作「殘」）花。", "有似馬蹄同此兆，移營擁（京本作「各營勇」）士定歸家，應驗決無差。", "。"]'),
('a6de04cb-4355-4e42-ac17-0306c9025571','兵要望江南 占地第十五（二十一首） 十八','易靜','唐','唐诗','tang','','[]','城營內，地忽現（辛本、川本、京本作「陷」）崩摧。',66,'全唐诗/poet.tang.54000.json','["城營內，地忽現（辛本、川本、京本作「陷」）崩摧。", "禍結兵連緣此兆，移營脩義滅（京本作「速修仁義免」）凶災，不信將身推（京本作「危」）。"]'),
('24ca6632-d537-425a-a6ad-02457f5d336c','兵要望江南 占地第十五（二十一首） 十九','易靜','唐','唐诗','tang','','[]','城營內，忽見地生丹（京本作「忽有土崩塌」）。',68,'全唐诗/poet.tang.54000.json','["城營內，忽見地生丹（京本作「忽有土崩塌」）。", "敵騎欲來衝突我，差人截路莫輕閑（京本作「待莫輕看」），移寨庶幾安（辛本、川本作「倚亭關」）。"]'),
('55656ad5-bb83-41f7-a741-d101bf9c3193','兵要望江南 占地第十五（二十一首） 二十','易靜','唐','唐诗','tang','','[]','城營內，花草忽然生。',40,'全唐诗/poet.tang.54000.json','["城營內，花草忽然生。", "急出莫令軍疾病，經旬不動將身傾，智士（京本作「勇」）切須明。"]'),
('36909703-c4eb-4cc3-ac8e-7d9a7757ffaf','兵要望江南 占地第十五（二十一首） 二十一','易靜','唐','唐诗','tang','','[]','城營內，地上忽然（京本作「生」）黃。',61,'全唐诗/poet.tang.54000.json','["城營內，地上忽然（京本作「生」）黃。", "五穀或生幷地長（京本作「忽然生遍地」），將軍祿位福無疆，士馬樂（京本作「亦」）安康。", "。"]'),
('e68d0251-0e4c-447d-982f-9a437442e906','兵要望江南 占樹第十六（五首） 一','易靜','唐','唐诗','tang','','[]','城（京本作「營」）中樹，忽然總萎黃。',48,'全唐诗/poet.tang.54000.json','["城（京本作「營」）中樹，忽然總萎黃。", "威氣（京本作「風」）助吾軍必勝，陰神祐我必成強，主將喜非常。"]'),
('9b0a7a7b-c5c4-4669-a934-6c2c511fe120','兵要望江南 占樹第十六（五首） 二','易靜','唐','唐诗','tang','','[]','營側畔，樹木自崩摧。',42,'全唐诗/poet.tang.54000.json','["營側畔，樹木自崩摧。", "若近軍前師敗辱，不然近彼賊（京本作「彼戰必」）衝來，移去免凶災。"]'),
('9ac41051-7178-4662-96cb-b9ad203b3715','兵要望江南 占樹第十六（五首） 三','易靜','唐','唐诗','tang','','[]','諸樹木，花發不當時。',40,'全唐诗/poet.tang.54000.json','["諸樹木，花發不當時。", "營內見之須速備（京本作「避」），定知賊衆欲來圍，移寨免災危。"]'),
('3062bc2e-0c7d-47d5-8c33-00286c43a77c','兵要望江南 占樹第十六（五首） 四','易靜','唐','唐诗','tang','','[]','營寨內，樹本被雷驚。',32,'全唐诗/poet.tang.54000.json','["營寨內，樹本被雷驚。", "或是震傷人與物，此爲傷敗被天嗔，移寨免憂心。"]'),
('4afdefe3-9f04-4e3e-8192-81635fe89f80','兵要望江南 占樹第十六（五首） 五','易靜','唐','唐诗','tang','','[]','諸樹木，忽地出奇枝。',43,'全唐诗/poet.tang.54000.json','["諸樹木，忽地出奇枝。", "異花奇葉人罕見，必生異事報軍（辛本、川本作「君」）知，將帥看修爲。"]'),
('2b759ed9-d97b-4f00-a568-40ee96449f6f','兵要望江南 占蜂第十七（京本列第十一○五首） 一','易靜','唐','唐诗','tang','','[]','軍營內，蜂衆泊於營。',40,'全唐诗/poet.tang.54000.json','["軍營內，蜂衆泊於營。", "兵（京本作「軍」）欲動移應不久，修磨器甲莫教停，總令便須行。"]'),
('950d9e31-fc57-4a92-849a-dc0e7e443d1a','兵要望江南 占蜂第十七（京本列第十一○五首） 二','易靜','唐','唐诗','tang','','[]','軍行次，蜂蝶接連來。',46,'全唐诗/poet.tang.54000.json','["軍行次，蜂蝶接連來。", "定有伏兵居草莽（辛本、川本、京本作「澤」），好防林木與山崖，先探保無災。"]'),
('f657b3ec-8f2d-4c34-a331-0406de5a7e26','兵要望江南 占蜂第十七（京本列第十一○五首） 三','易靜','唐','唐诗','tang','','[]','軍下寨，蜂蝶遍天飛，防有賊來攻我寨，急（首本作「忽」，茲從辛本、川本）須固守莫遲回，主將要先知。',48,'全唐诗/poet.tang.54000.json','["軍下寨，蜂蝶遍天飛，防有賊來攻我寨，急（首本作「忽」，茲從辛本、川本）須固守莫遲回，主將要先知。"]'),
('7440d815-4ee9-45ad-aa1e-d9b7dc779fa6','兵要望江南 占蜂第十七（京本列第十一○五首） 四','易靜','唐','唐诗','tang','','[]','軍營內，蜂惡亂叮（辛本、川本作「呵」）人。',56,'全唐诗/poet.tang.54000.json','["軍營內，蜂惡亂叮（辛本、川本作「呵」）人。", "或是反軍與謀將，必然軍將有灾危，謹守賊欺追（辛本、川本作「追欺」）。", "。"]'),
('9ce04659-2487-469c-b895-ac1af84fa2bc','兵要望江南 占蜂第十七（京本列第十一○五首） 五','易靜','唐','唐诗','tang','','[]','軍營內，蜂子遍飛遊。',32,'全唐诗/poet.tang.54000.json','["軍營內，蜂子遍飛遊。", "必主將軍多口舌，若還移寨沒災危，記此在心機。"]'),
('a8c4b600-1d9e-4dcd-a7b3-d24d6388554d','兵要望江南 占鼠第十八（京本列第十○十首） 一','易靜','唐','唐诗','tang','','[]','占見鼠，其物夙名虛。',32,'全唐诗/poet.tang.54000.json','["占見鼠，其物夙名虛。", "主盜主奸皆主賊，若來爲怪將兵虞，不信禍難除。"]'),
('78725b2c-b0f0-453a-9f4f-1448b378a6c1','兵要望江南 占鼠第十八（京本列第十○十首） 二','易靜','唐','唐诗','tang','','[]','逢見鼠，白色是金精。',40,'全唐诗/poet.tang.54000.json','["逢見鼠，白色是金精。", "若順軍行軍大勝，逆軍來者禍相（京本作「灾」）生，凶吉甚分明。"]'),
('5a8ff0b5-14d4-4aee-80b8-201b76acb892','兵要望江南 占鼠第十八（京本列第十○十首） 三','易靜','唐','唐诗','tang','','[]','逢赤鼠，來往在軍前。',40,'全唐诗/poet.tang.54000.json','["逢赤鼠，來往在軍前。", "此是伏軍（京本作「兵」）藏詭計，搜尋斜谷道旁邊，急備莫遲延。"]'),
('8dd1238c-00a5-4cd6-909b-f96a426d90bd','兵要望江南 占鼠第十八（京本列第十○十首） 四','易靜','唐','唐诗','tang','','[]','軍營內，鼠咬屋椽楹。',43,'全唐诗/poet.tang.54000.json','["軍營內，鼠咬屋椽楹。", "或見（辛本、京本作「向」）壁間搬出土，移營在近改遷寧，排備向前程。"]'),
('3a9c37ac-cb22-42df-af35-e72457a6e3a9','兵要望江南 占鼠第十八（京本列第十○十首） 五','易靜','唐','唐诗','tang','','[]','軍營內，行鼠尾舒前。',77,'全唐诗/poet.tang.54000.json','["軍營內，行鼠尾舒前。", "將（京本作「軍」）主有災須醮謝，夜深谷口（京本作「各各」、辛本、川本作「谷谷」）罷戈（京本作「兵」）鋋，太白（京本作「天似」）報人言。"]'),
('8d780d16-afc4-46a3-a211-89df38fbc0f4','兵要望江南 占鼠第十八（京本列第十○十首） 六','易靜','唐','唐诗','tang','','[]','營寨（京本作「軍營」）內，驀地鼠成行。',58,'全唐诗/poet.tang.54000.json','["營寨（京本作「軍營」）內，驀地鼠成行。", "欲似弔人聲不罷（京本作「出」），此須爲禍將身當，禳謝得平（京本作「保安」）康。"]'),
('ea887fa4-5573-4d5c-b82d-2460da77345f','兵要望江南 占鼠第十八（京本列第十○十首） 七','易靜','唐','唐诗','tang','','[]','營寨內，白日鼠搬兒。',54,'全唐诗/poet.tang.54000.json','["營寨內，白日鼠搬兒。", "不是火災應大水，三日（辛本、川本、京本作「朝」）五（京本作「兩」）日速遷移，不出禍相隨。"]'),
('6b386465-f116-4e16-bd3a-24f021fd306e','兵要望江南 占鼠第十八（京本列第十○十首） 八','易靜','唐','唐诗','tang','','[]','寨中鼠，能舞向人前。',32,'全唐诗/poet.tang.54000.json','["寨中鼠，能舞向人前。", "必有內奸通外敵，且須搜捉莫遷延，速備實爲先。"]'),
('e012d923-0187-4038-be47-3e4dcf3fe7ea','兵要望江南 占鼠第十八（京本列第十○十首） 九','易靜','唐','唐诗','tang','','[]','軍營鼠，血染將衣冠。',32,'全唐诗/poet.tang.54000.json','["軍營鼠，血染將衣冠。", "或咬鼓旗皆不利，信須修謝拜星官，移寨且求安。"]'),
('5de2196e-6098-42a9-8138-a642bf33254c','兵要望江南 占鼠第十八（京本列第十○十首） 十','易靜','唐','唐诗','tang','','[]','將軍臥，眼上被鼠傷（京本作「將軍服，上祍鼠來傷」）。',105,'全唐诗/poet.tang.54000.json','["將軍臥，眼上被鼠傷（京本作「將軍服，上祍鼠來傷」）。", "必有奸賊（京本作「喜神」）來（辛本、川本、京本作「看」）在即，或傷腰下不相當，財散（京本作「破」）客軍強。", "（經曰：「鼠者，賊也。", "如有變易，必主奸寇入也。", "」）。"]'),
('e6cc9a8f-5078-4ea6-b008-c91ed7bdcefc','兵要望江南 占蛇第十九（京本列第二十一○十二首） 一','易靜','唐','唐诗','tang','','[]','兵發日，路上遇橫蛇。',67,'全唐诗/poet.tang.54000.json','["兵發日，路上遇橫蛇。", "或入水中應大勝，蛇還赤地（京本作「色」）戰無涯，勝負較些些（辛本、川本作「勝地住些些」。", "泊住過一日，外動則吉。", "）。"]'),
('4621c164-30b1-4a6c-8ad8-7b3f4b5d62e7','兵要望江南 占蛇第十九（京本列第二十一○十二首） 二','易靜','唐','唐诗','tang','','[]','兵（京本作「軍」）行次，蛇赤忌逢之。',58,'全唐诗/poet.tang.54000.json','["兵（京本作「軍」）行次，蛇赤忌逢之。", "慎備（京本作「陣當」）前程來勒（京本作「應勤」）戰，訓兵激賞布恩威，厚薄勿偏虧。"]'),
('90fb1220-4358-417d-a851-1375b316905a','兵要望江南 占蛇第十九（京本列第二十一○十二首） 三','易靜','唐','唐诗','tang','','[]','軍發次，驀地見交蛇（京本作「蛟交」）。',41,'全唐诗/poet.tang.54000.json','["軍發次，驀地見交蛇（京本作「蛟交」）。", "講武揚兵須宴犒，不然上將中風邪，身喪掩黃沙。"]'),
('18bd2f16-d011-47e4-a2a3-293b1ca74dbf','兵要望江南 占蛇第十九（京本列第二十一○十二首） 四','易靜','唐','唐诗','tang','','[]','蛇赤（辛本、川本、京本作「諸」）色，大小外邊來。',82,'全唐诗/poet.tang.54000.json','["蛇赤（辛本、川本、京本作「諸」）色，大小外邊來。", "來入我軍兵欲敵（京本作「散」），更防引得外奸乖，德向（京本作「得上」）好通開（首本作「關」，茲從辛本、川本、京本）。"]'),
('c465aad0-9547-4877-9bd3-db6d910755d7','兵要望江南 占蛇第十九（京本列第二十一○十二首） 五','易靜','唐','唐诗','tang','','[]','長蛇見，飲水近營（京本作「軍」）傍。',76,'全唐诗/poet.tang.54000.json','["長蛇見，飲水近營（京本作「軍」）傍。", "抽退還鄉方始吉，不然移寨九天方，禳厭免災殃（辛本、川本末八字作「向高強，營壘布旌幢」。", "京本注：「太歲九天上同。", "」）。"]'),
('3ff907cd-d766-4fdd-b66c-912e14c03b2c','兵要望江南 占蛇第十九（京本列第二十一○十二首） 六','易靜','唐','唐诗','tang','','[]','兵（京本作「軍」）行次，蛇貫路邊傍。',57,'全唐诗/poet.tang.54000.json','["兵（京本作「軍」）行次，蛇貫路邊傍。", "備禦伏（京本作「賊」）兵前道阻，且須仔細更思量，終不使開（京本作「利封」）疆。"]'),
('fb486724-d2e9-461b-91b1-e084777042ca','兵要望江南 占蛇第十九（京本列第二十一○十二首） 七','易靜','唐','唐诗','tang','','[]','蛇入井，俱是敗軍形。',32,'全唐诗/poet.tang.54000.json','["蛇入井，俱是敗軍形。", "或似杄形營內現，若還交戰血成坑，堅守我軍營。"]'),
('397c2a69-29dc-4537-b3d7-dcd166f8dfca','兵要望江南 占蛇第十九（京本列第二十一○十二首） 八','易靜','唐','唐诗','tang','','[]','蛇貫道，白赤動（京本作「助」）軍情。',70,'全唐诗/poet.tang.54000.json','["蛇貫道，白赤動（京本作「助」）軍情。", "必有賊兵攔道路（京本作「捫路道」），只宜盤泊賞軍兵，不久却回程。", "（但有異色之蛇攔路，回師罷戰，大吉。", "）。"]'),
('48c69f18-8588-412c-886b-866bf494f544','兵要望江南 占蛇第十九（京本列第二十一○十二首） 九','易靜','唐','唐诗','tang','','[]','蛇如鳥，更有似弓（辛本、川本作「車」）形。',62,'全唐诗/poet.tang.54000.json','["蛇如鳥，更有似弓（辛本、川本作「車」）形。", "或是白蛇形（辛本、川本作「行」、京本作「形如」）斷續，兼之五六見城營，泣淚血交幷。"]'),
('9348bcd6-b64a-4c80-9b34-727e35852b5e','兵要望江南 占蛇第十九（京本列第二十一○十二首） 十','易靜','唐','唐诗','tang','','[]','蛟蛇見，營寨必（京本作「不」）宜攻。',56,'全唐诗/poet.tang.54000.json','["蛟蛇見，營寨必（京本作「不」）宜攻。", "更有青蛇人病疾，黃蛇疫瘴總成凶，移寨（京本作「徙」）免灾凶（京本作「逢」）。"]'),
('37e9b40e-dace-48b5-9d5a-2424bb352d4c','兵要望江南 占蛇第十九（京本列第二十一○十二首） 十一','易靜','唐','唐诗','tang','','[]','兵行次，水裏怕逢蛇。',52,'全唐诗/poet.tang.54000.json','["兵行次，水裏怕逢蛇。", "更有魚龍蜃類見，悉皆進退事無涯（京本作「捱」），速退莫咨嗟。", "（如見龍蛇蜃，幷同。", "）。"]'),
('ea6960e7-d6f3-40fe-8bb9-b04e1da10c59','兵要望江南 占蛇第十九（京本列第二十一○十二首） 十二','易靜','唐','唐诗','tang','','[]','下營畢（京本作「軍」），遶寨（京本作「蛇遶」）大蛇棲。',73,'全唐诗/poet.tang.54000.json','["下營畢（京本作「軍」），遶寨（京本作「蛇遶」）大蛇棲。", "必有賊（京本作「戰」）兵來打寨，高強營壘矗（京本作「布」）旌旗，謹慎欲（京本作「好」）防之。"]'),
('49568868-4aa2-4f53-b2cf-58fa2146ceb5','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 一','易靜','唐','唐诗','tang','','[]','城營內，馬夜轉槽鳴。',78,'全唐诗/poet.tang.54000.json','["城營內，馬夜轉槽鳴。", "軍欲離營將大戰，早排驍勇各嚴（辛本、川本作「令行」）明，（京本作「各令齊」），法令（辛本、川本作「號」）整齊行（京本作「號令辨高低」）。"]'),
('e4fc4e8f-27b9-448c-9632-5a1c632fdef3','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 二','易靜','唐','唐诗','tang','','[]','軍營內，馬咬石兼沙。',40,'全唐诗/poet.tang.54000.json','["軍營內，馬咬石兼沙。", "必有賊兵吾（京本作「君」）大獲，將軍克勝遠方誇，大小總榮華。"]'),
('e2b8a7d9-f58b-4e13-aa24-b55517cd0fcf','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 三','易靜','唐','唐诗','tang','','[]','軍營內，牛舞向人前。',46,'全唐诗/poet.tang.54000.json','["軍營內，牛舞向人前。", "欲罷戰爭休士卒，干戈不舉却回旋，各（辛本、川本、京本作「齊」）賀太平年。"]'),
('81e52107-79e7-4bdc-a3c0-0bb97f646213','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 四','易靜','唐','唐诗','tang','','[]','馬廐內，天火忽然燒。',43,'全唐诗/poet.tang.54000.json','["馬廐內，天火忽然燒。", "看即大兵將欲起，直須修德（辛本、川本作「福」）禍方消，勿使自身招。"]'),
('b9423768-8233-431a-a2ee-a74b0fced7ee','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 五','易靜','唐','唐诗','tang','','[]','城營內，驢馬作人言。',51,'全唐诗/poet.tang.54000.json','["城營內，驢馬作人言。", "聽取語言爲定（京本作「作」）准，更看馬後（辛本、川本作「駿」）殺軍年，方始報仇冤。"]'),
('74d5613c-7fcc-43c2-a74f-d4b364f77e0e','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 六','易靜','唐','唐诗','tang','','[]','軍（川本作「城」）營內，牛馬夜間鳴。',40,'全唐诗/poet.tang.54000.json','["軍（川本作「城」）營內，牛馬夜間鳴。", "必有暴兵來覓鬬，直須防備夜偷營，速暗布精兵。"]'),
('009f62cf-56f7-46f8-80d3-0d91102ddea6','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 七','易靜','唐','唐诗','tang','','[]','城營內，生產兩頭奇。',32,'全唐诗/poet.tang.54000.json','["城營內，生產兩頭奇。", "或有足多生八隻，四足兩頭禍不移，裂土應逾期。"]'),
('4b1ff82b-e6a0-4a0c-b22f-bc1f3b7d8e5a','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 八','易靜','唐','唐诗','tang','','[]','占走獸，獸字體相將。',54,'全唐诗/poet.tang.54000.json','["占走獸，獸字體相將。", "或（辛本、川本作「凡」）有怪形須要當，由分凶吉與君張，要辨（辛本、川本作「獸」）虎豺狼。"]'),
('056df25f-d9a0-42d4-8791-1287fb770892','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 九','易靜','唐','唐诗','tang','','[]','兵發日（京本作「發兵次」），野獸截軍（京本作「兵」）行。',66,'全唐诗/poet.tang.54000.json','["兵發日（京本作「發兵次」），野獸截軍（京本作「兵」）行。", "直向隊中衝透過，必然（京本作「分」）隊伍兩縱橫，良將要（京本作「亦」）須明。"]'),
('6c4b7af3-6da3-4215-b840-3896d7e207ed','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 十','易靜','唐','唐诗','tang','','[]','兵行次，狼虎及熊羆。',60,'全唐诗/poet.tang.54000.json','["兵行次，狼虎及熊羆。", "若在軍前狂亂（京本作「浪」）走，此行旬日戰無移（京本作「旬戰定無宜」），先舉得（京本作「合」）天機。"]'),
('d8a51876-f68e-4731-b48d-39086dccc1a8','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 十一','易靜','唐','唐诗','tang','','[]','諸禽獸，異色及無名。',41,'全唐诗/poet.tang.54000.json','["諸禽獸，異色及無名。", "有爪有牙（京本作「齒」）爲我怕，無牙無爪亦應輕，此兆甚分明。", "。"]'),
('a351e243-7706-4dbd-a86f-0535d1a45e04','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 十二','易靜','唐','唐诗','tang','','[]','營前後，野獸亂縱橫。',48,'全唐诗/poet.tang.54000.json','["營前後，野獸亂縱橫。", "殺取太牢天地祭，三（京本作「六」）軍方得保安寧，有戰必須（京本作「然」）贏。"]'),
('3b8f198c-4bbc-4b04-b1dc-cd7b0d9c9bf2','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 十三','易靜','唐','唐诗','tang','','[]','城營內，白鹿入營來。',40,'全唐诗/poet.tang.54000.json','["城營內，白鹿入營來。", "將士病災方欲起，若還無角（京本作「病」）主兵回，移寨免災危。"]'),
('f2dda3e0-9036-4d58-995e-e29fa4891806','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 十四','易靜','唐','唐诗','tang','','[]','兵屯次，鹿走入軍營。',58,'全唐诗/poet.tang.54000.json','["兵屯次，鹿走入軍營。", "必有降人來見我，期於三日事分明，或（京本作「咸」）喜長威名。", "（辛本、川本注：有戰作，主大勝。", "）。"]'),
('f344e0d5-a9c0-4c7e-85f0-db28a56d3898','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 十五','易靜','唐','唐诗','tang','','[]','狼與虎，切忌入軍（京本作「營」）中。',40,'全唐诗/poet.tang.54000.json','["狼與虎，切忌入軍（京本作「營」）中。", "隊伍突衝幷截路，不過數日有危凶，警備勿交攻。"]'),
('0ff54753-e6f6-4ccf-b543-11f84f250a91','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 十六','易靜','唐','唐诗','tang','','[]','虎相食，兆不出三年。',32,'全唐诗/poet.tang.54000.json','["虎相食，兆不出三年。", "必有大兵當至此，來其分野禍相煎，其兆理關天。"]'),
('802235c8-357e-4816-9709-3c221592856e','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 十七','易靜','唐','唐诗','tang','','[]','兵屯次，野象（京本作「豕」）入于營。',48,'全唐诗/poet.tang.54000.json','["兵屯次，野象（京本作「豕」）入于營。", "急急殺來將祭獻（京本作「鼓」），三軍從此得安寧，齋沐要嚴精。"]'),
('3f1cc32c-d855-4f75-b322-f166384c528b','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 十八','易靜','唐','唐诗','tang','','[]','城營內，鹿（京本作「麂」）子入其中。',54,'全唐诗/poet.tang.54000.json','["城營內，鹿（京本作「麂」）子入其中。", "殺取三牲將祭獻（辛本、川本、京本作「禱」），急當移寨免災凶，否則禍重重。"]'),
('607c47df-9f78-4aae-89bc-c745f6bfdb47','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 十九','易靜','唐','唐诗','tang','','[]','軍營側，驀地有豪猪。',43,'全唐诗/poet.tang.54000.json','["軍營側，驀地有豪猪。", "須備伏兵來犯（京本作「賊兵來劫」）我，便宜先舉莫躊躇，移寨始無虞。"]'),
('3221003d-1d3c-4d99-b88b-9f37ffa1110b','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 二十','易靜','唐','唐诗','tang','','[]','軍營內，或（京本作「忽」）有野猪來。',40,'全唐诗/poet.tang.54000.json','["軍營內，或（京本作「忽」）有野猪來。", "若戰先贏多後敗，速當移寨避其災，修謝莫遲回。"]'),
('c0d73cf5-b1af-4985-b8d5-a79cf6f82821','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 二十一','易靜','唐','唐诗','tang','','[]','軍營內，兔走在（京本作「入」）其中。',48,'全唐诗/poet.tang.54000.json','["軍營內，兔走在（京本作「入」）其中。", "雖有雄兵終不戰，都緣彼敵欲和同，不在苦（京本作「若」）邀功。"]'),
('18c9759e-5a3e-4d57-adbc-306b5ad9b754','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 二十二','易靜','唐','唐诗','tang','','[]','軍營內，狸獸（京本作「走」）夜頻鳴。',40,'全唐诗/poet.tang.54000.json','["軍營內，狸獸（京本作「走」）夜頻鳴。", "恰似豺狼同此兆，必知將士欲離營，不久禍災生。"]'),
('48ae1f2a-09ad-43d9-8380-f164bf083a2d','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 二十三','易靜','唐','唐诗','tang','','[]','兵屯（京本作「行」）次，豺狗入於營。',57,'全唐诗/poet.tang.54000.json','["兵屯（京本作「行」）次，豺狗入於營。", "內有奸人（京本作「兵」）相結外，急須搜捉察原情，莫遣叛縱橫（京本作「蹤興」）。"]'),
('c155b47a-ac06-4592-bb84-c95259852aba','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 二十四','易靜','唐','唐诗','tang','','[]','軍營內，狗怪遣人猜（京本作「灾」）。',48,'全唐诗/poet.tang.54000.json','["軍營內，狗怪遣人猜（京本作「灾」）。", "急殺血流于戍（京本作「成」）地，埋深三尺以禳災，敵將必擒來。"]'),
('6956e41d-1e23-4ff2-9e02-656859a1d54d','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 二十五','易靜','唐','唐诗','tang','','[]','軍營內，獐入及登城。',40,'全唐诗/poet.tang.54000.json','["軍營內，獐入及登城。", "若遇此妖多是火，不然孝服與兵爭，祈謝保（京本作「得」）安寧。"]'),
('43a2feeb-f5b4-4d2d-b622-23d4b7287094','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 二十六','易靜','唐','唐诗','tang','','[]','兵行次，路上遇猿猴。',41,'全唐诗/poet.tang.54000.json','["兵行次，路上遇猿猴。", "嚴令小心防恐怖，理當排槊（京本作「齪」）整戈矛，預計盡良籌。", "。"]'),
('d83cf4e1-12df-4f88-bab5-9adf94a1c86a','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 二十七','易靜','唐','唐诗','tang','','[]','狼與虎，遶寨作悲鳴（京本作「聲」）。',64,'全唐诗/poet.tang.54000.json','["狼與虎，遶寨作悲鳴（京本作「聲」）。", "似哭似號（京本作「嘷」）軍大敗，將軍兵敗（京本作「潰」）事多驚（京本作「更」），屍壘澗溝平。"]'),
('852eb726-8ee0-49b6-810d-0627e10b6cb6','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 二十八','易靜','唐','唐诗','tang','','[]','狼奔走，直撞入吾軍。',42,'全唐诗/poet.tang.54000.json','["狼奔走，直撞入吾軍。", "不出三日（京本作「去三朝」）幷五日，敵來降我引朝君，彼我受皇恩。"]'),
('92236bbb-653e-44cf-981c-8f7667a446e6','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 二十九','易靜','唐','唐诗','tang','','[]','野猪鹿，從外入中營。',48,'全唐诗/poet.tang.54000.json','["野猪鹿，從外入中營。", "定有降人來投（京本作「伏」）我，只於三日見分明，引使（京本作「伴」）履王庭。"]'),
('66a98895-88e0-4ea9-8dfa-21c63753de1e','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 三十','易靜','唐','唐诗','tang','','[]','狼與虎，卒見使人驚。',46,'全唐诗/poet.tang.54000.json','["狼與虎，卒見使人驚。", "我在徒師前去後（京本作「在我帥營前後走」），須防大戰血成坑，不遇聖賢明。"]'),
('eed6bc04-99fc-43cf-a817-4a6679ecd9f8','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 三十一','易靜','唐','唐诗','tang','','[]','兵行（辛本、川本、京本作「屯」）次，狸走入其中。',77,'全唐诗/poet.tang.54000.json','["兵行（辛本、川本、京本作「屯」）次，狸走入其中。", "不住夜鳴圍繞寨，先因風火事（京本作「憂風火夜」）重重，埋伏且藏兵（京本作「蹤」、辛本、川本作「擬藏中」）。"]'),
('bc0bb51d-4780-450c-b262-3b7d8eb49feb','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 三十二','易靜','唐','唐诗','tang','','[]','軍營內，驀地有來獐。',32,'全唐诗/poet.tang.54000.json','["軍營內，驀地有來獐。", "三朝七日須大戰，不然講武較旗鎗。", "速斬免災殃。"]'),
('7709d923-bff5-45de-bf32-6d20d40810f2','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 三十三','易靜','唐','唐诗','tang','','[]','牛與馬，產出是人形。',32,'全唐诗/poet.tang.54000.json','["牛與馬，產出是人形。", "定主胡人侵大國，不分南北亂人民，且候聖明生。"]'),
('0867a374-3563-42a9-a659-2ba38b993fec','兵要望江南 占獸第二十（京本列第二十二，前六首另作「占牛馬第十八」○三十四首） 三十四','易靜','唐','唐诗','tang','','[]','狼與虎，號泣（辛本、川本作「號叫」、京本作「嘯叫」）又傷人。',70,'全唐诗/poet.tang.54000.json','["狼與虎，號泣（辛本、川本作「號叫」、京本作「嘯叫」）又傷人。", "五日七朝兵起至，臨時勝負預鋪陳，方許（辛本、川本作「治」、京本作「恥」）敗來軍。"]'),
('76101ae4-47fa-4b58-a067-38185fa24ed9','兵要望江南 占水族第二十一（京本列第十二○七首） 一','易靜','唐','唐诗','tang','','[]','兵行次，水族忌逢（京本作「行」）之。',40,'全唐诗/poet.tang.54000.json','["兵行次，水族忌逢（京本作「行」）之。", "但是魚龍蛟蜃類，悉皆不吉兆災危，抽退却相宜。"]'),
('95203a55-2b63-427c-8ffb-b2255fe43e35','兵要望江南 占水族第二十一（京本列第十二○七首） 二','易靜','唐','唐诗','tang','','[]','龍現壘，室宅及池（京本作「其」）中。',55,'全唐诗/poet.tang.54000.json','["龍現壘，室宅及池（京本作「其」）中。", "必有大臣謀叛逆，且須作急探奸凶，莫待有奔衝。", "（王莽、朱溫時，龍現池沼。", "）。"]'),
('dc219c92-4e96-4927-9107-ef6c99dba9c3','兵要望江南 占水族第二十一（京本列第十二○七首） 三','易靜','唐','唐诗','tang','','[]','軍（京本作「兵」）行次，龍鬬在軍前。',48,'全唐诗/poet.tang.54000.json','["軍（京本作「兵」）行次，龍鬬在軍前。", "必是（京本作「有」）交鋒亡命戰，黃龍得勝黑龍偏，平地血成川。"]'),
('0c70251e-0b3b-4076-93ba-b36820f8dcc1','兵要望江南 占水族第二十一（京本列第十二○七首） 四','易靜','唐','唐诗','tang','','[]','城營內，魚鼈現（辛本、川本、京本作「鼈忽露」）其形。',49,'全唐诗/poet.tang.54000.json','["城營內，魚鼈現（辛本、川本、京本作「鼈忽露」）其形。", "防有內奸謀叛逆，不然水漲浸軍兵，速去得安寧。", "。"]'),
('b19cd304-7403-4aad-8b86-e54db50ca207','兵要望江南 占水族第二十一（京本列第十二○七首） 五','易靜','唐','唐诗','tang','','[]','城營內，龜蟹入其（京本作「營」）中。',60,'全唐诗/poet.tang.54000.json','["城營內，龜蟹入其（京本作「營」）中。", "更有聚蠅億萬數，軍兵潰散（京本作「敗」）敗不從容，看即棄（辛本、川本作「旋」）營空。"]'),
('78a6d31f-3383-4887-866e-08aa0d491959','兵要望江南 占水族第二十一（京本列第十二○七首） 六','易靜','唐','唐诗','tang','','[]','軍（京本作「兵」）行次，路上見黿鼉。',60,'全唐诗/poet.tang.54000.json','["軍（京本作「兵」）行次，路上見黿鼉。", "或有戰爭營寨（京本作「在戰營征砦」）內，不宜前進有（京本作「損」）兵戈，細審莫奔波。"]'),
('0fe0eb3d-8ddb-4230-a6b7-369925180e3e','兵要望江南 占水族第二十一（京本列第十二○七首） 七','易靜','唐','唐诗','tang','','[]','城營內，龜鼈入其營。',59,'全唐诗/poet.tang.54000.json','["城營內，龜鼈入其營。", "盡是頓遲亡（首本作「忘」，此從辛本、川本）敗象，速當移寨免灾凶，不去禍灾（辛本、川本作「將」）生。"]'),
('cd93af76-40f1-4a64-9ee0-830373dc4601','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 一','易靜','唐','唐诗','tang','','[]','占飛鳥，軍旅要知因。',32,'全唐诗/poet.tang.54000.json','["占飛鳥，軍旅要知因。", "或是縱橫或逐我，或來逆我或成羣，仔細說來情。"]'),
('5f70d83a-4a12-4815-b6ce-370a465a4610','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 二','易靜','唐','唐诗','tang','','[]','鷹搦鷂，勢速入軍營。',32,'全唐诗/poet.tang.54000.json','["鷹搦鷂，勢速入軍營。", "必是義兄圖義弟，不然義弟欲謀兄，奸禍兩般情。"]'),
('297fd717-d7d2-40e2-b9f5-fa536fdb62a9','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 三','易靜','唐','唐诗','tang','','[]','兵行次，鷹鶚面（京本作「鷂向」）前飛。',67,'全唐诗/poet.tang.54000.json','["兵行次，鷹鶚面（京本作「鷂向」）前飛。", "所向進兵應（京本作「須」）大勝，必能捉彼將兵（辛本、川本作「師」、京本作「帥」）歸，天意助神威。"]'),
('82d19f3c-ee0d-4ee4-8618-1eb2d6a41413','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 四','易靜','唐','唐诗','tang','','[]','城營內，鷂子搦蒼鷹。',32,'全唐诗/poet.tang.54000.json','["城營內，鷂子搦蒼鷹。", "定有奸謀陰禍起，早須排備莫惶驚，有戰損精兵。"]'),
('d50f0cea-f599-47ee-8272-3989d19b15f5','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 五','易靜','唐','唐诗','tang','','[]','兵行次，鷂鶚（京本作「鷹鷂」）捉飛禽。',49,'全唐诗/poet.tang.54000.json','["兵行次，鷂鶚（京本作「鷹鷂」）捉飛禽。", "此去前程須有戰，得其首領盡生擒，主（京本作「上」）將稱其心。"]'),
('bf225cf9-c237-42c3-9fdf-19710e027cbe','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 六','易靜','唐','唐诗','tang','','[]','兵行次，鷹鶻（辛本、川本、京本作「鶻雁」）盡同占。',61,'全唐诗/poet.tang.54000.json','["兵行次，鷹鶻（辛本、川本、京本作「鶻雁」）盡同占。", "鷹（辛本、川本、京本作「雁」）不避鶻鶻不搦，兩軍通好守盟言，各擁士回還。"]'),
('71efab20-23cf-4690-be7b-c991a6800c32','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 七','易靜','唐','唐诗','tang','','[]','城營內，忽（京本作「或」）見杜鵑來。',41,'全唐诗/poet.tang.54000.json','["城營內，忽（京本作「或」）見杜鵑來。", "應有負冤人未雪，佞臣謀間損賢才，天遣叫聲哀。", "。"]'),
('d4d6770b-edb9-4e59-913f-eaa066d87119','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 八','易靜','唐','唐诗','tang','','[]','羣烏（京本作「雀」）噪，隊隊逐（辛本、川本、京本作「遶」）營飛。',78,'全唐诗/poet.tang.54000.json','["羣烏（京本作「雀」）噪，隊隊逐（辛本、川本、京本作「遶」）營飛。", "防有賊（京本作「外」）兵來劫寨，早須整（京本作「准」）備設關機，遲（京本作「稽」）慢致灾危。"]'),
('0246629d-cce1-46ba-baf5-9fdcbc109396','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 九','易靜','唐','唐诗','tang','','[]','城營內，衆鳥噪聲鳴。',50,'全唐诗/poet.tang.54000.json','["城營內，衆鳥噪聲鳴。", "必有暴兵來劫寨，不然有戰損於（辛本、川本作「千」、京本作「戈」）兵，移轉最爲精。"]'),
('ed3217a3-8ba0-43d0-90c6-362227b5b845','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 十','易靜','唐','唐诗','tang','','[]','羣鳥隊，飛去又飛來。',69,'全唐诗/poet.tang.54000.json','["羣鳥隊，飛去又飛來。", "不問（辛本、川本作「以」）下（京本作「在」）營幷在路，此行千里足（京本作「十里走」）難回，仔細察天灾（京本作「威」）。"]'),
('357865db-5d53-4ef2-88ee-ab3b277d6071','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 十一','易靜','唐','唐诗','tang','','[]','羣鳥聚（京本作「隊」），飛起忽然驚。',61,'全唐诗/poet.tang.54000.json','["羣鳥聚（京本作「隊」），飛起忽然驚。", "盡向滿天鳴噪鬧，不過三日火燒營，或有劫寨（辛本、川本、京本作「殘」）兵。", "（移營吉。", "）。"]'),
('4bf56b5b-d0c3-444d-8899-18cccabdd5bb','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 十二','易靜','唐','唐诗','tang','','[]','城營內，四面鳥聲鳴（京本作「有鳥聲」）。',42,'全唐诗/poet.tang.54000.json','["城營內，四面鳥聲鳴（京本作「有鳥聲」）。", "千萬結成鳴噪去，急須固守本城營，堅執戰傷兵。"]'),
('af66f823-0faa-4926-86a0-b1535e8080a9','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 十三','易靜','唐','唐诗','tang','','[]','城營內，鳥夜結羣鳴。',40,'全唐诗/poet.tang.54000.json','["城營內，鳥夜結羣鳴。", "必有暴兵來覓戰，不然城寨有虛驚，探後（京本作「候」）用心聽。"]'),
('5996bd22-e34b-4d99-b808-2230d122c223','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 十四','易靜','唐','唐诗','tang','','[]','鳥衆泊（京本作「拍」）營墻（京本作「壇」）。',52,'全唐诗/poet.tang.54000.json','["鳥衆泊（京本作「拍」）營墻（京本作「壇」）。", "頭向此營皆盡叫，人驚不起是天殃，不免（京本作「去」）見傷亡。"]'),
('545a8c31-2803-4308-920a-4a90660eb28f','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 十五','易靜','唐','唐诗','tang','','[]','城營內，鳥鵲（辛本、川本、京本作「烏鳥」）驀然驚。',78,'全唐诗/poet.tang.54000.json','["城營內，鳥鵲（辛本、川本、京本作「烏鳥」）驀然驚。", "內有奸臣連外賊，隄防大（京本、辛本、川本作「苦」）戰血成坑，謀反（京本作「叛」）害英明（川本作「其身」）。"]'),
('a864ad60-c48a-43e8-8026-a1c3e93b1cb9','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 十六','易靜','唐','唐诗','tang','','[]','城營內，烏鵲忽圍牆。',62,'全唐诗/poet.tang.54000.json','["城營內，烏鵲忽圍牆。", "當有敵（京本作「外」）兵來打寨，不然疾病大（辛本、川本、京本作「火」）灾殃，營內欲來（京本作「他」）降。"]'),
('9dfd0001-50de-4ba0-bbf6-5432d56a5c1b','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 十七','易靜','唐','唐诗','tang','','[]','城營內，鳥鵲（辛本、川本作「噪」）兩（京本作「叫二」）三聲。',69,'全唐诗/poet.tang.54000.json','["城營內，鳥鵲（辛本、川本作「噪」）兩（京本作「叫二」）三聲。", "必有命（京本作「使」）來應在即，早須奉候出門迎，此意（京本作「語」）且須聽。", "。"]'),
('abc04902-785e-44e2-94f1-06d44eca2c72','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 十八','易靜','唐','唐诗','tang','','[]','鳥相打（京本作「相打拍」），防撃有奸爭。',53,'全唐诗/poet.tang.54000.json','["鳥相打（京本作「相打拍」），防撃有奸爭。", "斬斷罪愆懲戒衆，若無敵（辛本、川本作「停」）戰禍應生，固守始爲精。"]'),
('03a45fc1-306a-4910-9411-4a497aebafde','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 十九','易靜','唐','唐诗','tang','','[]','城營內，鳥集奪巢飛。',53,'全唐诗/poet.tang.54000.json','["城營內，鳥集奪巢飛。", "必有鬬爭相競事，不然下吏欲爲非，防慎見（辛本、川本作「間」）分（京本作「有間相」）離。"]'),
('c1383f34-e08a-4cca-b78d-01af48ede2ed','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 二十','易靜','唐','唐诗','tang','','[]','臨陣次，鳥向四方鳴。',48,'全唐诗/poet.tang.54000.json','["臨陣次，鳥向四方鳴。", "選取鳥聲鳴叫（京本作「向」）處，但從（京本作「存」）此地出軍征，百戰百回贏。"]'),
('c1dbe323-183c-4d05-ac66-2908e7c607a7','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 二十一','易靜','唐','唐诗','tang','','[]','兵發日，前面有羣烏（首本作「聲鳴」，茲從辛本、川本、京本）。',82,'全唐诗/poet.tang.54000.json','["兵發日，前面有羣烏（首本作「聲鳴」，茲從辛本、川本、京本）。", "亂叫亂（辛本、川本、京本作「衆」）鳴防伏截，或（京本作「忽」）然有戰莫先圖，詳緩保（京本作「却」）無虞。"]'),
('4bd153ea-2324-41d1-8726-17dcfeeddb95','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 二十二','易靜','唐','唐诗','tang','','[]','兵行次，鳥衆集旌旗。',44,'全唐诗/poet.tang.54000.json','["兵行次，鳥衆集旌旗。", "若見中軍加喜氣，將軍增爵位遷移，在即不爲遲（京本作「在疾莫遲爲」）。"]'),
('0761f95a-dab2-4959-b317-6c1445e27a9b','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 二十三','易靜','唐','唐诗','tang','','[]','兵發日，鳥衆逐軍行。',40,'全唐诗/poet.tang.54000.json','["兵發日，鳥衆逐軍行。", "未見彼軍防隱伏，若逢敵戰（京本作「陣」）利先征，攻戰必先贏。"]'),
('86139e78-a8bf-4314-8ae4-1a15c4b4c925','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 二十四','易靜','唐','唐诗','tang','','[]','兵（京本作「軍」）行次，橫陣列鳥來。',49,'全唐诗/poet.tang.54000.json','["兵（京本作「軍」）行次，橫陣列鳥來。", "防有伏兵衝隊伍（京本作「陣位」），搜羅前後用心猜，不信必爲災。"]'),
('670c14c2-2ee1-484c-b4da-5e941b9b9dd7','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 二十五','易靜','唐','唐诗','tang','','[]','兵行次，鳥衆後頭來。',47,'全唐诗/poet.tang.54000.json','["兵行次，鳥衆後頭來。", "若遇前隨應大勝，逆來衝我且宜回，退却免凶灾（辛本、川本、京本作「灾危」）。"]'),
('a92b4853-331a-4dbd-925f-1276709d7fcf','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 二十六','易靜','唐','唐诗','tang','','[]','兵行次，鳥立在軍旗。',40,'全唐诗/poet.tang.54000.json','["兵行次，鳥立在軍旗。", "必有奸人言賊勢，今旬來月好防之，偷（京本作「發」）號運謀機。"]'),
('32b14051-7005-4ed4-b5fd-0e0df250077a','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 二十七','易靜','唐','唐诗','tang','','[]','兵行次，軍上鳥鳴飛。',32,'全唐诗/poet.tang.54000.json','["兵行次，軍上鳥鳴飛。", "不論下營將布陣，若同此瑞合天機，必勝莫遲疑。"]'),
('6a3f6376-717f-4733-8fbb-03356f87ef79','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 二十八','易靜','唐','唐诗','tang','','[]','下營次，鳥衆集牙旗。',40,'全唐诗/poet.tang.54000.json','["下營次，鳥衆集牙旗。", "急宰三牲將祭禱，不然軍（京本作「兵」）敗主分離，靈物報人知。"]'),
('54791372-42a0-4e32-bd6a-89948fd9089a','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 二十九','易靜','唐','唐诗','tang','','[]','城營內，白鵲（京本作「雀」）入軍營（辛本、川本、京本作「營中」）。',55,'全唐诗/poet.tang.54000.json','["城營內，白鵲（京本作「雀」）入軍營（辛本、川本、京本作「營中」）。", "若作巢窩兵大起，急須移寨免災凶，否則禍重重。"]'),
('ccd7549e-3f14-4cf5-8f01-df7d586952a1','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 三十','易靜','唐','唐诗','tang','','[]','城營內，靈鵲（京本作「雀」）件巢窩。',40,'全唐诗/poet.tang.54000.json','["城營內，靈鵲（京本作「雀」）件巢窩。", "不去營空兼火起，速當移寨禍消磨，久住殺傷多。"]'),
('8b0ba4f5-5cc1-40cc-af1b-4e292e4c5cc6','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 三十一','易靜','唐','唐诗','tang','','[]','寨始定，白鵲入營來。',32,'全唐诗/poet.tang.54000.json','["寨始定，白鵲入營來。", "此是金星呈怪象，有人相害處謀乖，移寨免其災。"]'),
('3c5ba0f5-467f-430a-8af1-046a2f682368','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 三十二','易靜','唐','唐诗','tang','','[]','羣鵲（京本作「雀」）噪，頭向敵軍營。',68,'全唐诗/poet.tang.54000.json','["羣鵲（京本作「雀」）噪，頭向敵軍營。", "隨鵲戰之軍必勝，一般羣鵲（京本作「雀」）事無成，在外也須驚。", "（頭指敵噪我軍勝，不指敵噪鬧則虛驚。", "）。"]'),
('1d812059-64ce-47dc-970b-28eb31703903','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 三十三','易靜','唐','唐诗','tang','','[]','城營內，野雉入軍中。',44,'全唐诗/poet.tang.54000.json','["城營內，野雉入軍中。", "若在德鄉來即吉，或臨刑殺候爲（京本作「刑或殺帥侯」）凶，仔細審西東。"]'),
('57011e37-451d-4787-8bed-dc0b41b2a7ee','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 三十四','易靜','唐','唐诗','tang','','[]','城營內，驀地降鴛鴦。',32,'全唐诗/poet.tang.54000.json','["城營內，驀地降鴛鴦。", "必有奸人生戶內，不然朋友害忠良，自衛己身強。"]'),
('959128e7-d948-42e4-9fea-4616df43f476','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 三十五','易靜','唐','唐诗','tang','','[]','城營內，燕鴿忽離城。',32,'全唐诗/poet.tang.54000.json','["城營內，燕鴿忽離城。", "定有火災兼禍起，軍中行尅事叮嚀，禳厭始安平。"]'),
('78dc38de-2027-4be8-a1a3-f1b71be8cc6d','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 三十六','易靜','唐','唐诗','tang','','[]','城營內，水鳥忽啣魚。',51,'全唐诗/poet.tang.54000.json','["城營內，水鳥忽啣魚。", "將至門橋幷臺屋（京本作「樓臺屋上」），必應大水漫街衢，預辦早防虞（京本作「危」）。"]'),
('21c6b30c-115e-4703-a12f-431e9d264041','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 三十七','易靜','唐','唐诗','tang','','[]','鴨聲異，一樣似鵝聲（京本作「鳴」）。',48,'全唐诗/poet.tang.54000.json','["鴨聲異，一樣似鵝聲（京本作「鳴」）。", "鵿有官災幷口舌，速須齋醮慎交爭，方使免灾（京本作「遭」）刑。"]'),
('28a1e7cb-5db7-440c-b1c9-1628255053ac','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 三十八','易靜','唐','唐诗','tang','','[]','鵝與鴨，或解（京本作「忽辨」）作人聲。',82,'全唐诗/poet.tang.54000.json','["鵝與鴨，或解（京本作「忽辨」）作人聲。", "家內必登三品祿（京本作「位」），一門子（辛本、川本作「兒」）姪盡（京本作「更」）享（辛本、川本、京本作「亨」）榮，吉兆自天生。"]'),
('1de6a584-5355-4a3c-a310-947c0a4ed2c4','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 三十九','易靜','唐','唐诗','tang','','[]','城營內，雞母作雄聲。',64,'全唐诗/poet.tang.54000.json','["城營內，雞母作雄聲。", "或在夜鳴家（京本作「皆」）有禍，若門（京本作「聞」）陰暗（京本作「口」）不惺惺，禳（京本作「醮」）謝始安寧。"]'),
('09b8a5c9-b794-40eb-bbd5-32ec5c92b3b5','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 四十','易靜','唐','唐诗','tang','','[]','兵（京本作「軍」）行次，軍上伯勞鳴（京本作「鶯」）。',68,'全唐诗/poet.tang.54000.json','["兵（京本作「軍」）行次，軍上伯勞鳴（京本作「鶯」）。", "兆是軍分爲（京本作「鳴兆是軍分」），兩路兼防禍起察奸情，主將要須（京本作「詳」）明。"]'),
('d672d346-0c0b-4e81-a330-44eada9fabb0','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 四十一','易靜','唐','唐诗','tang','','[]','伯勞鳥，鬧噪在軍前。',60,'全唐诗/poet.tang.54000.json','["伯勞鳥，鬧噪在軍前。", "大禍預（辛本、川本作「須」）知（京本作「將臨」）須早覺，不逾兩月（京本作「日」）事應然，此象理關天。"]'),
('881968c0-6809-4989-aa27-fb2d1809c230','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 四十二','易靜','唐','唐诗','tang','','[]','伯勞鳥，啼叫在軍營。',32,'全唐诗/poet.tang.54000.json','["伯勞鳥，啼叫在軍營。", "南北敵人困我將，東西只是有虛聲，此象甚分明。"]'),
('fc0dca5b-e9df-4b6c-ba2f-339210fe53ba','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 四十三','易靜','唐','唐诗','tang','','[]','城營內，梟鳥噪聲鳴。',41,'全唐诗/poet.tang.54000.json','["城營內，梟鳥噪聲鳴。", "若（京本作「如」）在德鄉分隊伍，如居刑殺有奔驚，預叫使人聽。", "。"]'),
('ae94a565-7f18-49cd-817c-604e66ba5c56','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 四十四','易靜','唐','唐诗','tang','','[]','下營次，衆鳥集羣鳴。',42,'全唐诗/poet.tang.54000.json','["下營次，衆鳥集羣鳴。", "如在德鄉猶自可，若臨刑上血成坑，此兆細（京本作「仔細要」）詳聽。"]'),
('d1d7620b-43a3-47d6-9742-b86d80c9eb74','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 四十五','易靜','唐','唐诗','tang','','[]','兵發日，百（京本作「白」）鳥忽迎軍。',40,'全唐诗/poet.tang.54000.json','["兵發日，百（京本作「白」）鳥忽迎軍。", "此是天威來助順，賊人歸向息邊塵，端的立功勳。"]'),
('c4b3cd3b-1470-49b1-9a2e-033090c12803','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 四十六','易靜','唐','唐诗','tang','','[]','兵行次，衆鳥覆（京本作「巨鳥伏」）於營。',60,'全唐诗/poet.tang.54000.json','["兵行次，衆鳥覆（京本作「巨鳥伏」）於營。", "必有大軍來撃我，皂旗黃杆引師行，禳厭必（辛本作「畢」）登程（京本作「早堪程」）。"]'),
('44b958c1-b9c9-47c7-ab0c-cc076c16329d','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 四十七','易靜','唐','唐诗','tang','','[]','兵行日（京本作「已」），禽乃或（京本作「巨鳥或」）期軍。',50,'全唐诗/poet.tang.54000.json','["兵行日（京本作「已」），禽乃或（京本作「巨鳥或」）期軍。", "將有福神天祐助，必然旬日立功勳，官爵顯超羣。"]'),
('b391f195-12c8-43b9-83b3-f5ba585e35f8','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 四十八','易靜','唐','唐诗','tang','','[]','雞聲鬧（京本作「鬬」），半夜及黃昏。',55,'全唐诗/poet.tang.54000.json','["雞聲鬧（京本作「鬬」），半夜及黃昏。", "半夜精兵行在速，黃昏啼後有回軍，太白報人聞。", "（衆雞主國事，一雞主家咎。", "）。"]'),
('18dc0e0d-e9a1-4de2-9f36-0722dfbfb75a','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 四十九','易靜','唐','唐诗','tang','','[]','燕雀鬧，隣境動（京本作「有」）兵爭。',40,'全唐诗/poet.tang.54000.json','["燕雀鬧，隣境動（京本作「有」）兵爭。", "更有黑頭黃鳥至，腹黃身黑不知名，彼已出精兵。"]'),
('bdbe791d-6d7e-45e1-8068-05ba619f455a','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 五十','易靜','唐','唐诗','tang','','[]','城營內，雞鳥共喧爭。',41,'全唐诗/poet.tang.54000.json','["城營內，雞鳥共喧爭。", "鳥若贏時軍外（京本作「客軍」）勝，雞贏主勝甚分明，偷寨兩般情。"]'),
('28ab71fb-7020-4b3c-9da8-6fa86641f924','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 五十一','易靜','唐','唐诗','tang','','[]','鴉鳴（京本作「鳥」）噪，無故噪城營。',49,'全唐诗/poet.tang.54000.json','["鴉鳴（京本作「鳥」）噪，無故噪城營。", "此是用兵災欲起（京本作「預兆」），人家被噪有凶情，禍發不安寧。"]'),
('e7c0f9d0-6829-4d5d-9586-2ef915a24d68','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 五十二','易靜','唐','唐诗','tang','','[]','城營內，鶩（京本作「鶖」）鳥入其城。',48,'全唐诗/poet.tang.54000.json','["城營內，鶩（京本作「鶖」）鳥入其城。", "定有兵災幷瘴疫，人民饑餓失（京本作「不」）耕耘，修德免災成。"]'),
('1ea7ecfe-2a7e-4621-8fad-99f8fde0cb77','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 五十三','易靜','唐','唐诗','tang','','[]','城營內，黃鳥（京本作「牛」）赤其頭。',52,'全唐诗/poet.tang.54000.json','["城營內，黃鳥（京本作「牛」）赤其頭。", "必有官災三日內，兼防奸叛有因由，熒惑禍堪憂。", "（熒惑禍者，火災也。", "）。"]'),
('cc96e7eb-90e3-494d-99ec-909e162c2944','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 五十四','易靜','唐','唐诗','tang','','[]','城營內，赤鳥入於（京本作「其」）營。',80,'全唐诗/poet.tang.54000.json','["城營內，赤鳥入於（京本作「其」）營。", "更有野鷄併野雉，須防風火與虛驚，皂幟厭爲精。", "（水剋火，故用皂旗。", "如見赤色鳥入軍營，覆將帳幕以皂旗白竿，立帳前三日，厭吉。", "）。"]'),
('d06fc237-8032-44b8-b443-23eb86c1a04b','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 五十五','易靜','唐','唐诗','tang','','[]','城營內，大（京本作「各」）鳥遶其中。',48,'全唐诗/poet.tang.54000.json','["城營內，大（京本作「各」）鳥遶其中。", "不是將軍亡瘴疫，及防外寇損身躬，先兆（京本作「逃」）已呈凶。"]'),
('40fd8d0e-7010-4541-b1d1-cb32841a2139','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 五十六','易靜','唐','唐诗','tang','','[]','城營內，異鳥或（京本作「忽」）然來。',83,'全唐诗/poet.tang.54000.json','["城營內，異鳥或（京本作「忽」）然來。", "好慎外歸（京本作「切忌外方」）刑禍事，不然軍（京本作「君」）將主（辛本、川本、京本作「主將」）身灾，齋醮保無（京本作「年」）乖。", "。"]'),
('d63315ea-0805-4853-b541-184a8a6ecbd0','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 五十七','易靜','唐','唐诗','tang','','[]','城營內，夜靜有鳩鳴。',40,'全唐诗/poet.tang.54000.json','["城營內，夜靜有鳩鳴。", "此是暴兵來逼我，便（京本作「更」）須防備速移營，即得事安寧。"]'),
('eb8c3b5b-e85d-435d-bcf7-fe955559015a','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 五十八','易靜','唐','唐诗','tang','','[]','城營內，衆鳥驀翱翔。',40,'全唐诗/poet.tang.54000.json','["城營內，衆鳥驀翱翔。", "障日翳天成陣起，必知內外將猖狂，仔細可（京本作「好」）消詳。"]'),
('4b335f22-def0-4d34-b90e-a3f7c1a5aba5','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 五十九','易靜','唐','唐诗','tang','','[]','彼軍上，衆鳥泊其中。',40,'全唐诗/poet.tang.54000.json','["彼軍上，衆鳥泊其中。", "定見（京本作「主」）拋營軍敗走，不然潛伏刷營空，仔細審其蹤。"]'),
('077e8330-1d43-458c-acb5-e985f7c003c0','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 六十','易靜','唐','唐诗','tang','','[]','彼軍上，衆鳥鬧紛紛。',32,'全唐诗/poet.tang.54000.json','["彼軍上，衆鳥鬧紛紛。", "聚散只看三五日，不然潛伏擬謀人，防禦始參真。"]'),
('8feac1f5-c02d-4568-babf-26d45eb7cb69','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 六十一','易靜','唐','唐诗','tang','','[]','諸鳴鳥，不利叫三聲。',94,'全唐诗/poet.tang.54000.json','["諸鳴鳥，不利叫三聲。", "一語（辛本、川本、京本作「與」）五聲將快和（京本作「利」），若逢（京本作「過」）此數不堪聽，一任徹更（辛本、川本、京本作「天」）鳴。", "（《易》云：「三多凶。", "」故不利。", "）。"]'),
('7b9f7fd4-fcce-4f05-a833-8a155042274d','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 六十二','易靜','唐','唐诗','tang','','[]','占飛鳥，何事（辛本、川本作「處」）入軍營。',51,'全唐诗/poet.tang.54000.json','["占飛鳥，何事（辛本、川本作「處」）入軍營。", "若在德鄉加喜氣，只從刑地（京本作「上」）是凶聲，百鳥一般聽。"]'),
('5441d3bf-072c-451b-b99f-db490ed51a96','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 六十三','易靜','唐','唐诗','tang','','[]','城營內，鳥散作巢窩。',48,'全唐诗/poet.tang.54000.json','["城營內，鳥散作巢窩。", "其地欲荒堪（京本作「看」）在即，速須移寨莫蹉跎，不去禍來磨（京本作「多」）。"]'),
('50543c95-12de-4583-ac9c-b03782f99534','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 六十四','易靜','唐','唐诗','tang','','[]','攻城次，羣鳥出牆頭。',60,'全唐诗/poet.tang.54000.json','["攻城次，羣鳥出牆頭。", "內有敵圍（京本作「人」）軍欲出，外兵急備整戈矛（首本作「干戈」，此從辛本、川本、京本），用意設良籌。"]'),
('6aaedda3-c95b-464b-a56f-ff3530ab6264','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 六十五','易靜','唐','唐诗','tang','','[]','軍營內，白鳥立旗頭。',32,'全唐诗/poet.tang.54000.json','["軍營內，白鳥立旗頭。", "相聚數枚人總見，將軍遷位作公侯，吉慶喜天休。"]'),
('27bfa10f-510b-452c-8fba-608ac696f538','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 六十六','易靜','唐','唐诗','tang','','[]','鷹與鷂，逐鳥奔吾軍。',54,'全唐诗/poet.tang.54000.json','["鷹與鷂，逐鳥奔吾軍。", "前有暴客（辛本、川本、京本作「兵」）來勢猛，速當准備莫因循，常（京本作「當」）守險關津。"]'),
('19369756-f95b-4417-9328-c1740532436e','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 六十七','易靜','唐','唐诗','tang','','[]','下營次，鳥立樹枝間。',40,'全唐诗/poet.tang.54000.json','["下營次，鳥立樹枝間。", "或在牙旗毛羽掩（京本作「際」），須防敵騎欲相殘，三日內生奸。"]'),
('60c2418d-ed3a-4a00-95e5-223e6d6f0925','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 六十八','易靜','唐','唐诗','tang','','[]','城營內，異鳥入其中。',48,'全唐诗/poet.tang.54000.json','["城營內，異鳥入其中。", "宿處不知人不識，終（京本作「中」）須血染草頭紅，防備有奸（京本作「妨」）通。"]'),
('d8606553-5d41-4dea-800b-1b7e4d1cfe9f','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 六十九','易靜','唐','唐诗','tang','','[]','占烏鳥，結伴後（京本作「盡」）隨軍。',68,'全唐诗/poet.tang.54000.json','["占烏鳥，結伴後（京本作「盡」）隨軍。", "路後（川本、京本作「寇」）敵（京本作「賊」）人應過去，我軍不久却回程，相賀喜安平（京本作「寧」）。", "。"]'),
('a11e0152-4ae5-47c3-8d85-cbfde346f1a4','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 七十','易靜','唐','唐诗','tang','','[]','城營內，巨鳥忽留停。',68,'全唐诗/poet.tang.54000.json','["城營內，巨鳥忽留停。", "防備賊人來索（京本作「兵來搦」）戰，兆當催衆早收（京本作「擁士倒抽」）兵，不去禍還成。", "（京本注：「三日從始吉。", "」）。"]'),
('5b89a1d4-6ecd-478b-9405-9ee224845a81','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 七十一','易靜','唐','唐诗','tang','','[]','城營內，巨鳥至紛紛。',43,'全唐诗/poet.tang.54000.json','["城營內，巨鳥至紛紛。", "地（辛本、川本作「他」）分欲荒應在即，早須排備莫留停，號令速驅兵。"]'),
('fa330d1e-cd91-4c2a-9e69-a80ae879dc33','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 七十二','易靜','唐','唐诗','tang','','[]','臨陣次，聆（京本作「聽」）取鳥聲鳴。',58,'全唐诗/poet.tang.54000.json','["臨陣次，聆（京本作「聽」）取鳥聲鳴。", "若在我軍頭上叫，切忌（川本作「須」）備敵莫（京本「須忌取敵」）交兵，在彼我軍贏。"]'),
('3d597381-73f7-4ffb-ad4b-c3c6a357a771','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 七十三','易靜','唐','唐诗','tang','','[]','臨陣次，鳥向（京本作「鬬」）彼軍飛。',48,'全唐诗/poet.tang.54000.json','["臨陣次，鳥向（京本作「鬬」）彼軍飛。", "便整旗鎗（京本作「旛」）征敵吉，統兵大帥不須疑，天助得其時。"]'),
('e859d3b9-4546-4a23-b233-0e90f64b6d19','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 七十四','易靜','唐','唐诗','tang','','[]','臨陣次，鳥向敵軍來。',60,'全唐诗/poet.tang.54000.json','["臨陣次，鳥向敵軍來。", "一隻一隻（辛本、川本作「雙」）猶可撃（京本作「自可」），或（京本作「忽」）然成陣叫聲哀，勿戰速當迴。"]'),
('e1624cd3-15b9-4c1e-8a8e-62a5697b7c02','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 七十五','易靜','唐','唐诗','tang','','[]','彼軍壘，羣鳥出高飛。',56,'全唐诗/poet.tang.54000.json','["彼軍壘，羣鳥出高飛。", "內有雄兵來突我（京本作「將突出」），其城須（辛本、川本、京本作「難」）下速當回，不悟將身危。"]'),
('712e7411-b104-49de-922f-37b6a1d65435','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 七十六','易靜','唐','唐诗','tang','','[]','城營內，鷄雁（京本作「鷹鷂」）入其中。',83,'全唐诗/poet.tang.54000.json','["城營內，鷄雁（京本作「鷹鷂」）入其中。", "必（京本作「的」）有外（京本作「內」）奸通敵事（京本作「外敵」），忽然搦鳥更爲（京本作「尤」）凶，遇戰豈成（京本作「我無」）功。"]'),
('aa771c12-607c-4402-aaef-c33d5ee10516','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 七十七','易靜','唐','唐诗','tang','','[]','兵發日，烏鳥後隨聲。',32,'全唐诗/poet.tang.54000.json','["兵發日，烏鳥後隨聲。", "此是順天天助我，靈禽預報戰須贏，將士有歡情。"]'),
('4437c697-d3b7-4ad3-8199-9a838acf7ac5','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 七十八','易靜','唐','唐诗','tang','','[]','臨陣次，敵上鳥來衝。',32,'全唐诗/poet.tang.54000.json','["臨陣次，敵上鳥來衝。", "進戰必當傷將士，如從我後却宜攻，賊敗定生擒。"]'),
('4ab009fb-4aa1-453b-9866-135f24afce73','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 七十九','易靜','唐','唐诗','tang','','[]','城營內，夜靜有鳩鳴。',32,'全唐诗/poet.tang.54000.json','["城營內，夜靜有鳩鳴。", "軍欲還鄉宜准備，此爲天意事叮嚀，爲將莫憂驚。"]'),
('605eb193-00b6-4a27-ba68-afb071d33568','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 八十','易靜','唐','唐诗','tang','','[]','下營次，鳥衆聚營中。',32,'全唐诗/poet.tang.54000.json','["下營次，鳥衆聚營中。", "防有外兵來撃我，亦虞諸將起奸凶，急去莫從容。"]'),
('99b60958-bc1d-492a-8514-c0edaccbcbd7','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 八十一','易靜','唐','唐诗','tang','','[]','他陣上，四面有鳥來。',32,'全唐诗/poet.tang.54000.json','["他陣上，四面有鳥來。", "進戰必因傷將士，若從我陣往前摧，生捉將休猜。"]'),
('7eea0c25-bf7e-48ee-8a37-2dea65c04fa3','兵要望江南 占鳥第二十二（京本作「占飛禽第二十」○八十三首） 八十二','易靜','唐','唐诗','tang','','[]','兵發日，旗後有烏鳴。',44,'全唐诗/poet.tang.54000.json','["兵發日，旗後有烏鳴。", "此是天教吾得勝，令禽先報我公卿，將士盡歡欣。", "（以上三首據京本補。", "）。"]'),
('6898ccd2-08e8-4879-9a6a-337b20b32f49','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 一','易靜','唐','唐诗','tang','','[]','戈矛上，忽有火光明。',55,'全唐诗/poet.tang.54000.json','["戈矛上，忽有火光明。", "兆主三軍輕命戰，管須（京本作「取」）交戰我軍贏，青焰不宜兵。", "（火青焰小如鬼火者主兵憂。", "）。"]'),
('964e7a3b-df35-42ab-9e0b-fe8667a3df18','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 二','易靜','唐','唐诗','tang','','[]','帥衣服，無故血痕班。',50,'全唐诗/poet.tang.54000.json','["帥衣服，無故血痕班。", "防有奸人（京本作「備奸謀」）來害己，急須焚毀禍回還，不爾將（京本作「帥」）遭殃。"]'),
('9491ef76-8bd3-468d-ab21-cbd79856989f','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 三','易靜','唐','唐诗','tang','','[]','抽刀劍，血點自然生。',48,'全唐诗/poet.tang.54000.json','["抽刀劍，血點自然生。", "戰有大功須在近，又兼鈴鐸不搖（京本作「撝」）鳴，遇戰（京本作「賊」）必須贏。"]'),
('cae0c2f7-2ac6-4f2d-a68d-4eeea14f3780','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 四','易靜','唐','唐诗','tang','','[]','出軍日，龍現衆人驚。',72,'全唐诗/poet.tang.54000.json','["出軍日，龍現衆人驚。", "急令（京本作「命」）師（京本作「帥」）回休強去（辛本、川本、京本作「進」），若還堅執往前行（京本作「向前營」），枉損馬和兵。"]'),
('0714a01f-d57f-4fe8-9add-37f630da056e','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 五','易靜','唐','唐诗','tang','','[]','將軍帳，無故似人搖。',32,'全唐诗/poet.tang.54000.json','["將軍帳，無故似人搖。", "兆主敵人兵潰散，稍驅兵馬向前交，瓦解與冰消。"]'),
('36b07a5d-7cdf-42ef-ba15-fb127d3b6357','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 六','易靜','唐','唐诗','tang','','[]','將軍帳，床動衆人驚。',55,'全唐诗/poet.tang.54000.json','["將軍帳，床動衆人驚。", "及有血生俱作怪（京本作「怪訝」），若還臨陣禍無輕，身喪掩黃（辛本、川本、京本作「泉」）坰。"]'),
('075eda84-14eb-41b6-bcfb-54943e2028ff','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 七','易靜','唐','唐诗','tang','','[]','將軍袂，驀地起飛騰。',55,'全唐诗/poet.tang.54000.json','["將軍袂，驀地起飛騰。", "上備將軍傾折象（京本作「逝相」），難禳兵衆敵相凌（京本作「急須禳厭敵相臨」），火急整回程。"]'),
('c9ac35d7-c021-44a5-9402-1cce73fbf68b','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 八','易靜','唐','唐诗','tang','','[]','軍纔統（京本作「上」、辛本、川本作「正」），陂澤與郊（京本作「菱」）田。',66,'全唐诗/poet.tang.54000.json','["軍纔統（京本作「上」、辛本、川本作「正」），陂澤與郊（京本作「菱」）田。", "或有石盤從地湧，此爲吉兆可攻前，君聖（京本作「任」）宰臣賢。"]'),
('6ee75e56-cd16-4d12-bfed-963f7ea44d6f','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 九','易靜','唐','唐诗','tang','','[]','安營訖，分布已周圍（京本作「依圓」）。',49,'全唐诗/poet.tang.54000.json','["安營訖，分布已周圍（京本作「依圓」）。", "碎石或生無數目，將軍不久罷兵權，天地（京本作「兆」）應昭然。"]'),
('c0eeba4a-61a7-443f-8cf7-b0f6cc3056d9','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 十','易靜','唐','唐诗','tang','','[]','軍營內，田地陡然高。',58,'全唐诗/poet.tang.54000.json','["軍營內，田地陡然高。", "必得敵人來土貢（京本作「城土地」），開旗贏彼不疲勞，休士少（川本作「止」、京本作「要止」）鎗刀。"]'),
('a0bceb3a-aa16-4a21-ad2f-7f6b0212e059','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 十一','易靜','唐','唐诗','tang','','[]','軍營內，元處是平田。',32,'全唐诗/poet.tang.54000.json','["軍營內，元處是平田。", "地比始臨微似長，將軍官職必陞遷，祿位享遐年。"]'),
('da0ecfef-d89b-4523-9d97-d05259bdf564','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 十二','易靜','唐','唐诗','tang','','[]','軍營內，地上或（京本作「忽」）生黃。',53,'全唐诗/poet.tang.54000.json','["軍營內，地上或（京本作「忽」）生黃。", "兆（首本作「照」，此從京本）得敵人兵與將，凱旋歸國長威光，天下舉宮商。"]'),
('e20ef2c8-f12e-4803-a376-92d60c3647c4','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 十三','易靜','唐','唐诗','tang','','[]','軍營內，氣出地（京本作「應」）中央。',48,'全唐诗/poet.tang.54000.json','["軍營內，氣出地（京本作「應」）中央。", "滿寨便教（京本作「交」）人勿訝，敵人怯戰愈乖張，獲將得封疆。"]'),
('1898d852-51db-4b55-9499-cb4207dea4e2','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 十四','易靜','唐','唐诗','tang','','[]','軍營內，地上水泉生。',40,'全唐诗/poet.tang.54000.json','["軍營內，地上水泉生。", "此是潤軍天助順，須當先敵（京本作「預」）將和兵，捷報入朝京。"]'),
('5659f87d-b6ce-494e-bd00-9d29c3f66f20','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 十五','易靜','唐','唐诗','tang','','[]','軍止歇（京本作「憇」），地上忽生塵。',77,'全唐诗/poet.tang.54000.json','["軍止歇（京本作「憇」），地上忽生塵。", "若有震聲人總怪，三朝（首本作「日」，此從辛本、川本、京本）五日定還軍（京本作「勒還兵」），大戰苦勞心（辛本作「辛」）。"]'),
('5afde480-6b23-4e8c-b0dd-ecb885bf8905','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 十六','易靜','唐','唐诗','tang','','[]','軍寨內，地上血紛紛。',48,'全唐诗/poet.tang.54000.json','["軍寨內，地上血紛紛。", "此象大凶人速避，麻衣布（京本作「履」）帽送將（京本作「三」）軍，休望有功勳。"]'),
('af506e05-e773-44ab-a2bf-26e472c80f02','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 十七','易靜','唐','唐诗','tang','','[]','軍營內，地上艾方（京本作「蒿」）生。',67,'全唐诗/poet.tang.54000.json','["軍營內，地上艾方（京本作「蒿」）生。", "青嫩葉苗人盡識，師徒將捷（京本作「疾」）事非輕，惡疾使人驚。", "（七年之病，求三年之艾，故爲病兆。", "）。"]'),
('b4233f96-29af-4cde-a35d-306789bbbfeb','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 十八','易靜','唐','唐诗','tang','','[]','安營內（京本作「畢」），街（京本作「階」）經（京本作「陘」）已編成。',72,'全唐诗/poet.tang.54000.json','["安營內（京本作「畢」），街（京本作「階」）經（京本作「陘」）已編成。", "地上忽然土裂坼（辛本、川本、京本作「生拆裂」），不如准備速移營，不信大亡傾。"]'),
('a401a1e7-c21a-49a9-a434-25e6a14127dd','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 十九','易靜','唐','唐诗','tang','','[]','營寨內，地陷或（京本作「忽」）成坑。',41,'全唐诗/poet.tang.54000.json','["營寨內，地陷或（京本作「忽」）成坑。", "大陷大虧微小負，俱爲戰敗喪軍情，火速去移營。", "。"]'),
('b2e421cf-f683-4b88-9e7b-34e05769cb52','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 二十','易靜','唐','唐诗','tang','','[]','軍營內，地陷幾（京本作「使」）人驚。',64,'全唐诗/poet.tang.54000.json','["軍營內，地陷幾（京本作「使」）人驚。", "若更似催征（京本作「作聲如」）戰鼓，此般凶象速移營，少（辛本、川本、京本作「稍」）緩禍災成。"]'),
('5d416b55-542b-450f-98b7-e3cdae46c19e','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 二十一','易靜','唐','唐诗','tang','','[]','城（京本作「軍」）營內，半夜忽鍋鳴。',64,'全唐诗/poet.tang.54000.json','["城（京本作「軍」）營內，半夜忽鍋鳴。", "定有暴兵來劫寨，幷（京本作「兼」）防謀反（京本作「叛」）及奸生，列陣後（京本作「遠」）相迎。"]'),
('c180ee89-8b2d-4670-a1a7-e7baf7ffd636','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 二十二','易靜','唐','唐诗','tang','','[]','軍營內，螻蟻滿營生。',50,'全唐诗/poet.tang.54000.json','["軍營內，螻蟻滿營生。", "好備奸謀陰（京本作「陰奸謀」）禍起，兼虞地道入奸（京本作「城」）兵，早備得平平。"]'),
('14ebe32c-c7e4-4220-8ff7-b74685d213c3','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 二十三','易靜','唐','唐诗','tang','','[]','軍邑（京本作「營口」）內，天上忽聞聲。',90,'全唐诗/poet.tang.54000.json','["軍邑（京本作「營口」）內，天上忽聞聲。", "恰是（京本作「似」）雷聲還不是（京本作「似」），多應（京本作「因」）土地見英（京本作「現陰」）靈，不久（京本作「是」）戰兵行（京本作「興」）。"]'),
('5e4cbb24-0058-49e4-aa59-1b3c30f57774','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 二十四','易靜','唐','唐诗','tang','','[]','諸怪現，不可廣傳聞（京本、辛本、川本作「聲」）。',69,'全唐诗/poet.tang.54000.json','["諸怪現，不可廣傳聞（京本、辛本、川本作「聲」）。", "防有奸人知仔細，亦防（京本作「虞」、川本作「如」）彼內有賢英，知我兆原（京本作「元」）情。"]'),
('5088dc28-90b7-42b7-a176-6d2b6c2b1a15','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 二十五','易靜','唐','唐诗','tang','','[]','城（京本作「軍」）營內，晝夜起虛驚。',68,'全唐诗/poet.tang.54000.json','["城（京本作「軍」）營內，晝夜起虛驚。", "營所田（辛本、川本、京本作「舊」）爲神廟地，速移營寨莫居停（京本作「速將移徙莫教停」），不去賊偷營。"]'),
('70bebde3-1151-47fd-82cc-69f1ec3c7716','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 二十六','易靜','唐','唐诗','tang','','[]','城營內，旗鼓自搖鳴。',32,'全唐诗/poet.tang.54000.json','["城營內，旗鼓自搖鳴。", "此是天威來助我，十番出戰九須贏，上將稱其情。"]'),
('e5a2cb3d-891a-45e1-8fb5-536571489b19','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 二十七','易靜','唐','唐诗','tang','','[]','城營內，鼓角急聲雄。',40,'全唐诗/poet.tang.54000.json','["城營內，鼓角急聲雄。", "此是乾坤興廢事，戈矛（京本作「鋋」）大舉禍重重，萬姓失耕農。"]'),
('e5ec6cbb-99d1-4661-a40b-644174158131','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 二十八','易靜','唐','唐诗','tang','','[]','城營內，鼓角自然鳴。',40,'全唐诗/poet.tang.54000.json','["城營內，鼓角自然鳴。", "必有敵（京本作「外」）軍來撃我，急須整備待來兵，着意與交征。"]'),
('6dc20d24-71d5-4c1a-972a-4e23ee9cc34f','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 二十九','易靜','唐','唐诗','tang','','[]','城營內，鼓打不多鳴。',41,'全唐诗/poet.tang.54000.json','["城營內，鼓打不多鳴。", "一丈高懸併九尺，都虞副將驗槌聲，七拜解妖精。", "（各七拜後打。", "）。"]'),
('ab4c6f2a-1c98-4ae3-bbd1-43e624b8bf18','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 三十','易靜','唐','唐诗','tang','','[]','城營內，鼓打不能鳴。',40,'全唐诗/poet.tang.54000.json','["城營內，鼓打不能鳴。", "主將戰輸遭寇擄，早須收拾便回程，不去損其兵。", "（移寨兵得。", "）。"]'),
('29da5319-74c4-4594-b185-2252029431ec','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 三十一','易靜','唐','唐诗','tang','','[]','或晝夜，大將劍刀鳴。',62,'全唐诗/poet.tang.54000.json','["或晝夜，大將劍刀鳴。", "刺客奸人在庭（京本作「應在」）近，急須搜捉莫教停，不信（辛本、川本作「便見」）血光成（京本作「成坑」）。"]'),
('ade81606-1b07-4802-aba1-5aaa2c47c665','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 三十二','易靜','唐','唐诗','tang','','[]','營與邑，井沸聞其（京本作「鼎沸忽聞」）聲。',51,'全唐诗/poet.tang.54000.json','["營與邑，井沸聞其（京本作「鼎沸忽聞」）聲。", "或溢水泉皆是敗，更還（京本作「逢」）龍見也同情，覩此便移營。"]'),
('b947b386-1aa8-430f-9fd1-3bbb9ec03a81','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 三十三','易靜','唐','唐诗','tang','','[]','城營內，獨鼓（辛本、川本作「角」）自然（京本作「能」）鳴。',51,'全唐诗/poet.tang.54000.json','["城營內，獨鼓（辛本、川本作「角」）自然（京本作「能」）鳴。", "此兆敵人來劫我，隨鳴火急整精兵，遠探向前征。"]'),
('f7b74ac2-dd8a-4be3-8da0-95bb79a3cee7','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 三十四','易靜','唐','唐诗','tang','','[]','城營角，吹聲（辛本、川本、京本作「了」）遠而微。',73,'全唐诗/poet.tang.54000.json','["城營角，吹聲（辛本、川本、京本作「了」）遠而微。", "韻斷聲長（京本作「哀」）人怪訝，兆當我衆有災危，固守免傾（首本作「灾」，茲從辛本、川本、京本）頹。"]'),
('e5a11d7c-456e-4c0f-9a0c-b6dc1aaad617','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 三十五','易靜','唐','唐诗','tang','','[]','金鼙鼓，自裂七分餘。',62,'全唐诗/poet.tang.54000.json','["金鼙鼓，自裂七分餘。", "此是三（京本作「將」）軍囚沒兆（京本作「死」），速當求解醮移居，不可侈（辛本、川本、京本作「恣」）行誅。"]'),
('93411893-7010-44db-acf4-1c3847a50dae','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 三十六','易靜','唐','唐诗','tang','','[]','鎗旗戟，無故倒交加。',54,'全唐诗/poet.tang.54000.json','["鎗旗戟，無故倒交加。", "象主病災如臥草，四門宰犬瀝田沙，子候（京本作「後」）設施佳。", "（子時以犬血瀝四門地上。", "）。"]'),
('69d0f7a8-0193-46d3-ac5c-2e106aec0c1f','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 三十七','易靜','唐','唐诗','tang','','[]','鈴與鐸，風息自然鳴。',46,'全唐诗/poet.tang.54000.json','["鈴與鐸，風息自然鳴。", "鼓角雄聲音振地，必須勝敵悅軍行（辛本、川本、京本作「情」），擁衆返回程。"]'),
('512c4588-f377-4dcb-b36c-6c2b3505373c','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 三十八','易靜','唐','唐诗','tang','','[]','或晝夜，飲宴在其中。',68,'全唐诗/poet.tang.54000.json','["或晝夜，飲宴在其中。", "驀地盞鳴人總訝，賊（辛本、川本、京本作「劫」）人已起影無蹤（辛本、川本作「意忙匆」、京本作「盡忙匆」），急遣將邀衝。"]'),
('2e0c6be3-6e21-49e1-8f17-cef589e63ea4','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 三十九','易靜','唐','唐诗','tang','','[]','杯器內，清水忽然紅。',32,'全唐诗/poet.tang.54000.json','["杯器內，清水忽然紅。", "有似血來人盡訝，此爲祥瑞立奇功，戰急總無凶。"]'),
('de61769c-454b-4903-af7a-c2c35554ccc4','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 四十','易靜','唐','唐诗','tang','','[]','軍營內，戰馬忽然嘶。',32,'全唐诗/poet.tang.54000.json','["軍營內，戰馬忽然嘶。", "跑擁搖身非時亂，賊兵降伏要相欺，祭享上天知。"]'),
('61d99706-64ee-453d-b608-ba95e2773237','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 四十一','易靜','唐','唐诗','tang','','[]','軍器甲，夜後更生光。',40,'全唐诗/poet.tang.55000.json','["軍器甲，夜後更生光。", "折毀月形方上窖，離營百步正相當，遠去更宜長（辛本作「良」）。"]'),
('bc205dc8-d6a1-447c-8a75-ede3aa0a308d','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 四十二','易靜','唐','唐诗','tang','','[]','風不起，旗號自飛揚。',33,'全唐诗/poet.tang.55000.json','["風不起，旗號自飛揚。", "前指敵軍幷陣次，必當我勝用心腸，得勝早回鄉。", "。"]'),
('c7f8e8fb-a3e3-41f2-8743-e0a4c43ecaf4','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 四十三','易靜','唐','唐诗','tang','','[]','臨陣次，馬匹忽然驚。',32,'全唐诗/poet.tang.55000.json','["臨陣次，馬匹忽然驚。", "欲悚欲慊多退縮，牽纏不動自遲情，回首免軍驚。"]'),
('0fa0d630-f4c6-4576-9ee7-3373ea934bee','兵要望江南 占怪第二十三（京本作「占怪象第十四」○四十四首） 四十四','易靜','唐','唐诗','tang','','[]','占怪異，說與衆賢知。',32,'全唐诗/poet.tang.55000.json','["占怪異，說與衆賢知。", "正是一人行踏處，當逢奇異怪逢爲，兵衆豈無知。"]'),
('d33b1c7f-a9f1-438a-b37f-429e330b6ae4','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 一','易靜','唐','唐诗','tang','','[]','禳厭法，其理事情深。',32,'全唐诗/poet.tang.55000.json','["禳厭法，其理事情深。", "首異諸般奇異怪，或逢要日要時辰，厭法要精明。"]'),
('85f1fe88-ff7e-40d7-be5c-8645400e1fe3','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 二','易靜','唐','唐诗','tang','','[]','軍行日，春正及春分。',40,'全唐诗/poet.tang.55000.json','["軍行日，春正及春分。", "須用長鎗前列（京本作「作」）勝，次排弓弩在中軍，決勝定須聞。"]'),
('a9dc21ce-37b5-47ba-88b2-dd1e51d1fddc','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 三','易靜','唐','唐诗','tang','','[]','軍行日，立夏至皆同。',32,'全唐诗/poet.tang.55000.json','["軍行日，立夏至皆同。", "令下三軍諸將士，須排戈戟作先鋒，將士定英雄。"]'),
('a07ad083-e681-42d9-94e7-16989ec4453c','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 四','易靜','唐','唐诗','tang','','[]','軍行日，秋始與秋分。',40,'全唐诗/poet.tang.55000.json','["軍行日，秋始與秋分。", "金氣旺時須要順，先持弓矢向前行（京本作「存」），得勝遠方聞。"]'),
('7427dea3-1bc8-4d1c-a0f5-e7b101052464','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 五','易靜','唐','唐诗','tang','','[]','軍行日，凜冽正當冬。',32,'全唐诗/poet.tang.55000.json','["軍行日，凜冽正當冬。", "得氣一陽回一候，首令刀劍向前衝，舉戰得全功。"]'),
('a2ba6275-f2aa-47c8-b7ec-4684be611c97','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 六','易靜','唐','唐诗','tang','','[]','東方陣，角姓七人從。',40,'全唐诗/poet.tang.55000.json','["東方陣，角姓七人從。", "純着青衣青隊伏，青旗青（京本作「驄」）馬作先鋒，木陣號青龍。"]'),
('1902148b-50aa-4f0c-aa6a-ad88121093c4','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 七','易靜','唐','唐诗','tang','','[]','南方陣，徴姓最爲雄。',32,'全唐诗/poet.tang.55000.json','["南方陣，徴姓最爲雄。", "七箇赤衣乘赤馬，赤旗招動號長空，朱雀陣先鋒。"]'),
('0a837ee5-c2ac-44aa-a7ca-c8b6f86d59b1','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 八','易靜','唐','唐诗','tang','','[]','西方陣，商姓白衣兵。',57,'全唐诗/poet.tang.55000.json','["西方陣，商姓白衣兵。", "七箇健兒乘白馬，白旗獨角（京本作「却」）引前程（京本作「行」），爲首向先行（京本作「前征」）。"]'),
('28fb8b32-3882-4969-bd3f-d113d1448de4','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 九','易靜','唐','唐诗','tang','','[]','北方陣，羽姓顯然明。',32,'全唐诗/poet.tang.55000.json','["北方陣，羽姓顯然明。", "騅馬烏衣如北斗，黑旗玄武隊前行，賊將勢摧傾。"]'),
('1c2e75bc-f670-415c-a78d-56a1798a0133','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 十','易靜','唐','唐诗','tang','','[]','中央陣，宮姓要黃衣。',32,'全唐诗/poet.tang.55000.json','["中央陣，宮姓要黃衣。", "七箇黃旗黃色馬，勾陣大將助堪依，敵國定橫屍。"]'),
('7eb9b2bd-e6fa-45d8-b548-3d7e229d558b','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 十一','易靜','唐','唐诗','tang','','[]','凡行陣，甲子甲辰申（京本作「寅辰」）。',59,'全唐诗/poet.tang.55000.json','["凡行陣，甲子甲辰申（京本作「寅辰」）。", "三箇甲頭旬日內，前驅（辛本、川本作「祛」、京本作「行」）天馬擺令真，整頓要辛勤。"]'),
('97ecde76-d131-4378-bdae-75b87cb5db05','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 十二','易靜','唐','唐诗','tang','','[]','凡行陣，甲午甲寅（京本作「申」）旬。',49,'全唐诗/poet.tang.55000.json','["凡行陣，甲午甲寅（京本作「申」）旬。", "甲戌都來爲一處，當時（京本作「持」）刀劍在前行，其陣勒來兵。", "。"]'),
('529d7a1e-91e6-4c71-aad9-6f174b976c4b','兵要望江南 禳厭第二十四（京本作「占厭禳第十九」○十三首） 十三','易靜','唐','唐诗','tang','','[]','揚兵吉（京本作「禳兵告」），頓在（辛本、川本、京本作「須向」）九天方。',97,'全唐诗/poet.tang.55000.json','["揚兵吉（京本作「禳兵告」），頓在（辛本、川本、京本作「須向」）九天方。", "諸惡不成加喜氣。", "更宜上將見恩光，安得（京本作「將」）有乖張。", "（《太乙式》云：「九天之上，可以陳兵，九地之下，可以潛伏。", "」）。"]'),
('0705a821-ea3a-41f1-80e2-bdba7bf0e1ed','兵要望江南 占夢第二十五（京本列第十三○九首） 一','易靜','唐','唐诗','tang','','[]','凡占夢，本出自微茫。',32,'全唐诗/poet.tang.55000.json','["凡占夢，本出自微茫。", "得一夢來三事應，方知凶吉爲君張，神魄預知祥。"]'),
('2e4ac0fd-bbcc-412e-976d-67e477aacb3f','兵要望江南 占夢第二十五（京本列第十三○九首） 二','易靜','唐','唐诗','tang','','[]','將軍夢，雲外見飛龍。',43,'全唐诗/poet.tang.55000.json','["將軍夢，雲外見飛龍。", "急去戰時須獲捷，不過三（辛本、川本作「百」）日帝王封，位顯立奇功。"]'),
('4db9fa18-e023-462e-9cf9-c56bcc3abc4d','兵要望江南 占夢第二十五（京本列第十三○九首） 三','易靜','唐','唐诗','tang','','[]','將軍夢，魚變作蛟龍。',32,'全唐诗/poet.tang.55000.json','["將軍夢，魚變作蛟龍。", "百戰自然皆百勝，相敵來捉必無凶，大將職加封。"]'),
('7a428e38-c7a5-472b-8568-8901400fffbf','兵要望江南 占夢第二十五（京本列第十三○九首） 四','易靜','唐','唐诗','tang','','[]','將軍夢，打（辛本、川本、京本作「大」）鼓大聲鳴。',62,'全唐诗/poet.tang.55000.json','["將軍夢，打（辛本、川本、京本作「大」）鼓大聲鳴。", "小鼓小聲（京本作「鳴」）軍小勝，不鳴固守莫先（京本作「前」）征，勝負取其聲。"]'),
('52548074-cf60-492a-9dfa-bc27d332afc0','兵要望江南 占夢第二十五（京本列第十三○九首） 五','易靜','唐','唐诗','tang','','[]','將軍夢，夢得大魚形。',54,'全唐诗/poet.tang.55000.json','["將軍夢，夢得大魚形。", "若得小魚軍（京本作「兵」）小勝，電光霹靂主軍鳴（辛本、川本、京本作「驚」），此象最爲靈。"]'),
('b79196ab-fc6e-4213-8d3c-6f5e37287d83','兵要望江南 占夢第二十五（京本列第十三○九首） 六','易靜','唐','唐诗','tang','','[]','將軍夢，見水及（京本作「夢見汲」）波濤。',66,'全唐诗/poet.tang.55000.json','["將軍夢，見水及（京本作「夢見汲」）波濤。", "或（京本作「忽」）與敵人相角（京本作「爭」）競，須來挑（京本作「排」）戰莫輕交，堅守我門橋。"]'),
('3907a25d-5ee7-40e5-acdf-b8db4d2b48e0','兵要望江南 占夢第二十五（京本列第十三○九首） 七','易靜','唐','唐诗','tang','','[]','將軍夢，天上作雷鳴。',92,'全唐诗/poet.tang.55000.json','["將軍夢，天上作雷鳴。", "破敵勤（辛本、川本、京本作「擒」）王有（京本作「看」）此兆，無（京本作「不」）拘明（辛本、川本、京本作「月」）暗與陰晴，擁（京本作「勇」）士向前程（京本作「征」）。"]'),
('4cd9d85f-2955-40e5-8391-1ed40da76e9f','兵要望江南 占夢第二十五（京本列第十三○九首） 八','易靜','唐','唐诗','tang','','[]','將軍夢，身涉大高山。',41,'全唐诗/poet.tang.55000.json','["將軍夢，身涉大高山。", "遇戰必贏功顯著，相逢敵戰（京本作「鬬敵」）急攻殘，莫放片時間。"]'),
('1bef96d4-a7d1-4fce-91ee-20fd838cac5b','兵要望江南 占夢第二十五（京本列第十三○九首） 九','易靜','唐','唐诗','tang','','[]','將軍夢，夢見大舟船。',45,'全唐诗/poet.tang.55000.json','["將軍夢，夢見大舟船。", "順水順風帆幔順，戰之獲捷獨爲先，快樂（辛本、川本作「不爾」）似神仙。", "。"]'),
('d1631f0e-7f92-4aba-ab8b-5384e54563a9','兵要望江南 《周易》占候第二十六（三十七首） 一','易靜','唐','唐诗','tang','','[]','聖人造，作《易》變爻辭。',34,'全唐诗/poet.tang.55000.json','["聖人造，作《易》變爻辭。", "擲卦要知凶與吉，切須盥手動占儀，懇意合天機。"]'),
('5f61f8d6-62c5-4c39-b779-db8919f71783','兵要望江南 《周易》占候第二十六（三十七首） 二','易靜','唐','唐诗','tang','','[]','凡占《易》，動靜卦爻裝。',34,'全唐诗/poet.tang.55000.json','["凡占《易》，動靜卦爻裝。", "先辨剛柔分彼我，更分主客要知當，決勝自昭彰。"]'),
('190bee7c-523d-49b2-ad8d-62d4c7f62989','兵要望江南 《周易》占候第二十六（三十七首） 三','易靜','唐','唐诗','tang','','[]','論主客，後舉我爲尊。',43,'全唐诗/poet.tang.55000.json','["論主客，後舉我爲尊。", "旗底（辛本、川本作「低」）住坐並爲主，先身行者號爲賓，此理甚分明。"]'),
('b15bd5c3-1751-4168-8188-a769ae993c10','兵要望江南 《周易》占候第二十六（三十七首） 四','易靜','唐','唐诗','tang','','[]','入他國，我即論爲（辛本、川本作「其」）賓。',65,'全唐诗/poet.tang.55000.json','["入他國，我即論爲（辛本、川本作「其」）賓。", "若是他來攻我寨，我爲主（辛本、川本作「賓」）者汝爲賓（辛本、川本作「尊」），此理合天文。"]'),
('a29d7015-b8e2-4609-a997-eb5d1c3f8b17','兵要望江南 《周易》占候第二十六（三十七首） 五','易靜','唐','唐诗','tang','','[]','凡占《易》，先論六親方。',48,'全唐诗/poet.tang.55000.json','["凡占《易》，先論六親方。", "大煞彼鄉（辛本、川本作「大謹五鄉」）比和尅，應殺世主總漂揚，官鬼子孫量。"]'),
('608132b3-d5c4-45b3-9699-c79941ea4ea9','兵要望江南 《周易》占候第二十六（三十七首） 六','易靜','唐','唐诗','tang','','[]','彼與我，子鬼取爲先。',43,'全唐诗/poet.tang.55000.json','["彼與我，子鬼取爲先。", "子孫旺相吾軍勝，鬼爻囚死彼（辛本、川本作「復」）遭愆，反此亦如然。"]'),
('9a770a7c-4e5f-445a-8b25-404c31ae5556','兵要望江南 《周易》占候第二十六（三十七首） 七','易靜','唐','唐诗','tang','','[]','世爲我，應象便爲他。',32,'全唐诗/poet.tang.55000.json','["世爲我，應象便爲他。", "世尅應兮當我勝，應爻尅世我無家，比者各安家。"]'),
('48d735df-675d-43b9-923a-e850afeddc47','兵要望江南 《周易》占候第二十六（三十七首） 八','易靜','唐','唐诗','tang','','[]','內卦我，外卦屬他邦。',55,'全唐诗/poet.tang.55000.json','["內卦我，外卦屬他邦。", "內尅外時無大損（辛本、川本作「攢捷」），子孫發動急旋（辛本、川本作「施」）張，大戰我軍強。"]'),
('c9d6490e-b5c5-4887-9c2c-2ae9d06ce155','兵要望江南 《周易》占候第二十六（三十七首） 九','易靜','唐','唐诗','tang','','[]','官爻動，却在內爻興。',79,'全唐诗/poet.tang.55000.json','["官爻動，却在內爻興。", "若在子孫傍發動，未（辛本、川本作「雖」）來攻我不曾贏，彼敗怎回程？", "（凡占戰，世爲我，應爲他；內爲我，外爲他；子爲我，官爲他；比和者吉。", "）。"]'),
('7d7fdcfd-0d98-42ec-98ff-42c289890500','兵要望江南 《周易》占候第二十六（三十七首） 十','易靜','唐','唐诗','tang','','[]','子孫動，有氣甚分明。',32,'全唐诗/poet.tang.55000.json','["子孫動，有氣甚分明。", "我若撃他全獲捷，他來攻我敗無門，我將立功勳。"]'),
('386b2189-46c8-4f7c-a07d-da6e6afdc75e','兵要望江南 《周易》占候第二十六（三十七首） 十一','易靜','唐','唐诗','tang','','[]','占賊信，官鬼上二爻。',43,'全唐诗/poet.tang.55000.json','["占賊信，官鬼上二爻。", "無氣動居爻五六，雖然已動不相遭，賊衆自（辛本、川本作「再」）回巢。"]'),
('398e0dca-8385-4023-ac6a-69c76392da6a','兵要望江南 《周易》占候第二十六（三十七首） 十二','易靜','唐','唐诗','tang','','[]','占賊信，鬼發內三中。',32,'全唐诗/poet.tang.55000.json','["占賊信，鬼發內三中。", "或是官爻生有氣，賊軍來速在逡巡，急備點三軍。"]'),
('028685bf-a6dd-4020-87b6-aaed2c15bff6','兵要望江南 《周易》占候第二十六（三十七首） 十三','易靜','唐','唐诗','tang','','[]','占賊興，卦裏子孫興。',33,'全唐诗/poet.tang.55000.json','["占賊興，卦裏子孫興。", "六位官爻全不見，話中空自說來情，不見信和音。", "。"]'),
('f9b8d9ee-4fe8-4057-92bb-7c16b14c1df4','兵要望江南 《周易》占候第二十六（三十七首） 十四','易靜','唐','唐诗','tang','','[]','占賊信，應動是（辛本、川本作「世」）爲他。',54,'全唐诗/poet.tang.55000.json','["占賊信，應動是（辛本、川本作「世」）爲他。", "其賊來時須（辛本、川本作「雖」）是到，到時攻我將須拿，來將喪黃沙。"]'),
('7d7bd016-d91c-468b-9d82-3457da8c8cef','兵要望江南 《周易》占候第二十六（三十七首） 十五','易靜','唐','唐诗','tang','','[]','占賊信，兄弟動如何。',43,'全唐诗/poet.tang.55000.json','["占賊信，兄弟動如何。", "三四爻中他（辛本、川本作「我」）尅我，逡巡來到不蹉跎，到後却安和。"]'),
('af8033ed-46b2-41a0-8bac-8f9dc246be2f','兵要望江南 《周易》占候第二十六（三十七首） 十六','易靜','唐','唐诗','tang','','[]','占賊信，父母主文書。',32,'全唐诗/poet.tang.55000.json','["占賊信，父母主文書。", "若遇吉神天喜位，朝廷加祿永安和，賊智設機多。"]'),
('98a1e9b0-1385-409b-976c-ec9a46cd8588','兵要望江南 《周易》占候第二十六（三十七首） 十七','易靜','唐','唐诗','tang','','[]','占賊信，卦象動妻財。',32,'全唐诗/poet.tang.55000.json','["占賊信，卦象動妻財。", "天喜來交爻已動，若來相戰見兵乖，我將得和諧。"]'),
('fd9bebde-0a00-4127-8ea6-9a7913f002c5','兵要望江南 《周易》占候第二十六（三十七首） 十八','易靜','唐','唐诗','tang','','[]','凡占《易》，奇偶與剛柔。',42,'全唐诗/poet.tang.55000.json','["凡占《易》，奇偶與剛柔。", "陽爻爲九陰爻六，陽爻多衆我須周，柔少我（辛本作「彼」）軍憂。"]'),
('d206014d-5ebc-4658-bd6e-267b9ff4a01e','兵要望江南 《周易》占候第二十六（三十七首） 十九','易靜','唐','唐诗','tang','','[]','入他境，我却用官爻。',32,'全唐诗/poet.tang.55000.json','["入他境，我却用官爻。", "官旺子孫休我勝，若煞反此少功勞，術士自詳消。"]'),
('1b196b0e-471a-4bb6-bc0a-ffcfe5f51c7d','兵要望江南 《周易》占候第二十六（三十七首） 二十','易靜','唐','唐诗','tang','','[]','入他國，大要看財鄉。',32,'全唐诗/poet.tang.55000.json','["入他國，大要看財鄉。", "子動才興皆出現，處處獲捷有衣糧，飽賞喜還鄉。"]'),
('22e56ca0-3713-4cae-854f-485dd69f9e2d','兵要望江南 《周易》占候第二十六（三十七首） 二十一','易靜','唐','唐诗','tang','','[]','爻上見，無鬼又無孫。',32,'全唐诗/poet.tang.55000.json','["爻上見，無鬼又無孫。", "但有應方幷世上，以應爲他我世軍，此克定軍情。"]'),
('1bc0a73f-7360-4d51-9a87-3d5ccc0fcdd6','兵要望江南 《周易》占候第二十六（三十七首） 二十二','易靜','唐','唐诗','tang','','[]','世爻旺，若尅應爻宮。',32,'全唐诗/poet.tang.55000.json','["世爻旺，若尅應爻宮。", "速便提兵前去吉，自知天助喜重重，主將得奇功。"]'),
('31ee1d26-d411-4969-b35f-280836a0bbda','兵要望江南 《周易》占候第二十六（三十七首） 二十三','易靜','唐','唐诗','tang','','[]','兄獨發，有寇伏埋藏。',43,'全唐诗/poet.tang.55000.json','["兄獨發，有寇伏埋藏。", "且莫提兵行遠路，急行前必有驚惶，不信見灾（辛本、川本作「遭」）殃。"]'),
('7941d36d-53ea-45a4-ac21-76736428c7f1','兵要望江南 《周易》占候第二十六（三十七首） 二十四','易靜','唐','唐诗','tang','','[]','財（辛本、川本作「賊」）爻動，便是我軍糧。',82,'全唐诗/poet.tang.55000.json','["財（辛本、川本作「賊」）爻動，便是我軍糧。", "出國尋糧我軍旺（辛本、川本作「財旺發」），無財難（辛本、川本作「雖」）旺恐饑荒，仔細好推詳（辛本、川本作「半敵遇空亡」）。"]'),
('58540232-e9b2-42bf-b475-5fe123ca2ab4','兵要望江南 《周易》占候第二十六（三十七首） 二十五','易靜','唐','唐诗','tang','','[]','世若墓，我軍且默（辛本、川本作「執」）屯。',43,'全唐诗/poet.tang.55000.json','["世若墓，我軍且默（辛本、川本作「執」）屯。", "應爻被尅休囚位，來軍必敗損人兵，我衆喜忻忻。"]'),
('70518158-d441-49fa-8a13-745a6dbb5a39','兵要望江南 《周易》占候第二十六（三十七首） 二十六','易靜','唐','唐诗','tang','','[]','官臨火，尅我應（辛本、川本作「慮」）偷營。',54,'全唐诗/poet.tang.55000.json','["官臨火，尅我應（辛本、川本作「慮」）偷營。", "水立官鄉休立寨，土臨官鬼四方兵，不可（辛本、川本作「一」）亂提兵。"]'),
('a550ebc2-3d1b-4bfe-b308-bc24fb591959','兵要望江南 《周易》占候第二十六（三十七首） 二十七','易靜','唐','唐诗','tang','','[]','木官（辛本、川本作「宮」）旺，必定有雄兵。',54,'全唐诗/poet.tang.55000.json','["木官（辛本、川本作「宮」）旺，必定有雄兵。", "金火不宜臨世應，兩家流血定交爭，火鬼劫吾營（辛本、川本作「軍」）。"]'),
('fe16ed50-cbf1-4234-b238-7de83205220b','兵要望江南 《周易》占候第二十六（三十七首） 二十八','易靜','唐','唐诗','tang','','[]','兄爻尅，防奪我軍糧。',45,'全唐诗/poet.tang.55000.json','["兄爻尅，防奪我軍糧。", "水動舟車火營寨，文書父母合穹蒼（辛本、川本作「倉場」），嚴令下兒郎。", "。"]'),
('3bb78b76-02f3-4844-866f-3cac50c3387d','兵要望江南 《周易》占候第二十六（三十七首） 二十九','易靜','唐','唐诗','tang','','[]','爻辭位，九六號陰陽。',32,'全唐诗/poet.tang.55000.json','["爻辭位，九六號陰陽。", "中半自然皆相守，比和世應兩無傷，各自主刀鎗。"]'),
('7d4ab225-21bd-45df-946b-afc513a75078','兵要望江南 《周易》占候第二十六（三十七首） 三十','易靜','唐','唐诗','tang','','[]','外卦靜，內動見兄爻。',32,'全唐诗/poet.tang.55000.json','["外卦靜，內動見兄爻。", "空亡臨象虛驚事，更兼不定事無毫，固守且平交。"]'),
('476c9956-3aed-4176-bf85-25f295a5a850','兵要望江南 《周易》占候第二十六（三十七首） 三十一','易靜','唐','唐诗','tang','','[]','歸魂卦，三四動爻凶。',43,'全唐诗/poet.tang.55000.json','["歸魂卦，三四動爻凶。", "若制鬼爻凶轉遂（辛本、川本作「隊」），若逢天喜好回軍，不久却抽兵。"]'),
('d8e98acd-9bb1-43fd-8a2c-665a18197ae4','兵要望江南 《周易》占候第二十六（三十七首） 三十二','易靜','唐','唐诗','tang','','[]','《易》之位，六親與五鄉。',34,'全唐诗/poet.tang.55000.json','["《易》之位，六親與五鄉。", "外卦世爻子孫旺，三般有氣我無傷，勿要落空亡。"]'),
('e369aeed-3073-48ad-958c-34248a93e989','兵要望江南 《周易》占候第二十六（三十七首） 三十三','易靜','唐','唐诗','tang','','[]','凡占課，內動外平安。',43,'全唐诗/poet.tang.55000.json','["凡占課，內動外平安。", "動爻無鬼虛驚恐，內爻凶（辛本、川本作「兄」）動稔凶張，術者細參詳。"]'),
('75590a5b-8562-4f4a-a9a8-2cd591c7fdc7','兵要望江南 《周易》占候第二十六（三十七首） 三十四','易靜','唐','唐诗','tang','','[]','外卦動，內卦動興爻。',32,'全唐诗/poet.tang.55000.json','["外卦動，內卦動興爻。", "內外動爻俱動發，若然我戰動鎗刀，大戰殺聲高。"]'),
('961343e1-4c64-451e-8c6d-3ed1a08f37f6','兵要望江南 《周易》占候第二十六（三十七首） 三十五','易靜','唐','唐诗','tang','','[]','鬼爻旺，三四動交爻。',32,'全唐诗/poet.tang.55000.json','["鬼爻旺，三四動交爻。", "定主賊兵侵我陣，急須回首莫相交，動則我軍咷。"]'),
('cffdcd13-c31f-477b-b726-a32f14215639','兵要望江南 《周易》占候第二十六（三十七首） 三十六','易靜','唐','唐诗','tang','','[]','四德用，其課我軍強。',43,'全唐诗/poet.tang.55000.json','["四德用，其課我軍強。", "春占雷巽寅卯木，夏火巳午得離鄉，此理要知詳（辛本、川本作「當」）。"]'),
('8dcb65a5-5c66-44c1-8a54-c19fc142ca49','兵要望江南 《周易》占候第二十六（三十七首） 三十七','易靜','唐','唐诗','tang','','[]','秋乾位，申酉喜逢臨（辛本、川本作「相逢」）。',56,'全唐诗/poet.tang.55000.json','["秋乾位，申酉喜逢臨（辛本、川本作「相逢」）。", "三冬亥子坎宮卦，土旺用事艮和坤，丑未辰戌冲（辛本、川本作「辰中」）。"]'),
('f6ed8fc8-5dea-4bbd-b058-25b2c8b6feef','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 一','易靜','唐','唐诗','tang','','[]','太乙式，逆順論陰陽。',43,'全唐诗/poet.tang.55000.json','["太乙式，逆順論陰陽。", "五日六時成一局，八門九曜遂（辛本、川本作「逐」）時當，凶吉利門方。"]'),
('c78ca668-24ae-447f-9bb9-0573fd79b736','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 二','易靜','唐','唐诗','tang','','[]','爲術者，太乙式（辛本、川本作「遁」）須知。',43,'全唐诗/poet.tang.55000.json','["爲術者，太乙式（辛本、川本作「遁」）須知。", "起造凶喪須得此，出行蒞任動兵機，用者得便宜。"]'),
('ce0e7d12-750f-4d4d-9bfa-fe494a0a40e3','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 三','易靜','唐','唐诗','tang','','[]','出軍日，出門向何方。',41,'全唐诗/poet.tang.55000.json','["出軍日，出門向何方。", "開休生門三路吉（川本作「吉路」），一奇臨合自然良，主將得安康。"]'),
('6aed96a1-1366-4b89-a56f-77cf3b2ab346','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 四','易靜','唐','唐诗','tang','','[]','乙丙丁，名曰是三奇。',43,'全唐诗/poet.tang.55000.json','["乙丙丁，名曰是三奇。", "天上若臨三吉路，自然神助合天機，任（辛本、川本作「恁」）往莫憂疑。"]'),
('62b9c682-13e2-40df-a2fa-477a60e2bfc3','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 五','易靜','唐','唐诗','tang','','[]','九星位，當位（辛本、川本作「住」）八宮方。',44,'全唐诗/poet.tang.55000.json','["九星位，當位（辛本、川本作「住」）八宮方。", "惟有中官寄在二，術人運式細消詳，依此我軍強。", "。"]'),
('f0bb7f76-0a5f-4a3f-8929-fb1d9be04d9a','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 六','易靜','唐','唐诗','tang','','[]','甲加丙，龍反首（京本、川本作「首反」）爲先。',44,'全唐诗/poet.tang.55000.json','["甲加丙，龍反首（京本、川本作「首反」）爲先。", "丙甲相臨鳥跌穴，時中得此自然全，得勝凱歌旋。"]'),
('9e9f778b-594f-426c-bd9f-c99b88aed798','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 七','易靜','唐','唐诗','tang','','[]','太乙遁，月奇合生門。',32,'全唐诗/poet.tang.55000.json','["太乙遁，月奇合生門。", "下有六丁加臨者，此時攝政顯公卿，上策進書呈。"]'),
('75b878c6-4a34-4d06-bd01-a59af9866094','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 八','易靜','唐','唐诗','tang','','[]','開門合，日奇六七（辛本、川本作「乙」）方。',51,'全唐诗/poet.tang.55000.json','["開門合，日奇六七（辛本、川本作「乙」）方。", "此爲地遁安營吉，藏兵設伏免憂殃，所獻日精長（川本作「良」）。"]'),
('76ff17ac-3a3a-426a-92e9-c6a60a6fadf4','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 九','易靜','唐','唐诗','tang','','[]','星奇合，休門有蔭人。',32,'全唐诗/poet.tang.55000.json','["星奇合，休門有蔭人。", "舉善薦賢求猛將，和仇說敵哲明言，此法合先賢。"]'),
('20ccb075-bd23-4a9e-a0a9-648a5f252e22','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 十','易靜','唐','唐诗','tang','','[]','月奇合，生門見九天。',79,'全唐诗/poet.tang.55000.json','["月奇合，生門見九天。", "祭禱神祇行聖術，布仇（辛本、川本作「籌」）作法此間言，神遁不虛傳。", "（生門月奇合，得九天所臨之位，謂「神遁」。", "宜作布籌，行聖術，祭神祇。", "）。"]'),
('36a07fe4-4781-4c5a-af95-94472099ad48','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 十一','易靜','唐','唐诗','tang','','[]','日奇合，九地見開門。',32,'全唐诗/poet.tang.55000.json','["日奇合，九地見開門。", "探審賊機揚虛陣，遙虛設假利偷營，鬼遁隱神兵。"]'),
('482d8301-b0ef-4b3c-93e2-c17dae3a6af4','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 十二','易靜','唐','唐诗','tang','','[]','日休幷，九地上加臨。',43,'全唐诗/poet.tang.55000.json','["日休幷，九地上加臨。", "龍遁祭龍宜水戰，祈求雨澤（辛本、川本作「求」）奏天庭。", "掩敵有才能。"]'),
('b56f179e-c94d-4743-960d-ea614aae1707','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 十三','易靜','唐','唐诗','tang','','[]','生門下，辛儀艮位安。',32,'全唐诗/poet.tang.55000.json','["生門下，辛儀艮位安。", "此處一方爲虎遁，招安反賊討交關，將帥總平安。"]'),
('3dd4e97f-c32c-4c7c-a554-df9ed4cb1c1f','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 十四','易靜','唐','唐诗','tang','','[]','論雲遁，龍走有奇門。',43,'全唐诗/poet.tang.55000.json','["論雲遁，龍走有奇門。", "便把鐵礫噴噀酒，令軍佈（辛本、川本作「仰」）望必昇平，雲遁自相陳。"]'),
('31d46689-522d-43b8-9e02-7f72d9979aa7','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 十五','易靜','唐','唐诗','tang','','[]','論風遁，白虎號張狂。',32,'全唐诗/poet.tang.55000.json','["論風遁，白虎號張狂。", "運式天星加地乙，祭風起順祝吾邦，此理合天蒼。"]'),
('ea062785-6d7d-4ab6-8c60-e6fe5de7ea18','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 十六','易靜','唐','唐诗','tang','','[]','九天上，大利我軍陳。',32,'全唐诗/poet.tang.55000.json','["九天上，大利我軍陳。", "九地伏藏宜密事，逃潛六合避凶星，隱伏喜忻情。"]'),
('284f1065-f3c0-4708-88c9-19e2b2beb91a','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 十七','易靜','唐','唐诗','tang','','[]','五不過（辛本、川本作「遇」），甲午丙從辰。',43,'全唐诗/poet.tang.55000.json','["五不過（辛本、川本作「遇」），甲午丙從辰。", "乙日已時丁日卯，更兼戌日在於寅，都是忌行軍。"]'),
('b6f832d4-3d5e-45b9-8afd-c20122d96ca6','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 十八','易靜','唐','唐诗','tang','','[]','五不撃，第一九天方。',43,'全唐诗/poet.tang.55000.json','["五不撃，第一九天方。", "九地直符直使位，生門通兵（辛本、川本作「共」）五般傷，此法遁中藏。"]'),
('6ac47fb5-1fbb-4e19-9f88-9921be34bdfd','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 十九','易靜','唐','唐诗','tang','','[]','六儀刑，謀事總難成。',40,'全唐诗/poet.tang.55000.json','["六儀刑，謀事總難成。", "遇着此時遭失陷，奇門雖有也難生（川本作「禁」），大忌用兵行。"]'),
('02108b88-b2ca-43f2-adc9-b5f354e024dd','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 二十','易靜','唐','唐诗','tang','','[]','子符使，都忌在三宮。',44,'全唐诗/poet.tang.55000.json','["子符使，都忌在三宮。", "戌怕冲（辛本、川本作「坤」）宮申在艮，午離酉巽必爲凶，寅與甲辰同。", "。"]'),
('08fde33c-403a-48a9-9a27-f8341bbbd386','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 二十一','易靜','唐','唐诗','tang','','[]','三奇墓，課是沒（辛本、川本作「設」）人多。',65,'全唐诗/poet.tang.55000.json','["三奇墓，課是沒（辛本、川本作「設」）人多。", "好事中間須減（辛本、川本作「滅」）力，奇門雖（辛本、川本作「須」）遇也難過，固守免蹉跎。"]'),
('cfff4e1a-ae37-49c5-a18b-01f56856b6c8','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 二十二','易靜','唐','唐诗','tang','','[]','乙奇墓，未上望坤方。',54,'全唐诗/poet.tang.55000.json','["乙奇墓，未上望坤方。", "丙奇（辛本、川本作「其」）戍地酉中是，丁奇同位戌乾（辛本、川本作「朝」）張，都是審明方。"]'),
('26d1eb5e-de1b-4082-852c-b3b1995efb95','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 二十三','易靜','唐','唐诗','tang','','[]','三奇將，游在六儀中。',32,'全唐诗/poet.tang.55000.json','["三奇將，游在六儀中。", "子庚丑辛寅乾上，卯壬爲例順行蹤，八方四維宮。"]'),
('1dfcd950-af54-45ca-93ca-9dea3078ad98','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 二十四','易靜','唐','唐诗','tang','','[]','六癸丁，天網四張時。',32,'全唐诗/poet.tang.55000.json','["六癸丁，天網四張時。", "舉用所謀皆不定，周天網者有高低，坎地一宮隨。"]'),
('87958385-3d65-4b72-9ef5-abd671601e91','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 二十五','易靜','唐','唐诗','tang','','[]','如急難，事速要（辛本、川本作「爲」）逃之。',43,'全唐诗/poet.tang.55000.json','["如急難，事速要（辛本、川本作「爲」）逃之。", "刀刃對肩居左右，行過六十步無疑，此事要君知。"]'),
('e424568c-43ac-44c0-99d2-58f19f0e85c4','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 二十六','易靜','唐','唐诗','tang','','[]','開門照，六戊（辛本、川本作「戌」）合奇門。',65,'全唐诗/poet.tang.55000.json','["開門照，六戊（辛本、川本作「戌」）合奇門。", "前程（辛本、川本作「門」）貴客相伏（辛本、川本作「扶」）助，陰人酒肉待相迎，拜訪喜忻忻。"]'),
('c710feb4-0283-4066-b323-0f59fc3ee86c','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 二十七','易靜','唐','唐诗','tang','','[]','休門外，喜笑得錢財。',56,'全唐诗/poet.tang.55000.json','["休門外，喜笑得錢財。", "出門（辛本、川本作「外」）三旬五十里，蛇鼠陰人及小孩，出外免無厄（辛本、川本作「定無災」）。"]'),
('d81ef7e7-1f00-4ee1-8839-81fff260164b','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 二十八','易靜','唐','唐诗','tang','','[]','生門上，三奇合此門。',32,'全唐诗/poet.tang.55000.json','["生門上，三奇合此門。", "公吏官人生紫皂，逢之軍馬六三程，特應與軍門。"]'),
('404ece23-7f62-4a8a-b417-9530504fb913','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 二十九','易靜','唐','唐诗','tang','','[]','傷門內，捕盜可移趨。',32,'全唐诗/poet.tang.55000.json','["傷門內，捕盜可移趨。", "杜門有難前潛吉，景門凡事不安居，獻策稍通疎。"]'),
('17ffd9fc-70ea-40e2-86df-0cd0f5a95f47','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 三十','易靜','唐','唐诗','tang','','[]','死門上，攻戰莫（辛本、川本作「要」）逢之。',76,'全唐诗/poet.tang.55000.json','["死門上，攻戰莫（辛本、川本作「要」）逢之。", "出臘（辛本、川本作「獵」）更宜朝北（辛本、川本作「此」）向，若還征戰賊亡威（辛本、川本作「滅」），決勝要逢之。"]'),
('209f7d6d-0314-48cc-8d68-201ea7eba0f4','兵要望江南 太乙式第二十七（本門中「太乙」二字，辛本、川本皆作「天乙」○三十一首） 三十一','易靜','唐','唐诗','tang','','[]','驚門路，捕盜捉逃亡。',32,'全唐诗/poet.tang.55000.json','["驚門路，捕盜捉逃亡。", "出行一二十里路，路道不通鵲噪狂，論訟喜公方。"]'),
('e002246c-10f7-4b41-bd15-fa624040a443','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 一','易靜','唐','唐诗','tang','','[]','看行動，只取（京本作「在」）日辰推。',71,'全唐诗/poet.tang.55000.json','["看行動，只取（京本作「在」）日辰推。", "若在貴人前實是（京本作「是實」），三傳同去此（辛本、川本作「此去」）無（京本作「此不須」）疑，反此却難移。"]'),
('8fc5c611-cd5c-45f2-abc6-d0e59d4dc8d3','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 二','易靜','唐','唐诗','tang','','[]','看天馬，辰戌亦同前。',83,'全唐诗/poet.tang.55000.json','["看天馬，辰戌亦同前。", "（京本注：「魁罡也。", "」）若在支干（京本作「干支」）應空（辛本、川本、京本作「定」）發，更還加季不（京本作「主」）留連，人馬鬧（京本作「更」）喧喧。"]'),
('777fbb30-9ab6-4252-85a7-921107be99bf','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 三','易靜','唐','唐诗','tang','','[]','占虛實，後六作天空。',52,'全唐诗/poet.tang.55000.json','["占虛實，後六作天空。", "若在干支虛事定，天空爲煞最朦朧，虛妄禍（辛本、川本作「更」、京本作「更望更」）重重。"]'),
('de86e2da-d617-4388-991b-64b40579a109','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 四','易靜','唐','唐诗','tang','','[]','占主客，勝負蚤須知。',58,'全唐诗/poet.tang.55000.json','["占主客，勝負蚤須知。", "甲乙丙丁幷戊子（辛本、川本作「己」、京本作「字」），陽時出戰主凶危，此事決（京本作「定」）無疑。"]'),
('03135240-a4ea-440c-87bd-787b6841ad98','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 五','易靜','唐','唐诗','tang','','[]','占宿次，今夜定如何。',64,'全唐诗/poet.tang.55000.json','["占宿次，今夜定如何。", "太乙天罡太衝上，支干見者恐奔過（京本作「波」），準（辛本、川本、京本作「整」）備禦兵戈（京本作「預防他」）。"]'),
('ba6df73c-7f11-4349-b541-4d022c50eadc','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 六','易靜','唐','唐诗','tang','','[]','看歲月，沖破時（辛本、川本、京本作「下」）推之。',108,'全唐诗/poet.tang.55000.json','["看歲月，沖破時（辛本、川本、京本作「下」）推之。", "上將行年居此位（辛本、川本、京本作「下」），師行（辛本、京本作「侯」）身必有凶危，禳厭始無虧。", "（月將加所得之時，看支干上見魁罡星者主驚潰。", "將帥行年上見魁罡者宜禳之。", "）。"]'),
('f452bbbe-1dea-450a-810f-330a74ce0687','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 七','易靜','唐','唐诗','tang','','[]','看六害，用將及傳中。',57,'全唐诗/poet.tang.55000.json','["看六害，用將及傳中。", "若見定知他捷（京本作「健」）利，更兼惡（京本作「月」）將定重凶，不鬬却無凶（京本作「爲雄」）。"]'),
('a418ef09-25a8-43b8-8fac-d5cde587cfb4','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 八','易靜','唐','唐诗','tang','','[]','後三五，前四將年辰。',54,'全唐诗/poet.tang.55000.json','["後三五，前四將年辰。", "若被日衝兼被（辛本、川本作「破」）害，被刑之（辛本、川本作「亡」）者負於人，好記認爲真。"]'),
('1cc9db9f-295b-4355-88be-8284a84d8359','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 九','易靜','唐','唐诗','tang','','[]','參詳取，太歲頭上（京本作「上頭」）神。',77,'全唐诗/poet.tang.55000.json','["參詳取，太歲頭上（京本作「上頭」）神。", "若尅貴（京本作「能責」）人虛詐事，太陰六合（辛本、川本作「後」、京本作「神后」）僞爲（京本作「非」）真，防備見傷人。"]'),
('1a39bd9e-b4f6-40a5-9659-c5a132ce3b4e','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 十','易靜','唐','唐诗','tang','','[]','聞賊去，大吉是其元。',60,'全唐诗/poet.tang.55000.json','["聞賊去，大吉是其元。", "若在干（辛本、川本、京本作「前」）時應末去，若臨干（辛本、川本、京本作「賊」）後是虛傳，勿聽此狂言。"]'),
('01ba13c4-f92b-4e21-aaa8-95774338efb4','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 十一','易靜','唐','唐诗','tang','','[]','他軍走（京本作「是」），虛實（辛本、川本、京本作「的」）好參陳。',55,'全唐诗/poet.tang.55000.json','["他軍走（京本作「是」），虛實（辛本、川本、京本作「的」）好參陳。", "神克日辰天馬併，傳揚定去必無人，此兆決然真。", "。"]'),
('d8632507-aa54-4001-82c4-3b019dca004e','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 十二','易靜','唐','唐诗','tang','','[]','經險路，惟是（京本作「則」、辛本、川本作「爲則」）忌天罡。',73,'全唐诗/poet.tang.55000.json','["經險路，惟是（京本作「則」、辛本、川本作「爲則」）忌天罡。", "加孟前行喜（辛本、川本、京本作「應」）不喜，罡臨四仲己中傷，加季後（京本作「復」）逃亡。"]'),
('369b3459-b0b8-4a70-bff3-512c49cfcaf6','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 十三','易靜','唐','唐诗','tang','','[]','兵行次，四季獄神凶。',72,'全唐诗/poet.tang.55000.json','["兵行次，四季獄神凶。", "春卯（京本注：「夏午。", "」）順（京本注：「四季。", "」）雷（京本作「來」）居震位，辰年艮（京本作「日辰年」）上忌相逢，臨着失勳功。"]'),
('2240606e-3a57-4c58-9715-07ed58db181d','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 十四','易靜','唐','唐诗','tang','','[]','遊都將，併殺又重傷。',58,'全唐诗/poet.tang.55000.json','["遊都將，併殺又重傷。", "若遇德鄉神幷合（京本、辛本、川本作「神幷合將」），加臨不尅又加（京本作「有嘉」）祥，降虜我軍強。"]'),
('6d62d1b8-0a13-44dd-acb5-f315c4e3deec','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 十五','易靜','唐','唐诗','tang','','[]','遊都將，克日至行年。',60,'全唐诗/poet.tang.55000.json','["遊都將，克日至行年。", "約束（京本作「若屬」）我軍牢固守，若（辛本、川本作「莫」）教見陣必遭愆（京本作「邅」），不鬬却爲賢。"]'),
('76277381-48a2-4877-8d10-d8888b095f6e','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 十六','易靜','唐','唐诗','tang','','[]','主年上，須要克遊都。',40,'全唐诗/poet.tang.55000.json','["主年上，須要克遊都。", "克得此宮爲大勝，多應擒捉賊（京本作「客」）酋徒，半虜半降誅。"]'),
('357175b0-2bd6-452d-ae04-7d352f6482ac','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 十七','易靜','唐','唐诗','tang','','[]','遊都將，玄武與勾陳。',51,'全唐诗/poet.tang.55000.json','["遊都將，玄武與勾陳。", "白虎年將須穩審（辛本、川本作「害」），休囚絕氣不傷人，旺相却（京本作「即」）殘身。"]'),
('ae10c43d-4e22-43b6-b210-30296061b400','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 十八','易靜','唐','唐诗','tang','','[]','玄武將，斷例與前同。',48,'全唐诗/poet.tang.55000.json','["玄武將，斷例與前同。", "無克後三皆大勝，後三來（京本作「未」）克主皆凶，却是（京本作「試」）審其中。"]'),
('a2d9b3d3-37af-4bc5-90a6-941f18f97686','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 十九','易靜','唐','唐诗','tang','','[]','勾陳將，忌克主行年。',52,'全唐诗/poet.tang.55000.json','["勾陳將，忌克主行年。", "若克行年多敗死，行年無（京本作「多」）克見勳全，審細去參詮。", "（勾陳克玄武，主勝。", "）。"]'),
('09dac101-b2aa-43a7-b0aa-e38ba138db83','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 二十','易靜','唐','唐诗','tang','','[]','凶神將，又克主行年。',59,'全唐诗/poet.tang.55000.json','["凶神將，又克主行年。", "若遇行年克前四，此是交戰（京本作「勝」）勝當先，喜躍信（京本作「作」）超（辛本、川本作「趨」）前。"]'),
('61938ab1-52eb-420d-87a8-73939b7a8229','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 二十一','易靜','唐','唐诗','tang','','[]','軍勝負，六害卦中凶。',60,'全唐诗/poet.tang.55000.json','["軍勝負，六害卦中凶。", "更作惡神幷惡將，直須固守候時（辛本、川本、京本作「晴」）風，懼（辛本、川本、京本作「俱」）慎莫前沖。"]'),
('e93eb489-0ea7-474f-bade-5e099c68c168','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 二十二','易靜','唐','唐诗','tang','','[]','遊都將，臨日在如今。',44,'全唐诗/poet.tang.55000.json','["遊都將，臨日在如今。", "辰上見之明日是，支干不見（辛本、川本作「是」）用前神，三二是朝迍。", "。"]'),
('8cb113d7-2a97-465c-91a4-4a72d1a642dc','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 二十三','易靜','唐','唐诗','tang','','[]','聞賊去，仔細驗天罡。',32,'全唐诗/poet.tang.55000.json','["聞賊去，仔細驗天罡。", "若在孟方猶未去，忽然加仲已商量，加季發他鄉。"]'),
('3263917a-5d1c-4a26-832a-51e6c141a37f','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 二十四','易靜','唐','唐诗','tang','','[]','三傳將，遙日（辛本、川本、京本作「見」）覓支干。',54,'全唐诗/poet.tang.55000.json','["三傳將，遙日（辛本、川本、京本作「見」）覓支干。", "將見支干休進戰，三神被克我軍（京本作「神」）安，必獲彼旗旛。"]'),
('2b1e300e-3e78-419a-ba1d-a6bd1dc1bdb6','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 二十五','易靜','唐','唐诗','tang','','[]','課中惡，忌見戰雌神。',44,'全唐诗/poet.tang.55000.json','["課中惡，忌見戰雌神。", "傳送是春登明夏，秋寅冬巳愛傷人，日與喜神親（京本作「發動愈重迍」）。"]'),
('84776017-62ac-47a9-a21d-337aedd316a9','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 二十六','易靜','唐','唐诗','tang','','[]','行軍（京本作「兵」）課，惟有伏吟時。',48,'全唐诗/poet.tang.55000.json','["行軍（京本作「兵」）課，惟有伏吟時。", "兵伏自然軍勿進，預憂中道有儉（京本作「陰」）奇，審課要知機。"]'),
('64374d95-ecca-49c0-a7d4-21799f40d96d','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 二十七','易靜','唐','唐诗','tang','','[]','行兵（京本作「軍」）課，切忌反吟凶。',40,'全唐诗/poet.tang.55000.json','["行兵（京本作「軍」）課，切忌反吟凶。", "若遇喜神應解退，惡神立敗禍來衝。", "反覆我軍中。"]'),
('79f6f315-92d9-4065-82ee-80fb707c65fc','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 二十八','易靜','唐','唐诗','tang','','[]','熒惑煞，只是丙丁神。',44,'全唐诗/poet.tang.55000.json','["熒惑煞，只是丙丁神。", "加在金方兵已退，亦無征戰不傷人，發動愈重迍（京本作「日與喜神親」）。"]'),
('0c94f1ae-2f4d-449d-9370-bf7f57b358e9','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 二十九','易靜','唐','唐诗','tang','','[]','看課內，太白是庚辛。',40,'全唐诗/poet.tang.55000.json','["看課內，太白是庚辛。", "若在東方奸賊至，天罡加孟急（京本作「疾」）如神，警備要專勤。"]'),
('0c56f4d4-9234-4669-8da4-c311ce9dc7e0','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 三十','易靜','唐','唐诗','tang','','[]','課中聖，惟是戰雄併。',40,'全唐诗/poet.tang.55000.json','["課中聖，惟是戰雄併。", "四季孟神雄將位（與戰對沖是也），若居喜將得相生，旺相更爲榮。"]'),
('de11146d-c043-4f8d-a844-07d74af0d495','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 三十一','易靜','唐','唐诗','tang','','[]','看課上，與下要相生。',51,'全唐诗/poet.tang.55000.json','["看課上，與下要相生。", "上克下兮須損失，逢占惡將（京本作「要逢虛將」）必須驚，喜（京本作「吉」）將喜無爭。"]'),
('0bfe5e0f-202a-4643-9f1c-eb05197ef4df','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 三十二','易靜','唐','唐诗','tang','','[]','何煞重，天狗是其殃。',49,'全唐诗/poet.tang.55000.json','["何煞重，天狗是其殃。", "無殺福神相次惡，天雷併者是（京本作「也」）無妨，三殺可商量（京本作「參商」）。"]'),
('1471a437-1fa8-4ece-9cc7-455fffaf4180','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 三十三','易靜','唐','唐诗','tang','','[]','勾陳將，玄武共相親。',40,'全唐诗/poet.tang.55000.json','["勾陳將，玄武共相親。", "帶煞併加爲惡煞，若逢相克不宜軍（京本作「君」），有煞便相侵。"]'),
('284653cc-cc67-4c0f-afbb-0db0e95a12d8','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 三十四','易靜','唐','唐诗','tang','','[]','三刑內，最惡是天罡。',67,'全唐诗/poet.tang.55000.json','["三刑內，最惡是天罡。", "或是季兮爲日上，沖加四煞必相傷，夜即恐驚忙（京本作「亡」。", "魁罡臨日，主大將死，臨辰，主小將死，日辰俱臨，俱死。", "）。"]'),
('e657157b-7b10-45d2-ad5c-376615c5dbc1','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 三十五','易靜','唐','唐诗','tang','','[]','課驚怖，日上細尋推。',85,'全唐诗/poet.tang.55000.json','["課驚怖，日上細尋推。", "辰巳太沖加日上，若逢蛇雀見凶危，復手也如之。", "（大吉加日，宜急去，不可住，辰上見太沖，夜必有風雨，若神後太乙加日辰，夜有賊盜。", "旺相必見，無氣則不見。", "）。"]'),
('2700df4c-abd8-44ab-8f2d-0ef7366f0a2d','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 三十六','易靜','唐','唐诗','tang','','[]','課驚怖，辰巳卯三辰。',33,'全唐诗/poet.tang.55000.json','["課驚怖，辰巳卯三辰。", "無殺相併天馬併，用之發課不宜人，虛殺總相親。", "。"]'),
('3f03456b-9336-4846-a3f0-71c948cd38c0','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 三十七','易靜','唐','唐诗','tang','','[]','移伏起，陽日在中傳。',32,'全唐诗/poet.tang.55000.json','["移伏起，陽日在中傳。", "陰則未傳君記取，覺知如此見由緣，照處是推源。"]'),
('b55b78f4-2cdd-4efd-b3a2-bc56f6c8ad37','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 三十八','易靜','唐','唐诗','tang','','[]','欲捕捉，玄武定三傳。',32,'全唐诗/poet.tang.55000.json','["欲捕捉，玄武定三傳。", "相克三傳皆捉得，相生不克是無緣，好記不虛言。"]'),
('364ddf96-46b0-4a68-ac1d-7539eb0f1754','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 三十九','易靜','唐','唐诗','tang','','[]','三傳克，克日易前擒。',40,'全唐诗/poet.tang.55000.json','["三傳克，克日易前擒。", "快（京本作「決」）出疾行方始得，奸人移伏恐軍侵，離日却難尋。"]'),
('06389191-622a-4062-8ed0-1c8a7cf07da5','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 四十','易靜','唐','唐诗','tang','','[]','傳課中（京本作「內」），蛇雀與勾陳。',40,'全唐诗/poet.tang.55000.json','["傳課中（京本作「內」），蛇雀與勾陳。", "蛇主虛驚雀主火，亦兼音信又公文。", "仔細好推論。"]'),
('e716b96f-6f82-463e-94de-f9823af86e21','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 四十一','易靜','唐','唐诗','tang','','[]','傳白虎，相克戰傷人。',40,'全唐诗/poet.tang.55000.json','["傳白虎，相克戰傷人。", "無氣不傷途死損，天空依舊（京本作「積」）是空陳，旺處是窮貧。"]'),
('f4980e95-6646-491a-b1d6-182f73e05657','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 四十二','易靜','唐','唐诗','tang','','[]','占行路，逐日定占之。',32,'全唐诗/poet.tang.55000.json','["占行路，逐日定占之。", "有氣青龍並六合，錢財倉庫定無疑，多獲綵縑持。"]'),
('5c2e07b9-7dcf-4949-9a7a-e26df13bf74b','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 四十三','易靜','唐','唐诗','tang','','[]','將一二，兼持（京本作「赤」）忌勾陳。',40,'全唐诗/poet.tang.55000.json','["將一二，兼持（京本作「赤」）忌勾陳。", "若見後三幷五六，因爲發卦不宜軍，進步必遭迍。"]'),
('28b0e4a7-ac47-46f8-ba79-9889c9c475fa','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 四十四','易靜','唐','唐诗','tang','','[]','將軍吏，支干審占之。',32,'全唐诗/poet.tang.55000.json','["將軍吏，支干審占之。", "大吉小吉支干上，天罡加孟以同推，不戰兩無疑。"]'),
('69715966-13be-4153-99c8-8a60809e7f3e','兵要望江南 占六壬第二十八（京本列第十七○四十五首） 四十五','易靜','唐','唐诗','tang','','[]','後五六，即是我軍傷。',32,'全唐诗/poet.tang.55000.json','["後五六，即是我軍傷。", "六帥有人虛詐說，日辰不克也無妨，克日不宜良。"]'),
('d1798594-95a6-451d-b08c-825e64c48fba','兵要望江南 醫方第二十九（十六首） 一','易靜','唐','唐诗','tang','','[]','衆軍聚，駐札已經時。',43,'全唐诗/poet.tang.55000.json','["衆軍聚，駐札已經時。", "多有相蒸人（辛本、川本作「多」）氣鬱，使軍疫瘴見灾危，一一與君知。"]'),
('e11956ec-1a97-43e5-abb7-2e404d2cdb46','兵要望江南 醫方第二十九（十六首） 二','易靜','唐','唐诗','tang','','[]','如瘴氣，鶻骨火燒將。',32,'全唐诗/poet.tang.55000.json','["如瘴氣，鶻骨火燒將。", "便去上風焚此物，衆人聞此滅灾殃，從此得安康。"]'),
('755657ab-2ab8-43a5-aa4e-e96e69e36205','兵要望江南 醫方第二十九（十六首） 三','易靜','唐','唐诗','tang','','[]','轉筋脚，急去使生薑。',32,'全唐诗/poet.tang.55000.json','["轉筋脚，急去使生薑。", "新水一鍾煎五合，飲之即去總無妨，主將記心腸。"]'),
('a00607cf-9e22-45a6-9b4c-84ecee29a78f','兵要望江南 醫方第二十九（十六首） 四','易靜','唐','唐诗','tang','','[]','金刃重，速翦馬牛毛。',32,'全唐诗/poet.tang.55000.json','["金刃重，速翦馬牛毛。", "二件一同燒作末，敷之血止自然消，皮血便堅牢。"]'),
('b723dc0b-6ed2-4667-96c3-54df580cbf81','兵要望江南 醫方第二十九（十六首） 五','易靜','唐','唐诗','tang','','[]','金傷者，香白芷爲靈。',44,'全唐诗/poet.tang.55000.json','["金傷者，香白芷爲靈。", "細嚼噀敷瘡口上，更將暖酒飲七分（辛本作「酒下七分功」），細說與君聽。"]'),
('bc37ac38-c3a4-47e8-9317-58cb95f825f8','兵要望江南 醫方第二十九（十六首） 六','易靜','唐','唐诗','tang','','[]','金傷者，甚渴急（辛本作「即」）非常。',41,'全唐诗/poet.tang.55000.json','["金傷者，甚渴急（辛本作「即」）非常。", "切忌休將水與飲，飲之必定有乖張，肥膩即無妨。", "。"]'),
('6bddad09-d383-45c4-abe1-24d1fe299a5d','兵要望江南 醫方第二十九（十六首） 七','易靜','唐','唐诗','tang','','[]','金傷處，傷腦及天蒼（辛本作「倉」）。',40,'全唐诗/poet.tang.55000.json','["金傷處，傷腦及天蒼（辛本作「倉」）。", "臂中脈跳幷心內，鳩尾五臟小腹胱。", "醫者不能當。"]'),
('1b5499d5-9639-4494-808c-bad8cb1f4593','兵要望江南 醫方第二十九（十六首） 八','易靜','唐','唐诗','tang','','[]','金傷者，腦髓出非常。',54,'全唐诗/poet.tang.55000.json','["金傷者，腦髓出非常。", "頸咽喉中聲沸者，兩目直視痛難當，血似水流（辛本作「泉」）塘。", "（似此，皆不治而難醫也。", "）。"]'),
('4580e857-17d3-4c58-a726-b3b5532b69c4','兵要望江南 醫方第二十九（十六首） 九','易靜','唐','唐诗','tang','','[]','金瘡法，閒時備急方。',32,'全唐诗/poet.tang.55000.json','["金瘡法，閒時備急方。", "五月五日平明節，採其諸草搗成漿，石灰共作湯。"]'),
('f9c85799-9170-4748-956e-53d63dff1509','兵要望江南 醫方第二十九（十六首） 十','易靜','唐','唐诗','tang','','[]','遭毒箭，更兼馬汗方。',54,'全唐诗/poet.tang.55000.json','["遭毒箭，更兼馬汗方。", "大頭蝱蟲端午取，去翅陰乾爲末霜。", "挑破藥敷瘡。", "（次用醋打麵糊紙壓瘡口上，即追出毒氣也。", "）。"]'),
('77936bc9-00a0-4cb7-9998-624a6243727f','兵要望江南 醫方第二十九（十六首） 十一','易靜','唐','唐诗','tang','','[]','軍或患，發背及癰疽。',32,'全唐诗/poet.tang.55000.json','["軍或患，發背及癰疽。", "人屎糞盤下潤土，碾細篩羅貼敷之，猪膽共調施。"]'),
('8bebf91b-4f4d-4ed1-8dda-7eec48762cb8','兵要望江南 醫方第二十九（十六首） 十二','易靜','唐','唐诗','tang','','[]','人霍亂，吐瀉有方高。',80,'全唐诗/poet.tang.55000.json','["人霍亂，吐瀉有方高。", "生薑二（辛本作「三」）兩須炮過，芭蕉一兩去皮熬，五兩大黃燒。", "（大黃炒過爲末，蜜爲丸，如梧桐子大，每服三丸，以利爲度；如不利，以米粥投藥。", "）。"]'),
('d29242f6-2a91-48cc-940d-c29cddc2d35a','兵要望江南 醫方第二十九（十六首） 十三','易靜','唐','唐诗','tang','','[]','急喉閉，青艾汁須靈。',32,'全唐诗/poet.tang.55000.json','["急喉閉，青艾汁須靈。", "滴下自消血破出，逡巡不救損於人，切記在心勤。"]'),
('43ac9c74-e9ba-44d6-b6f4-7239b9ed836d','兵要望江南 醫方第二十九（十六首） 十四','易靜','唐','唐诗','tang','','[]','冬月內，無葉艾枝枯。',32,'全唐诗/poet.tang.55000.json','["冬月內，無葉艾枝枯。", "草內急尋蛇牀子，燒烟入中自消除，速救免灾虞。"]'),
('db486195-0b9d-490f-bf3a-178ad1c3d657','兵要望江南 醫方第二十九（十六首） 十五','易靜','唐','唐诗','tang','','[]','軍人衆，涉水冒霜多。',32,'全唐诗/poet.tang.55000.json','["軍人衆，涉水冒霜多。", "手脚面皮皆裂拆，麥葉濃煮汁相過，熱洗即安和。"]'),
('18ec9908-c73b-4201-9a70-f20d32701ef6','兵要望江南 醫方第二十九（十六首） 十六','易靜','唐','唐诗','tang','','[]','山瘴氣，嵐谷用恒山。',87,'全唐诗/poet.tang.55000.json','["山瘴氣，嵐谷用恒山。", "獨頭大蒜烏梅肉，速將酒煮便能痊，謹記此良言。", "（恒山二兩，獨頭蒜一兩，烏梅二十枚，咬咀，用酒二盞，煎至一大盞，分爲二服。", "初一服未發時喫，次一服已發時喫。", "）。"]'),
('b7faa53a-2be6-4161-8a2f-b71c43964a6e','兵要望江南 馬藥方第三十（四首） 一','易靜','唐','唐诗','tang','','["\u9ec4\u5c71"]','常灌馬，黃柏與黃連。',32,'全唐诗/poet.tang.55000.json','["常灌馬，黃柏與黃連。", "升麻大黃山梔子，胡鹽青黛鬱金仙，等分勿令偏。"]'),
('1f4ece68-68da-403f-b499-bedcd0bc001d','兵要望江南 馬藥方第三十（四首） 二','易靜','唐','唐诗','tang','','[]','相馬法，要試歲年何。',33,'全唐诗/poet.tang.55000.json','["相馬法，要試歲年何。", "鼻上金字十八歲，四字八歲不年多，八字四年過。", "。"]'),
('ad8ed22d-69ba-48ae-bf84-006d15394f1f','兵要望江南 馬藥方第三十（四首） 三','易靜','唐','唐诗','tang','','[]','鼻上赤，二十歲無零。',48,'全唐诗/poet.tang.55000.json','["鼻上赤，二十歲無零。", "馬鼻若青三十歲，公字雖（辛本作「須」）當念五乘，此象最（辛本作「甚」）分明。"]'),
('347beee2-bdc1-488b-b7c6-4cd4c6b06816','兵要望江南 馬藥方第三十（四首） 四','易靜','唐','唐诗','tang','','[]','馬瘟病，急取獺之肝。',588,'全唐诗/poet.tang.55000.json','["馬瘟病，急取獺之肝。", "肚內將來去屎洗，煮汁啖灌便平安。", "牢記在心間。", "（按：以上易靜詞四卷，凡七百二十一首，均見於《兵要望江南》一書。", "《崇文總目》卷三著錄於《子部·兵家類》：「《神機武略兵要望江南詞》一卷。", "」《郡齋讀書後志》卷二《兵類》云：「《兵要望江南》一卷。", "右題云黃石公以授張良者。", "按其書雜占行軍吉凶，寓聲於《望江南》詞，取其易記憶。", "《總目》云：『武安軍左押衙易靜撰。", "』蓋唐人也。", "」《總目》即《崇文總目》，今本已失解題，錢侗校本據以補出。", "檢《新唐書》卷六九《方鎮表》：光啓元年「改欽化軍節度爲武安軍節度使」。", "因知易靜應爲唐末人。", "今所據凡四本：其一爲明辛自修刊本〖簡稱辛本〗，刊於萬曆十年，今藏北京圖書館；其二爲四川省圖書館藏清初鈔本〖簡稱川本〗，此本錯別字較多，文字較近於辛本；其三，首都圖書館藏鈔本〖簡稱首本〗，題作《李衛公望江南》，分上下兩卷；其四爲北京圖書館收藏前京師圖書館舊鈔本〖簡稱京本〗，附跋云：「此從明督浙江都御史晉江蘇茂相校本錄出，題作《白猿奇書兵法雜占彖詞》，唐開府儀同三司衛公三原李靖著。", "」首本、川本、辛本均爲足本，但均有所殘缺。", "京本則僅存五百首，但有十餘首不見於前三本，文字亦差異較大。", "今以首本爲底本，以辛本、川本、京本校補。", "首本、辛本、川本皆據任半塘先生與王小盾同志合編《隋唐五代燕樂雜言歌辭集》〖稿本〗轉引，京本則轉引自張璋、黃畬編《全唐五代詞》。", "）。"]'),
('10f770cb-afc3-42e9-9592-d85c65313841','鳴山','羅袞','唐','唐诗','tang','','[]','天下名山有，未聞山自鳴。',80,'全唐诗/poet.tang.55000.json','["天下名山有，未聞山自鳴。", "昂藏如許濶，爾何亦不平。", "（見同治丙寅刊齊召南等纂《溫州府志》卷四《山川》。", "）（按：《宋詩紀事補遺》卷八八誤收羅袞此詩入事迹無考作者。", "）。"]'),
('5191f558-339e-4d52-b6e4-651659e8f22e','句','羅袞','唐','唐诗','tang','','[]','此心不向常人說。',30,'全唐诗/poet.tang.55000.json','["此心不向常人說。", "（《江湖小集》卷二十一李龏《剪綃集》引。", "）。"]'),
('78a05b7b-7b32-47e9-9b5d-73624d6edf1d','公讌詩','羅紹威','唐','唐诗','tang','','[]','簾前淡泊雲頭日，座上蕭騷兩脚風。',60,'全唐诗/poet.tang.55000.json','["簾前淡泊雲頭日，座上蕭騷兩脚風。", "（見《吟窗雜錄》卷二五《歷代吟譜》。", "）（按：《全唐詩》卷七三四收二句，缺題，今重錄。", "）。"]'),
('ec157f71-c18b-4188-8f30-8024077ca1b1','答王福娘紅箋題詩（題擬）','孫棨','唐','唐诗','tang','','[]','韶妙如何有遠圖，未能相爲信非夫。',42,'全唐诗/poet.tang.55000.json','["韶妙如何有遠圖，未能相爲信非夫。", "泥中蓮子雖無染，移入家園未得無。", "（見《北里志》。", "）。"]'),
('2f8f22b7-4ff2-4a5e-acc1-1b5625b883ea','句','黃匪躬','唐','唐诗','tang','','[]','志大惟憂國，恩深豈顧身。',49,'全唐诗/poet.tang.55000.json','["志大惟憂國，恩深豈顧身。", "（見明黃佐《廣州人物傳》卷四、清黃子高輯《粤詩蒐逸》卷一引《連州志》。", "）。"]'),
('00691e9b-ba75-4b11-805e-d55437b76867','偈','匡仁','唐','唐诗','tang','','[]','吾有一寶琴，寄之在曠野。',38,'全唐诗/poet.tang.55000.json','["吾有一寶琴，寄之在曠野。", "不是不解彈，未遇知音者。", "（見《五燈會元》卷十三。", "）。"]'),
('a95981ae-0f7d-4f09-a8bd-83b7c3336db0','臨遷化時偈（《江西詩徴》題作《詩》）','匡仁','唐','唐诗','tang','','[]','我路碧空外，白雲無處閑。',102,'全唐诗/poet.tang.55000.json','["我路碧空外，白雲無處閑。", "世有無根樹，黃葉送風（《景德傳燈錄》、《五燈會元》作「風送」，《江西詩徴》作「風吹黃葉」）還。", "（見《祖堂集》卷八、《景德傳燈錄》卷十七、《五燈會元》卷十三、《江西詩徴》卷八七。", "）。"]'),
('2c7bdb8e-68d3-4558-96d6-4505702b7337','擲瓦果悟道偈（題擬）','智閑','唐','唐诗','tang','','[]','一挃（一作「撃」）忘所知，更不自（一作「假」）修持（一作「治」）。',101,'全唐诗/poet.tang.55000.json','["一挃（一作「撃」）忘所知，更不自（一作「假」）修持（一作「治」）。", "[動容揚古路，不墮悄然機]（二句據《景德傳燈錄》卷十一補。", "）處處無蹤跡，聲色外威儀。", "十（《五燈會元》卷九作「諸」）方達道者，咸言上上機。"]'),
('3aa71e5b-c923-43b2-858f-53c7561959d7','對仰山問作偈（題擬）','智閑','唐','唐诗','tang','','[]','去年未是貧，今年始是貧。',73,'全唐诗/poet.tang.55000.json','["去年未是貧，今年始是貧。", "去年無卓錐之地，今年錐也無。", "（《五燈會元》卷九作：「去年貧未是貧，今年貧始是貧。", "去年貧猶有卓錐之地，今年貧，錐也無。", "」）。"]'),
('0ea48d03-1043-4468-9569-9b6e9fe1443a','勵學吟','智閑','唐','唐诗','tang','','[]','滿口語，無處說，明明向道人（一作「人道」）不決。',116,'全唐诗/poet.tang.55000.json','["滿口語，無處說，明明向道人（一作「人道」）不決。", "急著力，勤咬囓，無常到來救不徹。", "口裏話（一作「語」），暗嗟（一作「瑳」）切，快磨古錐淨挑揭。", "理盡覺，自護持，此生事，吾（一作「終」）不說，玄旨（一作「學」）求他古老吟，禪學須窮心影絕。"]'),
('79b5f82b-0c49-4cdb-915f-90082f71cccc','誡宗教接物頌','智閑','唐','唐诗','tang','','[]','三句語，究人玄。',32,'全唐诗/poet.tang.55000.json','["三句語，究人玄。", "迅面目，示豁然。", "開兩路，備機緣。", "投不遇，說多年。"]'),
('144cd2bf-a39d-43f5-a228-929e21fbee64','最後頌（一作「語」）','智閑','唐','唐诗','tang','','[]','有一語，全規矩，休思量（一作「惟」），不自許。',81,'全唐诗/poet.tang.55000.json','["有一語，全規矩，休思量（一作「惟」），不自許。", "路逢同（一作「達」）道人，楊眉省來處。", "踏不著，多疑慮，却思量（一作「看」），帶伴侶。", "一生參學事無成，慇懃抱得栴檀樹。"]'),
('56818450-fb78-484e-ba6f-63ba3db40838','修行頌','智閑','唐','唐诗','tang','','[]','天寒宜曝日，歸堂一食傾。',50,'全唐诗/poet.tang.55000.json','["天寒宜曝日，歸堂一食傾。", "思著未生時，宜然任他清。", "只摩尋[□]時，明鏡非明鏡。", "獨坐覺虛涼，行時也只寧。"]'),
('777082a8-4b03-47b3-94cf-5cc0613b862e','發機頌答鄭郎中又問','智閑','唐','唐诗','tang','','[]','語裏埋筋骨，音聲染道容。',31,'全唐诗/poet.tang.55000.json','["語裏埋筋骨，音聲染道容。", "即時纔妙會，拍手趁乘（一作「乖」）龍。"]'),
('ab97aec1-cc2b-489c-b1e1-cdf0f2d79205','清思頌','智閑','唐','唐诗','tang','','[]','盡日坐虛堂，靜思絕參詳。',24,'全唐诗/poet.tang.55000.json','["盡日坐虛堂，靜思絕參詳。", "更無迴顧意，爭肯置平常。"]'),
('e978331e-e99a-41c1-9bd3-cfab534d5a56','談玄頌（一作「譚道頌」）','智閑','唐','唐诗','tang','','[]','的的無兼帶，獨運何依賴。',24,'全唐诗/poet.tang.55000.json','["的的無兼帶，獨運何依賴。", "路逢達道人，莫將語嘿對。"]'),
('38f38624-123f-4834-b7a2-612a419f1d6f','渾{山/淪}語頌','智閑','唐','唐诗','tang','','[]','一束茆，草六分，蓋得庵，無子門。',36,'全唐诗/poet.tang.55000.json','["一束茆，草六分，蓋得庵，無子門。", "藏頭人，入去却，轉頭來，語渾{山/淪}。"]'),
('23123d31-c7fc-4cda-85f4-106db94ea0d5','明古頌（一作「授指」）','智閑','唐','唐诗','tang','','[]','古人骨，多靈異。',234,'全唐诗/poet.tang.55000.json','["古人骨，多靈異。", "賢子孫。", "密安置。", "此一門，成孝義。", "人未達，莫差池。", "須志固，遣狐疑。", "得安靜，不傾危。", "向即遠，求即離。", "取即失（一作「急」），急（一作「失」）即遲。", "無計校，忘覺知。", "濁流識，今古僞。", "一剎那，通變異。", "嵯峨山，石火起（一作「氣」）。", "內裏發，焚巔𡻭。", "無遮攔，燒海底。", "決網疎，靈焰細。", "六月臥，去被衣（一作「衣被」）。", "蓋不得，無假僞。", "達道人，習（一作「唱」）祖意。", "我師宗，古來諱。", "唯此人，善安置。", "足法財，去（一作「具」）慙愧。", "不虛施，用處諦。", "有人問，小（一作「少」）呵氣。"]'),
('d5349801-e247-433d-b3b0-358ac4297f74','與崔大夫暢玄頌','智閑','唐','唐诗','tang','','[]','達人多隱顯，不定露形儀。',56,'全唐诗/poet.tang.55000.json','["達人多隱顯，不定露形儀。", "語下不遺跡，密密潛護持。", "動容揚古路，明妙乃方知。", "應求俱（一作「物但」）施設，莫道不思議。"]'),
('8303ce52-47bd-4512-a012-d89329ce8ff5','寶明頌','智閑','唐','唐诗','tang','','[]','思清人少慮，風規自然足。',24,'全唐诗/poet.tang.55000.json','["思清人少慮，風規自然足。", "影落在音容，孤明絕撑觸。"]'),
('2b8e8f9d-95a5-4215-a1e8-d34e2df7f4cb','出家頌','智閑','唐','唐诗','tang','','[]','從來求出家，未詳出家稱。',38,'全唐诗/poet.tang.55000.json','["從來求出家，未詳出家稱。", "起坐只尋常，更無小（《宗鏡錄》卷二四作「少」）殊勝。"]'),
('4634ad48-2906-4448-90c8-13d963d8d125','寄法堂頌','智閑','唐','唐诗','tang','','[]','東間裏入寂，西間裏語話。',37,'全唐诗/poet.tang.55000.json','["東間裏入寂，西間裏語話。", "中間裏睡眠，通間裏行道。", "向前即撿校，向後即隱形。", "。"]'),
('5711b6b4-e2dd-4247-aeba-795ffee01e25','時人都不措問什麽精靈答曰','智閑','唐','唐诗','tang','','[]','淨地上皷怒，怡然中伴嗔。',38,'全唐诗/poet.tang.55000.json','["淨地上皷怒，怡然中伴嗔。", "平坦處不守，危嶮中藏身。", "盲聾遇之眼開，僧瑤駐筆通神。"]'),
('7a6ab558-c1fd-4af4-8652-7d323f9801a0','玄旨頌','智閑','唐','唐诗','tang','','[]','去去無標的，來來只摩（一作「麽」）來。',31,'全唐诗/poet.tang.55000.json','["去去無標的，來來只摩（一作「麽」）來。", "有人相借問，不語笑咳咳。"]'),
('ae0c98fc-0de3-4746-ab30-7754d315bad0','贈同住歸寂頌（一作《歸寂吟贈同住》）','智閑','唐','唐诗','tang','','[]','同住道人七十餘，共辭城郭樂山居。',133,'全唐诗/poet.tang.55000.json','["同住道人七十餘，共辭城郭樂山居。", "身如寒木心芽（一作「牙」）絕，不話唐言休梵書。", "心期盡處身雖喪，如來弟子沙門樣。", "深信共崇鉢塔成，巍巍置在青山嶂（一作「掌」）。", "觀夫參道不虛然，脫去形骸惎（一作「甚」）高上。", "從來不說今朝事，暗裏埋頭隱玄暢。", "不留蹤跡異人間，深妙神光飽明亮。"]'),
('76c19c1b-2848-46c0-8d9a-d253b24d2c39','勸學頌','智閑','唐','唐诗','tang','','[]','出家修道莫求安，失念求安學道難。',32,'全唐诗/poet.tang.55000.json','["出家修道莫求安，失念求安學道難。", "未得直須求大道，覺了無安無不安。"]'),
('4f4b5b92-afac-4d1d-a422-d46ee9f2882b','志守得破頌','智閑','唐','唐诗','tang','','[]','十五日已前，師僧莫離此間。',40,'全唐诗/poet.tang.55000.json','["十五日已前，師僧莫離此間。", "十五日已後，師僧莫住此間。", "去即打汝頭破，住即亦復如然。"]'),
('4cf66848-655a-46a8-a896-4230dc0bbe4b','辭見聞頌','智閑','唐','唐诗','tang','','[]','好住逕分離，幽宗人跡稀。',24,'全唐诗/poet.tang.55000.json','["好住逕分離，幽宗人跡稀。", "從來未登陟，無許遣狐疑。"]'),
('2b278cbd-b084-49be-9f50-2efb4c8ae1cf','遵古路頌與郎中','智閑','唐','唐诗','tang','','[]','虛心越境淨思量，句裏無蹤聲外詳。',33,'全唐诗/poet.tang.55000.json','["虛心越境淨思量，句裏無蹤聲外詳。", "文字影像駭驚覺，動容彈指飽馨香。", "。"]'),
('1d7b01b0-690d-4790-b0eb-0a6253083639','與董兵馬使說示偈','智閑','唐','唐诗','tang','','[]','宿靜心意到山中，爲求半偈契神蹤。',43,'全唐诗/poet.tang.55000.json','["宿靜心意到山中，爲求半偈契神蹤。", "向道却思思不得，却將尋思㝵（疑即「礙」之俗寫字）不通。"]'),
('9cff6ad1-4f44-4dc6-b53b-29261b2fc66a','與學人宗教宗如','智閑','唐','唐诗','tang','','[]','滿寺釋迦子，未詳釋迦經。',24,'全唐诗/poet.tang.55000.json','["滿寺釋迦子，未詳釋迦經。", "喚來試共語，開口雜音聲。"]');
